# Clear existing data and graphics
rm(list=ls())
#graphics.off()


# Load libraries ----
pacman::p_load(
  tidyverse, 
  speff2trial,  # for 1996 HIV RCT data set
  rvinecopulib,  # for r-vine copula implementation
  e1071,  # for r-vine copula implementation
  caret,  # for r-vine copula implementation and to train ML models using CV
  EnvStats,  # for r-vine copula implementation - NOTE: predict OVERWRITES predict from base R stats package!!!
  truncnorm,  # for r-vine copula implementation
  dgof,  # for Kolmogorov-Smirnov tests
  caTools,  # to easily split data into train/test sets
  xgboost,  # for XGBoost model
  VIM, # to impute missing values using KNN
  class,  # to train KNN model
  patchwork,  # to plot multiple ggplots at once with same legend
  # ResourceSelection,  # Hosmer-Lemeshow GOF test
  # performance,  # Hosmer-Lemeshow GOF test
  # rms,  # Omnibus goodness of fit test for logistic regression
  mice,  # to perform multiple imputation by chained equations
  purrr, 
  foreach, 
  doParallel, 
  furrr,
  ggfortify  # for pca plots
)

# IMPORT AND PREPARE RAW DATA ----

# Import data
data(ACTG175)

# Select same variables from paper 1,
# make sure each column is correct type (numeric, factor)
# Note: here, treat Karnofsky score as numeric 
real <- ACTG175 %>%
  dplyr::select(c(pidnum, age, wtkg, hemo, homo, drugs, karnof, oprior, z30, preanti, 
                  race, gender, strat, symptom, cd40, arms, cd420, cd496, cens)) %>%
  mutate(strat = strat - 1)

# Double check sample size
# ACTG175 %>% group_by(pidnum) %>% summarise(count = n()) %>% nrow()  # 2139


# GENERATE MISSINGNESS ----

# First, restrict raw data to complete cases 
# (so we can then impose our own missingness mechanisms)
real_cc <- real %>% filter(!is.na(real$cd496))

# Standardize continuous variables so they are all on the same scale
# i.e., subtract the mean, divide by the standard deviation
real_cc <- real_cc %>%
  mutate(age_std = (age - mean(real_cc$age))/sd(real_cc$age),
         wtkg_std = (wtkg - mean(real_cc$wtkg))/sd(real_cc$wtkg),
         preanti_std = (preanti - mean(real_cc$preanti))/sd(real_cc$preanti),
         cd40_std = (cd40 - mean(real_cc$cd40))/sd(real_cc$cd40),
         cd420_std = (cd420 - mean(real_cc$cd420))/sd(real_cc$cd420),
         cd496_std = (cd496 - mean(real_cc$cd496))/sd(real_cc$cd496))

## For MAR, determine vars associated w/ variable at given time point in trial ----

# cd420
# First, fit a linear regression model to determine which variables are most associated 
# with the variable at the given time point in the trial (cd420)
cd420_mod <- lm(formula = cd420 ~ age + wtkg + as.factor(hemo) + as.factor(homo) +
                  as.factor(drugs) + as.factor(karnof) + as.factor(oprior) + as.factor(z30) +
                  preanti + as.factor(race) + as.factor(gender) + as.factor(strat) +
                  as.factor(symptom) + cd40 + as.factor(arms),
                data = real_cc)

summary(cd420_mod)
# most predictive: cd40, arms (1 v. 0), arms (2 v. 0), arms (3 v. 0)

# cd496
# First, fit a linear regression model to determine which variables are most associated 
# with the variable at the given time point in the trial (cd496)
cd496_mod <- lm(formula = cd496 ~ age + wtkg + as.factor(hemo) + as.factor(homo) +
                  as.factor(drugs) + as.factor(karnof) + as.factor(oprior) + as.factor(z30) +
                  preanti + as.factor(race) + as.factor(gender) + as.factor(strat) +
                  as.factor(symptom) + cd40 + as.factor(arms) + cd420,
                data = real_cc)

summary(cd496_mod)
# most predictive: cd40, arms (2 v. 0), cd420

# cens
# First, fit a logistic regression model to determine which variables are most associated 
# with the variable at the given time point in the trial (cens)
cens_mod <- glm(formula = as.factor(cens) ~ age + wtkg + as.factor(hemo) + as.factor(homo) +
                  as.factor(drugs) + as.factor(karnof) + as.factor(oprior) + as.factor(z30) +
                  preanti + as.factor(race) + as.factor(gender) + as.factor(strat) +
                  as.factor(symptom) + cd40 + as.factor(arms) + cd420 + cd496,
                data = real_cc,
                family = binomial)

summary(cens_mod)
# most predictive: cd40, cd496

# Set random seed ----
set.seed(20250224)

# Scenario 1A: Non-monotone x MAR  x 25% missing x strong mechanism ----
# Variables with missingness: Z_1 (cd420), Y (cens)

# Z_1:

# Define fixed parameter values
alpha_1 <- 10   # Coefficient for X_1 (cd40 - STANDARDIZED, so coef needs to be much larger)
alpha_2 <- 3.5  # Coefficient for A_1 (tx 1 v. 0)
alpha_3 <- 2   # Coefficient for A_2 (tx 2 v. 0)
alpha_4 <- 2.5   # Coefficient for A_3 (tx 3 v. 0)
alpha_5 <- 3  # Coefficient for X_2 (strat 1 v. 0)
alpha_6 <- 5  # Coefficient for X_3 (strat 2 v. 0)

# Function to find alpha_0 - use standardized continuous variables
find_alpha_0 <- function(alpha_0) {
  logit_p <- alpha_0 + 
    (alpha_1 * real_cc$cd40_std) + 
    ifelse(real_cc$arms == "1", alpha_2, 0) + 
    ifelse(real_cc$arms == "2", alpha_3, 0) + 
    ifelse(real_cc$arms == "3", alpha_4, 0) +
    ifelse(real_cc$strat == "1", alpha_5, 0) +
    ifelse(real_cc$strat == "2", alpha_6, 0) 
  p <- 1 / (1 + exp(-logit_p))  # convert log-odds to probability
  mean(p) - 0.75  # want mean(p) ~ 0.75
}

# Solve for alpha_0
alpha_0 <- uniroot(find_alpha_0, c(-5, 5), extendInt = "yes")$root
print(alpha_0)

# Compute logit(p) for each observation
logit_p <- alpha_0 + 
  (alpha_1 * real_cc$cd40_std) +                 # Effect of cd40 (continuous)
  ifelse(real_cc$arms == "1", alpha_2, 0) +  # Effect of tx 1 v. 0 (multi-category factor)
  ifelse(real_cc$arms == "2", alpha_3, 0) +  # Effect of tx 2 v. 0 (multi-category factor)
  ifelse(real_cc$arms == "3", alpha_4, 0) +  # Effect of tx 3 v. 0 (multi-category factor)  
  ifelse(real_cc$strat == "1", alpha_5, 0) +  # Effect of strat 1 v. 0 (multi-category factor)
  ifelse(real_cc$strat == "2", alpha_6, 0)    # Effect of strat 2 v. 0 (multi-category factor)

# Calculate p (i.e., convert to probability)
p <- exp(logit_p) / (1 + exp(logit_p))  

# Generate the binary missingness indicator for week 20
R_20 <- rbinom(n = nrow(real_cc), 1, p)

# Check the proportion of 1s
mean(R_20)  # Should be around 0.75 (since R = 1 if observed)

# Y:

# Define fixed parameter values
beta_1 <- 20    # Coefficient for X_1 (cd40 - STANDARDIZED, so coef needs to be much larger)
beta_2 <- 28   # Coefficient for Z_2 (cd496 - STANDARDIZED, so coef needs to be much larger)
beta_3 <- 5   # Coefficient for X_2 (strat 1 v. 0)
beta_4 <- 7   # Coefficient for X_3 (strat 2 v. 0)

# Function to find beta_0 - use standardized continuous variables
find_beta_0 <- function(beta_0) {
  logit_p <- beta_0 + 
    (beta_1 * real_cc$cd40_std) +
    (beta_2 * real_cc$cd496_std) +
    ifelse(real_cc$strat == "1", beta_3, 0) +
    ifelse(real_cc$strat == "2", beta_4, 0)
  p <- 1 / (1 + exp(-logit_p))  # convert log-odds to probability
  mean(p) - 0.75  # want mean(p) ~ 0.75
}

# Solve for beta_0
beta_0 <- uniroot(find_beta_0, c(-5, 5), extendInt = "yes")$root
print(beta_0)

# Compute logit(p) for each observation
logit_p <- beta_0 + 
  (beta_1 * real_cc$cd40_std) +  # Effect of cd40 (continuous)
  (beta_2 * real_cc$cd496_std) +  # Effect of cd496 (continuous)
  ifelse(real_cc$strat == "1", beta_3, 0) +  # Effect of strat 1 v. 0 (multi-category factor)
  ifelse(real_cc$strat == "2", beta_4, 0)    # Effect of strat 2 v. 0 (multi-category factor)


# Calculate p (i.e., convert to probability)
p <- exp(logit_p) / (1 + exp(logit_p))  

# Generate the binary missingness indicator for final visit
R_Y <- rbinom(n = nrow(real_cc), 1, p)

# Check the proportion of 1s
mean(R_Y)  # Should be around 0.75 (since R = 1 if observed)


# Add R_20, R_Y as columns to df with all var
data_simmiss_scen1A <- real_cc %>%
  mutate(R_20 = R_20,
         R_Y = R_Y)

# Impose missingness
data_simmiss_scen1A <- data_simmiss_scen1A %>%
  rename(cd420_complete = cd420,
         cens_complete = cens) %>%
  mutate(cd420 = ifelse(R_20 == 1, cd420_complete, NA),
         cens = ifelse(R_Y == 1, cens_complete, NA))

# Make sure variables are all of correct type 
data_simmiss_scen1A <- data_simmiss_scen1A %>%
  mutate(age = as.numeric(age),
         wtkg = as.numeric(wtkg),
         hemo = as.factor(hemo),
         homo = as.factor(homo),
         drugs = as.factor(drugs),
         karnof = as.factor(karnof),
         oprior = as.factor(oprior),
         z30 = as.factor(z30),
         preanti = as.numeric(preanti),
         race = as.factor(race),
         gender = as.factor(gender),
         strat = as.factor(strat),
         symptom = as.factor(symptom),
         cd40 = as.numeric(cd40),
         cd420 = as.numeric(cd420),
         cd496 = as.numeric(cd496),
         arms = as.factor(arms),
         cens = as.factor(cens)) 


# Scenario 1B: Monotone     x MAR  x 25% missing x strong mechanism ----
# Variables with missingness: Z_1 (cd420), Z_2 (cd496), Y (cens)

# Z_1:

# Define fixed parameter values
alpha_1 <- 10   # Coefficient for X_1 (cd40 - STANDARDIZED, so coef needs to be much larger)
alpha_2 <- 3.5  # Coefficient for A_1 (tx 1 v. 0)
alpha_3 <- 2   # Coefficient for A_2 (tx 2 v. 0)
alpha_4 <- 2.5   # Coefficient for A_3 (tx 3 v. 0)
alpha_5 <- 3   # Coefficient for X_2 (strat 1 v. 0)
alpha_6 <- 5   # Coefficient for X_3 (strat 2 v. 0)

# Function to find alpha_0 - use standardized continuous variables
find_alpha_0 <- function(alpha_0) {
  logit_p <- alpha_0 + 
    (alpha_1 * real_cc$cd40_std) + 
    ifelse(real_cc$arms == "1", alpha_2, 0) + 
    ifelse(real_cc$arms == "2", alpha_3, 0) + 
    ifelse(real_cc$arms == "3", alpha_4, 0) +
    ifelse(real_cc$strat == "1", alpha_5, 0) +
    ifelse(real_cc$strat == "2", alpha_6, 0)
  p <- 1 / (1 + exp(-logit_p))  # convert log-odds to probability
  mean(p) - 0.75  # want mean(p) ~ 0.75 (so missingness is not too low)
}

# Solve for alpha_0
alpha_0 <- uniroot(find_alpha_0, c(-5, 5), extendInt = "yes")$root
print(alpha_0)

# Compute logit(p) for each observation
logit_p_1 <- alpha_0 + 
  (alpha_1 * real_cc$cd40_std) +                 # Effect of cd40 (continuous)
  ifelse(real_cc$arms == "1", alpha_2, 0) +  # Effect of tx 1 v. 0 (multi-category factor)
  ifelse(real_cc$arms == "2", alpha_3, 0) +  # Effect of tx 2 v. 0 (multi-category factor)
  ifelse(real_cc$arms == "3", alpha_4, 0) +   # Effect of tx 3 v. 0 (multi-category factor)
  ifelse(real_cc$strat == "1", alpha_5, 0) + # Effect of strat 1 v. 0 (multi-category factor)
  ifelse(real_cc$strat == "2", alpha_6, 0)   # Effect of strat 2 v. 0 (multi-category factor)

# Calculate p (i.e., convert to probability)
p_1 <- exp(logit_p_1) / (1 + exp(logit_p_1))  

# Generate the binary missingness indicator for week 20
R_20 <- rbinom(n = nrow(real_cc), 1, p_1)

# Check the proportion of 1s
mean(R_20)  # Should be around 0.75 (since R = 1 if observed)

# Z_2:

# Define fixed parameter values
beta_1 <- 15   # Coefficient for X_1 (cd40 - STANDARDIZED, so coef needs to be much larger)
beta_2 <- 3   # Coefficient for A_2 (tx 2 v. 0)
beta_3 <- 15   # Coefficient for Z_1 (cd420 - STANDARDIZED, so coef needs to be much larger)
beta_4 <- 5  # Coefficient for X_2 (strat 1 v. 0)
beta_5 <- 7  # Coefficient for X_3 (strat 2 v. 0)

# Function to find beta_0 - use standardized continuous variables
find_beta_0 <- function(beta_0) {
  logit_p <- beta_0 + 
    (beta_1 * real_cc$cd40_std) + 
    ifelse(real_cc$arms == "2", beta_2, 0) + 
    (beta_3 * real_cc$cd420_std) +
    ifelse(real_cc$strat == "1", beta_4, 0) + 
    ifelse(real_cc$strat == "2", beta_5, 0) 
  p <- 1 / (1 + exp(-logit_p))  # convert log-odds to probability
  mean(p) - 0.75  # want mean(p) ~ 0.75 
  
}

# Solve for beta_0
beta_0 <- uniroot(find_beta_0, c(-5, 5), extendInt = "yes")$root
print(beta_0)

# Compute logit(p) for each observation
logit_p_2 <- beta_0 + 
  (beta_1 * real_cc$cd40_std) +             # Effect of cd40 (continuous)
  ifelse(real_cc$arms == "2", beta_2, 0) +  # Effect of tx 2 v. 0 (factor)
  (beta_3 * real_cc$cd420_std) +            # Effect of cd420 (continuous)
  ifelse(real_cc$strat == "1", beta_4, 0) +  # Effect of strat 1 v. 0 (factor)
  ifelse(real_cc$strat == "2", beta_5, 0)    # Effect of strat 2 v. 0 (factor)

# Calculate p (i.e., convert to probability)
p_2 <- exp(logit_p_2) / (1 + exp(logit_p_2))  

# Generate the binary missingness indicator for week 20
# Note: under monotone missingness, we manually set R_96 = 0 when R_20 = 0
# (Recall that R = 0 means missing)
R_96_raw <- rbinom(n = nrow(real_cc), 1, p_2)
R_96 <- ifelse(R_20 == 0, 0, R_96_raw)

# Check the proportion of 1s
mean(R_96)  # Should be less than mean(R_20) (since missingness should be greater than at Z_1)

# Y:

# Define fixed parameter values
gamma_1 <- 20   # Coefficient for X_1 (cd40 - STANDARDIZED, so coef needs to be much larger)
gamma_2 <- 28   # Coefficient for Z_2 (cd496 - STANDARDIZED, so coef needs to be much larger)
gamma_3 <- 6  # Coefficient for X_2 (strat 1 v. 0)
gamma_4 <- 8  # Coefficient for X_3 (strat 2 v. 0)

# Function to find gamma_0 - use standardized continuous variables
find_gamma_0 <- function(gamma_0) {
  logit_p <- gamma_0 + 
    (gamma_1 * real_cc$cd40_std) +
    (gamma_2 * real_cc$cd496_std) +
    ifelse(real_cc$strat == "1", gamma_3, 0) + 
    ifelse(real_cc$strat == "2", gamma_4, 0) 
  p <- 1 / (1 + exp(-logit_p))  # convert log-odds to probability
  mean(p) - 0.75  # want mean(p) ~ 0.75
}

# Solve for gamma_0
gamma_0 <- uniroot(find_gamma_0, c(-5, 5), extendInt = "yes")$root
print(gamma_0)

# Compute logit(p) for each observation
logit_p_Y <- gamma_0 + 
  (gamma_1 * real_cc$cd40_std) +  # Effect of cd40 (continuous)
  (gamma_2 * real_cc$cd496_std) +  # Effect of cd496 (continuous)
  ifelse(real_cc$strat == "1", gamma_3, 0) +  # Effect of strat 1 v. 0 (factor)
  ifelse(real_cc$strat == "2", gamma_4, 0)    # Effect of strat 2 v. 0 (factor)


# Calculate p (i.e., convert to probability)
p_Y <- exp(logit_p_Y) / (1 + exp(logit_p_Y))  

# Generate the binary missingness indicator for final visit
# Note: under monotone missingness, we manually set R_Y = 0 when R_96 = 0
# (Recall that R = 0 means missing)
R_Y_raw <- rbinom(n = nrow(real_cc), 1, p_Y)
R_Y <- ifelse(R_96 == 0, 0, R_Y_raw)

# Check the proportion of 1s
mean(R_Y)  # should be less than mean(R_96)


# Add R_20, R_96, R_Y as columns to df with all var
data_simmiss_scen1B <- real_cc %>%
  mutate(R_20 = R_20,
         R_96 = R_96,
         R_Y = R_Y)

# Impose missingness
data_simmiss_scen1B <- data_simmiss_scen1B %>%
  rename(cd420_complete = cd420,
         cd496_complete = cd496,
         cens_complete = cens) %>%
  mutate(cd420 = ifelse(R_20 == 1, cd420_complete, NA),
         cd496 = ifelse(R_96 == 1, cd496_complete, NA),
         cens = ifelse(R_Y == 1, cens_complete, NA))

# Make sure variables are all of correct type 
