# Scenario 3A: Non-monotone x MAR  x 10% missing x strong mechanism ----
# Variables with missingness: Z_1 (cd420), Y (cens)

# Z_1:

# Define fixed parameter values
alpha_1 <- 10   # Coefficient for X_1 (cd40 - STANDARDIZED, so coef needs to be much larger)
alpha_2 <- 3.5  # Coefficient for A_1 (tx 1 v. 0)
alpha_3 <- 2   # Coefficient for A_2 (tx 2 v. 0)
alpha_4 <- 2.5   # Coefficient for A_3 (tx 3 v. 0)
alpha_5 <- 3  # Coefficient for X_2 (strat 1 v. 0)
alpha_6 <- 5  # Coefficient for X_3 (strat 2 v. 0)

# Function to find alpha_0 - use standardized continuous variables
find_alpha_0 <- function(alpha_0) {
  logit_p <- alpha_0 + 
    (alpha_1 * real_cc$cd40_std) + 
    ifelse(real_cc$arms == "1", alpha_2, 0) + 
    ifelse(real_cc$arms == "2", alpha_3, 0) + 
    ifelse(real_cc$arms == "3", alpha_4, 0) +
    ifelse(real_cc$strat == "1", alpha_5, 0) +
    ifelse(real_cc$strat == "2", alpha_6, 0) 
  p <- 1 / (1 + exp(-logit_p))  # convert log-odds to probability
  mean(p) - 0.9  # want mean(p) ~ 0.9
}

# Solve for alpha_0
alpha_0 <- uniroot(find_alpha_0, c(-5, 5), extendInt = "yes")$root
print(alpha_0)

# Compute logit(p) for each observation
