  # Model to predict cd420
  # The prediction model is learned based on original data using a linear regression model
  cd4wk20_data_learn <- cbind(db, arms = Tx, cd420 = Post_Random$cd420)
  
  cd420_model <- lm(cd420 ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                      as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + as.factor(race) +
                      as.factor(gender) + as.factor(strat) + as.factor(symptom) + cd40 + 
                      as.factor(arms),
                    data = cd4wk20_data_learn)
  
  # Check if observed data at week 20 stage still includes the stratum 70 for karnof
  # If yes, then proceed with prediction as usual using fitted model
  # If not, then set synthetic cd420 to NA for synthetic patients with karnof = 70
  if(any(cd4wk20_data_learn[!is.na(cd4wk20_data_learn$cd420), ]$karnof == "70")) {
    cd420Simu <- Simulation_PostRandom_Wk20(Model = cd420_model, Covariates_synth = DataSimu, 
                                            Tx_synth = TxSimu)
  } else {
    # If synthetic baseline patient has a value 70 for karnof, set synthetic cd420 to NA
    indices_70 <- which(DataSimu$karnof == 70)
    
    cd420Simu_non70 <- Simulation_PostRandom_Wk20(Model = cd420_model, 
                                                  Covariates_synth = DataSimu[-c(indices_70), ], 
                                                  Tx_synth = TxSimu[-c(indices_70)])
    
    # Add NA for synthetic cd420 at the correct indices
    # Build full index
    full_index <- seq_along(cd420Simu_non70) %>% append(indices_70) %>% sort()
    
    # Expand vector with NA where needed (i.e., at indices_70)
    cd420Simu <- rep(NA, length(cd420Simu_non70) + length(indices_70))
    cd420Simu[-indices_70] <- cd420Simu_non70
  }
  
  # Simulation of post-randomization variable at week 96 (cd496)
  # Model to predict cd496
  # The prediction model is learned based on original data using a linear regression model
  cd4wk96_data_learn <- cbind(db, arms = Tx, cd420 = Post_Random$cd420, cd496 = Post_Random$cd496)
  
  cd496_model <- lm(cd496 ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                      as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + as.factor(race) +
                      as.factor(gender) + as.factor(strat) + as.factor(symptom) + cd40 + cd420 +
                      as.factor(arms),
                    data = cd4wk96_data_learn)
  
  # Check if observed data at week 96 stage still includes the stratum 70 for karnof
  # If yes, then proceed with prediction as usual using fitted model
  # If not, then set synthetic cd496 to NA for synthetic patients with karnof = 70
  if(any(cd4wk96_data_learn[!is.na(cd4wk96_data_learn$cd420), ]$karnof == "70")) {  # no missingness at wk 96 for non-monotone missing
    cd496Simu <- Simulation_PostRandom_Wk96(Model = cd496_model, Covariates_synth = DataSimu,
                                            Tx_synth = TxSimu, PostRandom_Wk20 = cd420Simu)
  } else {
    # If synthetic baseline patient has a value 70 for karnof, set synthetic cd496 to NA
    indices_70 <- which(DataSimu$karnof == 70)
    
    cd496Simu_non70 <- Simulation_PostRandom_Wk96(Model = cd496_model, 
                                                  Covariates_synth = DataSimu[-c(indices_70), ],
                                                  Tx_synth = TxSimu[-c(indices_70)], 
                                                  PostRandom_Wk20 = cd420Simu[-c(indices_70)])
    
    # Add NA for synthetic cd496 at the correct indices
    # Build full index
    full_index <- seq_along(cd496Simu_non70) %>% append(indices_70) %>% sort()
    
    # Expand vector with NA where needed (i.e., at indices_70)
    cd496Simu <- rep(NA, length(cd496Simu_non70) + length(indices_70))
    cd496Simu[-indices_70] <- cd496Simu_non70
  }
  
  # Simulation of the outcome for each virtual patients
  # Model to predict the outcome variable
  # The prediction model is learned based on original data using a logistic regression model 
  outcome_data_learn <- cbind(db[, !(names(db) %in% c("Outcome"))], 
                              arms = Tx, 
                              cd420 = Post_Random$cd420, 
                              cd496 = Post_Random$cd496,
                              cens = as.factor(Outcome))
  
  outcome_model <- glm(cens ~ age + wtkg + as.factor(hemo) + as.factor(homo) + 
                         as.factor(drugs) + as.factor(karnof) + oprior + as.factor(z30) + preanti + 
                         as.factor(race) + as.factor(gender) + as.factor(strat) + 
                         as.factor(symptom) + cd40 + cd420 + cd496 + as.factor(arms), 
                       data = outcome_data_learn, family = binomial())
  
  # Check if observed data at outcome stage still includes the stratum 70 for karnof
  # If yes, then proceed with prediction as usual using fitted model
  # If not, then set synthetic cens to NA for synthetic patients with karnof = 70
  if(any(outcome_data_learn[!is.na(outcome_data_learn$cd420) & !is.na(outcome_data_learn$cens), ]$karnof == "70")) {  # no missingness at wk 96 for non-monotone missing
    OutcomeSimu <- Simulation_DataOutcome(Model = outcome_model, Covariates_synth = DataSimu,
                                          Tx_synth = TxSimu, PostRandom_Wk20 = cd420Simu,
                                          PostRandom_Wk96 = cd496Simu)
  } else {
    # If synthetic baseline patient has a value 70 for karnof, set synthetic cens to NA
    indices_70 <- which(DataSimu$karnof == 70)
    
    OutcomeSimu_non70 <- Simulation_DataOutcome(Model = outcome_model, 
                                                Covariates_synth = DataSimu[-c(indices_70), ],
                                                Tx_synth = TxSimu[-c(indices_70)], 
                                                PostRandom_Wk20 = cd420Simu[-c(indices_70)],
                                                PostRandom_Wk96 = cd496Simu[-c(indices_70)])
    
    # Add NA for synthetic cens at the correct indices
    # Build full index
    full_index <- seq_along(OutcomeSimu_non70) %>% append(indices_70) %>% sort()
    
    # Expand vector with NA where needed (i.e., at indices_70)
    OutcomeSimu <- rep(NA, length(OutcomeSimu_non70) + length(indices_70))
    OutcomeSimu[-indices_70] <- OutcomeSimu_non70
  }
  
  # Final table of synthetic data generated via R-vine copula + execution models
  data_synthetic <- cbind(pidnum = c(1:nrow(DataSimu)),
                          DataSimu, 
                          arms = as.factor(TxSimu),
                          cd420 = cd420Simu,
                          cd496 = cd496Simu,
                          cens = as.factor(OutcomeSimu))
  
  return(data_synthetic)
}


# Non-monotone missingness

# IPW
# Missingness Indicator method, Pr(Y = obs | X, A, R_Z1, Z2, R_Z1:Z1)
generate1dataset_aipw_nonmono_missind <- function(real_data, random_seed, n_obs) {
  # Input: real_data is the real data dataframe, 
  #        random_seed is a number for the random seed,
  #        n_obs is the number of observations (i.e., rows) to generate
  # Output: dataframe of synthetic data
  
  # Definition of the outcome vector 
  Outcome <- real_data %>% dplyr::select(cens) %>% unlist() %>% as.factor() %>% unname()
  
  # Definition of the matrix of discrete covariates (at baseline)
  Cov_Discrete <- real_data %>% 
    dplyr::select(c(hemo, homo, drugs, oprior, z30, race, gender, strat, symptom, karnof)) %>%
    # mutate(strat = strat - 1) %>%
    lapply(., as.factor) %>%
    as.data.frame()
  
  # Definition of the matrix of continuous covariates (at baseline)
  Cov_Cont <- real_data %>%
    dplyr::select(c(age, wtkg, preanti, cd40))
  
  # Definition of the matrix of covariates (at baseline)
  Cov <- c(Cov_Discrete, Cov_Cont) %>% as.data.frame()
  
  # Definition of treatment assignment vector 
  Tx <- real_data %>% dplyr::select(arms) %>% unlist() %>% as.factor()
  
  # Definition of the matrix of post-randomization variables
  Post_Random <- real_data %>%
    dplyr::select(c(cd420, cd496))
  
  # Definition of the considered data
  data_allvar <- cbind(Cov, Tx, Post_Random, Outcome)
  
  # Definition of baseline data and outcome
  db <- cbind(Cov, Outcome)
  
  # Marginal distribution of the covariates are estimated using empirical estimator 
  set.seed(random_seed)
  
  # Estimation of the R-vine model based on original data
  Rvine_dist <- Estimation_Copula(Cov)
  
  # Simulation of virtual patients based on the R-vine model and empirical distribution (of the original data)
  DataSimu <- Simulation_Copula(n_obs, Rvine_dist, Cov)  # n_obs = number of rows in original data
  
  # Simulation of synthetic treatment allocation
  TxSimu <- Simulation_Treatment(N = n_obs, Treatment_Arms = c(0, 1, 2, 3), 
                                 Probabilities = c(0.25, 0.25, 0.25, 0.25))
  
  # Simulation of (complete) post-randomization variable at week 20 (cd420)
  
  # Data subset - include real patient ID (cd420 has missingness)
  cd4wk20_data_learn <- cbind(pidnum = real_data$pidnum, db, arms = Tx, 
                              cd420 = Post_Random$cd420, R_20 = real_data$R_20)
  
  # Model to estimate probability of being observed at week 20
  # Note: this model is also used to generate synthetic missingness (R_20)
  cd4wk20_probobs_model <- glm(as.factor(R_20) ~ age + wtkg + as.factor(hemo) + 
                                 as.factor(homo) + as.factor(drugs) + as.factor(karnof) + 
                                 as.factor(oprior) + as.factor(z30) + preanti + 
                                 as.factor(race) + as.factor(gender) + as.factor(strat) +
                                 as.factor(symptom) + cd40 + as.factor(arms),
                               data = cd4wk20_data_learn,
                               family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at week 20 for REAL data
  cd4wk20_data_learn$cd420_probobs <-  predict.glm(cd4wk20_probobs_model,
                                                   type = "response")
  
  # Weighted model to predict cd420
  # Note: weights = 1/p_i, where p_i = prob of being observed (estimated by cd4wk20_probobs)
  cd420_model <- lm(cd420 ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                      as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + 
                      as.factor(race) + as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                      cd40 + as.factor(arms),
                    data = cd4wk20_data_learn,
                    weights = (1/cd420_probobs))  # prob of being observed for REAL data
  
  # Generate synthetic cd420 (fully observed)
  cd420Simu <- Simulation_PostRandom_Wk20(Model = cd420_model, Covariates_synth = DataSimu, 
                                          Tx_synth = TxSimu)
  
  # Simulation of post-randomization variable at week 96 (cd496) - this variable is fully obs. in real data
  # Model to predict cd496
  # The prediction model is learned based on original data using a linear regression model
  cd4wk96_data_learn <- cbind(cd4wk20_data_learn, cd496 = Post_Random$cd496)
  
  # Fit a weighted execution model to account for missingness in Z1 (cd420)
  cd496_model <- lm(cd496 ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                      as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + as.factor(race) +
                      as.factor(gender) + as.factor(strat) + as.factor(symptom) + cd40 + cd420 +
                      as.factor(arms),
                    data = cd4wk96_data_learn,
                    weights = (1/cd420_probobs))  # prob of Z1 being observed for REAL data
  
  cd496Simu <- Simulation_PostRandom_Wk96(Model = cd496_model, Covariates_synth = DataSimu,
                                          Tx_synth = TxSimu, PostRandom_Wk20 = cd420Simu)
  
  # Simulation of the outcome
  
  # Data subset (not really a subset, here we use all variables)
  # cd420, cens (the outcome) have missingness
  outcome_data_learn <- cbind(cd4wk96_data_learn,
                              cens = as.factor(Outcome),
                              R_Y = real_data$R_Y,
                              R_20xZ1 = ifelse(cd4wk96_data_learn$R_20 == 1, 
                                               cd4wk96_data_learn$cd420,
                                               0))
  
  # Estimated probabilities of being observed at final visit for REAL data
  # based on the following model: 
  # Pr(Y = obs | X, A, R_Z1, Z2, R_Z1*Z1)
  
  # Model to estimate probability of being observed at final visit
  Y_probobs_model <- glm(as.factor(R_Y) ~ age + wtkg + as.factor(hemo) + as.factor(homo) +
                           as.factor(drugs) + as.factor(karnof) + as.factor(oprior) + 
                           as.factor(z30) + preanti + as.factor(race) + as.factor(gender) + 
                           as.factor(strat) + as.factor(symptom) + cd40 + as.factor(arms) + 
                           R_20 + cd496 + R_20xZ1,
                         data = outcome_data_learn,
                         family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at outcome for REAL data
  outcome_data_learn$cens_probobs <-  predict.glm(Y_probobs_model,
                                                  type = "response")  
  
  # Weighted model to predict cens (outcome)
  # Note: weights = 1/p_i, where p_i = prob of being observed (estimated by cens_probobs)
  outcome_model <- glm(cens ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                         as.factor(karnof) + as.factor(oprior) + as.factor(z30) + 
                         preanti + as.factor(race) + as.factor(gender) + as.factor(strat) + 
                         as.factor(symptom) + cd40 + as.factor(arms) +
                         R_20 + cd496 + R_20xZ1,
                       data = outcome_data_learn,
                       family = quasibinomial(link = "logit"),
                       weights = (1/(cens_probobs)))  # prob of being observed for REAL data
  
  # Generate synthetic outcome (all observed)
  # (Note: can't use general R function for execution model because need to add R_20 variables in model)
  outcome_synthetic_prob <- predict.glm(outcome_model,
                                        newdata = cbind(DataSimu,
                                                        arms = TxSimu,
                                                        cd420 = cd420Simu,
                                                        cd496 = cd496Simu,
                                                        R_20 = ifelse(!is.na(cd420Simu), 1, 0), # should be all 1
                                                        R_20xZ1 = ifelse(R_20 == 1, 
                                                                         cd420Simu,
                                                                         0)  # should be all cd420 values
                                        ),  
                                        type = "response")
  
  # Random sample of Unif(0,1)
  unif_samples <- runif(n = nrow(DataSimu), min = 0, max = 1)
  
  # Initialize vector to store final synthetic outcome values
  outcome_synthetic <- rep(NA, nrow(DataSimu))
  
  for (i in 1:length(outcome_synthetic)) {
    if (unif_samples[i] < outcome_synthetic_prob[i]) {
      outcome_synthetic[i] <- 1
    }
    else {
      outcome_synthetic[i] <- 0
    }
  }
  
  OutcomeSimu <- outcome_synthetic
  
  # Generate missingness (cd420, Y)
  
  # CD4 count at week 20 (Z1):
  
  # Estimated probabilities of being observed at week 20 for SIMULATED data
  cd4wk20Simu_probobs <- predict.glm(cd4wk20_probobs_model,
                                     newdata = cbind(DataSimu,
                                                     arms = TxSimu),
                                     type = "response")
  
  # Generate synthetic R_20
  R_20Simu <- rbinom(n = n_obs, size = 1, prob = cd4wk20Simu_probobs)
  
  # Generate cd420 (Z1) with missingness
  cd420Simu_withmiss <- cbind(R_20Simu, cd420Simu) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_20Simu == 1, cd420Simu, NA)) %>%
    pull(withmiss)
  
  
  
  # Outcome (cens, Y):
  
  # Estimated probabilities of being observed at week 20 for SIMULATED data
  OutcomeSimu_probobs <- predict.glm(Y_probobs_model,
                                     newdata = cbind(DataSimu,
                                                     arms = TxSimu,
                                                     cd420 = cd420Simu,
                                                     cd496 = cd496Simu,
                                                     R_20 = ifelse(!is.na(cd420Simu), 1, 0), # should be all 1
                                                     R_20xZ1 = ifelse(R_20 == 1, 
                                                                      cd420Simu,
                                                                      0)  # should be all cd420 values
                                     ),
                                     type = "response")
  
  # Generate synthetic R_Y
  R_YSimu = rbinom(n = n_obs, size = 1, prob = OutcomeSimu_probobs)
  
  # Generate cens (Y) with missingness
  OutcomeSimu_withmiss <- cbind(R_YSimu, OutcomeSimu) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_YSimu == 1, OutcomeSimu, NA)) %>%
    pull(withmiss)
  
  
  # Final table of synthetic data
  data_synthetic <- cbind(pidnum = c(1:nrow(DataSimu)),
                          DataSimu, 
                          arms = as.factor(TxSimu),
                          cd420_complete = cd420Simu, 
                          cd420 = cd420Simu_withmiss,
                          cd496 = cd496Simu,  # fully obs. in real data
                          cens_complete = as.factor(OutcomeSimu),
                          cens = as.factor(OutcomeSimu_withmiss))
  
  return(data_synthetic)
}

# Handle when missingness causes all observations with karnof = 70 to drop out from model fitting
generate1dataset_aipw_nonmono_missind_missingstrata <- function(real_data, random_seed, n_obs) {
  # Input: real_data is the real data dataframe, 
  #        random_seed is a number for the random seed,
  #        n_obs is the number of observations (i.e., rows) to generate
  # Output: dataframe of synthetic data
  
  # Definition of the outcome vector 
  Outcome <- real_data %>% dplyr::select(cens) %>% unlist() %>% as.factor() %>% unname()
  
  # Definition of the matrix of discrete covariates (at baseline)
  Cov_Discrete <- real_data %>% 
    dplyr::select(c(hemo, homo, drugs, oprior, z30, race, gender, strat, symptom, karnof)) %>%
    # mutate(strat = strat - 1) %>%
    lapply(., as.factor) %>%
    as.data.frame()
  
  # Definition of the matrix of continuous covariates (at baseline)
  Cov_Cont <- real_data %>%
    dplyr::select(c(age, wtkg, preanti, cd40))
  
  # Definition of the matrix of covariates (at baseline)
  Cov <- c(Cov_Discrete, Cov_Cont) %>% as.data.frame()
  
  # Definition of treatment assignment vector 
  Tx <- real_data %>% dplyr::select(arms) %>% unlist() %>% as.factor()
  
  # Definition of the matrix of post-randomization variables
  Post_Random <- real_data %>%
    dplyr::select(c(cd420, cd496))
  
  # Definition of the considered data
  data_allvar <- cbind(Cov, Tx, Post_Random, Outcome)
  
  # Definition of baseline data and outcome
  db <- cbind(Cov, Outcome)
  
  # Marginal distribution of the covariates are estimated using empirical estimator 
  set.seed(random_seed)
  
  # Estimation of the R-vine model based on original data
  Rvine_dist <- Estimation_Copula(Cov)
  
  # Simulation of virtual patients based on the R-vine model and empirical distribution (of the original data)
  DataSimu <- Simulation_Copula(n_obs, Rvine_dist, Cov)  # n_obs = number of rows in original data
  
  # Simulation of synthetic treatment allocation
  TxSimu <- Simulation_Treatment(N = n_obs, Treatment_Arms = c(0, 1, 2, 3), 
                                 Probabilities = c(0.25, 0.25, 0.25, 0.25))
  
  # Simulation of (complete) post-randomization variable at week 20 (cd420)
  # Note: for synthetic patients with karnof = 70, their cd420 value will be NA
  
  # Data subset - include real patient ID (cd420 has missingness)
  cd4wk20_data_learn <- cbind(pidnum = real_data$pidnum, db, arms = Tx, 
                              cd420 = Post_Random$cd420, R_20 = real_data$R_20)
  
  # Model to estimate probability of being observed at week 20
  # Note: this model is also used to generate synthetic missingness (R_20)
  cd4wk20_probobs_model <- glm(as.factor(R_20) ~ age + wtkg + as.factor(hemo) + 
                                 as.factor(homo) + as.factor(drugs) + as.factor(karnof) + 
                                 as.factor(oprior) + as.factor(z30) + preanti + 
                                 as.factor(race) + as.factor(gender) + as.factor(strat) +
                                 as.factor(symptom) + cd40 + as.factor(arms),
                               data = cd4wk20_data_learn,
                               family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at week 20 for REAL data
  cd4wk20_data_learn$cd420_probobs <-  predict.glm(cd4wk20_probobs_model,
                                                   type = "response")
  
  # Weighted model to predict cd420
  # Note: weights = 1/p_i, where p_i = prob of being observed (estimated by cd4wk20_probobs)
  cd420_model <- lm(cd420 ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                      as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + 
                      as.factor(race) + as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                      cd40 + as.factor(arms),
                    data = cd4wk20_data_learn,
                    weights = (1/cd420_probobs))  # prob of being observed for REAL data
  
  # Check if observed data at week 20 stage still includes the stratum 70 for karnof
  # If yes, then proceed with prediction as usual using fitted model
  # If not, then set synthetic cd420 to NA for synthetic patients with karnof = 70
  if(any(cd4wk20_data_learn[!is.na(cd4wk20_data_learn$cd420), ]$karnof == "70")) {
    cd420Simu <- Simulation_PostRandom_Wk20(Model = cd420_model, Covariates_synth = DataSimu, 
                                            Tx_synth = TxSimu)
  } else {
    # If synthetic baseline patient has a value 70 for karnof, set synthetic cd420 to NA
    indices_70 <- which(DataSimu$karnof == 70)
    
    cd420Simu_non70 <- Simulation_PostRandom_Wk20(Model = cd420_model, 
                                                  Covariates_synth = DataSimu[-c(indices_70), ], 
                                                  Tx_synth = TxSimu[-c(indices_70)])
    
    # Add NA for synthetic cd420 at the correct indices
    # Build full index
    full_index <- seq_along(cd420Simu_non70) %>% append(indices_70) %>% sort()
    
    # Expand vector with NA where needed (i.e., at indices_70)
    cd420Simu <- rep(NA, length(cd420Simu_non70) + length(indices_70))
    cd420Simu[-indices_70] <- cd420Simu_non70
  }
  
  # Simulation of post-randomization variable at week 96 (cd496) - this variable is fully obs. in real data
  # Model to predict cd496
  # The prediction model is learned based on original data using a linear regression model
  cd4wk96_data_learn <- cbind(cd4wk20_data_learn, cd496 = Post_Random$cd496)
  
  # Fit a weighted execution model to account for missingness in Z1 (cd420)
  cd496_model <- lm(cd496 ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                      as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + as.factor(race) +
                      as.factor(gender) + as.factor(strat) + as.factor(symptom) + cd40 + cd420 +
                      as.factor(arms),
                    data = cd4wk96_data_learn,
                    weights = (1/cd420_probobs))  # prob of Z1 being observed for REAL data
  
  # Check if observed data at week 96 stage still includes the stratum 70 for karnof
  # If yes, then proceed with prediction as usual using fitted model
  # If not, then set synthetic cd496 to NA for synthetic patients with karnof = 70
  if(any(cd4wk96_data_learn[!is.na(cd4wk96_data_learn$cd420), ]$karnof == "70")) {  
    cd496Simu <- Simulation_PostRandom_Wk96(Model = cd496_model, Covariates_synth = DataSimu,
                                            Tx_synth = TxSimu, PostRandom_Wk20 = cd420Simu)
  } else {
    # If synthetic baseline patient has a value 70 for karnof, set synthetic cd496 to NA
    indices_70 <- which(DataSimu$karnof == 70)
    
    cd496Simu_non70 <- Simulation_PostRandom_Wk96(Model = cd496_model, 
                                                  Covariates_synth = DataSimu[-c(indices_70), ],
                                                  Tx_synth = TxSimu[-c(indices_70)], 
                                                  PostRandom_Wk20 = cd420Simu[-c(indices_70)])
    
    # Add NA for synthetic cd496 at the correct indices
    # Build full index
    full_index <- seq_along(cd496Simu_non70) %>% append(indices_70) %>% sort()
    
    # Expand vector with NA where needed (i.e., at indices_70)
    cd496Simu <- rep(NA, length(cd496Simu_non70) + length(indices_70))
    cd496Simu[-indices_70] <- cd496Simu_non70
  }
  
  # Simulation of the outcome
  
  # Data subset (not really a subset, here we use all variables)
  # cd420, cens (the outcome) have missingness
  outcome_data_learn <- cbind(cd4wk96_data_learn,
                              cens = as.factor(Outcome),
                              R_Y = real_data$R_Y,
                              R_20xZ1 = ifelse(cd4wk96_data_learn$R_20 == 1, 
                                               cd4wk96_data_learn$cd420,
                                               0))
  
  # Estimated probabilities of being observed at final visit for REAL data
  # based on the following model: 
  # Pr(Y = obs | X, A, R_Z1, Z2, R_Z1*Z1)
  
  # Model to estimate probability of being observed at final visit
  Y_probobs_model <- glm(as.factor(R_Y) ~ age + wtkg + as.factor(hemo) + as.factor(homo) +
                           as.factor(drugs) + as.factor(karnof) + as.factor(oprior) + 
                           as.factor(z30) + preanti + as.factor(race) + as.factor(gender) + 
                           as.factor(strat) + as.factor(symptom) + cd40 + as.factor(arms) + 
                           R_20 + cd496 + R_20xZ1,
                         data = outcome_data_learn,
                         family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at outcome for REAL data
  outcome_data_learn$cens_probobs <-  predict.glm(Y_probobs_model,
                                                  type = "response")  
  
  # Weighted model to predict cens (outcome)
  # Note: weights = 1/p_i, where p_i = prob of being observed (estimated by cens_probobs)
  outcome_model <- glm(cens ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                         as.factor(karnof) + as.factor(oprior) + as.factor(z30) + 
                         preanti + as.factor(race) + as.factor(gender) + as.factor(strat) + 
                         as.factor(symptom) + cd40 + as.factor(arms) +
                         R_20 + cd496 + R_20xZ1,
                       data = outcome_data_learn,
                       family = quasibinomial(link = "logit"),
                       weights = (1/(cens_probobs)))  # prob of being observed for REAL data
  
  # Check if observed data at outcome stage still includes the stratum 70 for karnof
  # If yes, then proceed with prediction as usual using fitted model
  # If not, then set synthetic cens to NA for synthetic patients with karnof = 70
  if(any(outcome_data_learn[!is.na(outcome_data_learn$cd420) & !is.na(outcome_data_learn$cens), ]$karnof == "70")) {  # no missingness at wk 96 for non-monotone missing
    # Generate synthetic outcome (all observed)
    # (Note: can't use general R function for execution model because need to add R_20 variables in model)
    outcome_synthetic_prob <- predict.glm(outcome_model,
                                          newdata = cbind(DataSimu,
                                                          arms = TxSimu,
                                                          cd420 = cd420Simu,
                                                          cd496 = cd496Simu,
                                                          R_20 = ifelse(!is.na(cd420Simu), 1, 0), # should be all 1
                                                          R_20xZ1 = ifelse(R_20 == 1, 
                                                                           cd420Simu,
                                                                           0)  # should be all cd420 values
                                          ),  
                                          type = "response")
    
    # Random sample of Unif(0,1)
    unif_samples <- runif(n = nrow(DataSimu), min = 0, max = 1)
    
    # Initialize vector to store final synthetic outcome values
    outcome_synthetic <- rep(NA, nrow(DataSimu))
    
    for (i in 1:length(outcome_synthetic)) {
      if (unif_samples[i] < outcome_synthetic_prob[i]) {
        outcome_synthetic[i] <- 1
      }
      else {
        outcome_synthetic[i] <- 0
      }
    }
    
    OutcomeSimu <- outcome_synthetic
    
  } else {
    # If synthetic baseline patient has a value 70 for karnof, set synthetic cens to NA
    indices_70 <- which(DataSimu$karnof == 70)
    
    R_20_non70 <- ifelse(!is.na(cd420Simu[-c(indices_70)]), 1, 0)
    outcome_synthetic_prob <- predict.glm(outcome_model,
                                          newdata = cbind(DataSimu[-c(indices_70), ],
                                                          arms = TxSimu[-c(indices_70)],
                                                          cd420 = cd420Simu[-c(indices_70)],
                                                          cd496 = cd496Simu[-c(indices_70)],
                                                          R_20 = R_20_non70, # should be all 1
                                                          R_20xZ1 = ifelse(R_20_non70 == 1, 
                                                                           cd420Simu[-c(indices_70)],
                                                                           0)  # should be all cd420 values
                                          ),  
                                          type = "response")
    
    # Random sample of Unif(0,1)
    unif_samples <- runif(n = nrow(DataSimu[-c(indices_70), ]), min = 0, max = 1)
    
    # Initialize vector to store final synthetic outcome values
    outcome_synthetic <- rep(NA, nrow(DataSimu[-c(indices_70), ]))
    
    for (i in 1:length(outcome_synthetic)) {
      if (unif_samples[i] < outcome_synthetic_prob[i]) {
        outcome_synthetic[i] <- 1
      }
      else {
        outcome_synthetic[i] <- 0
      }
    }
    
    OutcomeSimu_non70 <- outcome_synthetic
    
    # Add NA for synthetic cens at the correct indices
    # Build full index
    full_index <- seq_along(OutcomeSimu_non70) %>% append(indices_70) %>% sort()
    
    # Expand vector with NA where needed (i.e., at indices_70)
    OutcomeSimu <- rep(NA, length(OutcomeSimu_non70) + length(indices_70))
    OutcomeSimu[-indices_70] <- OutcomeSimu_non70
  }
  
  # Generate missingness (cd420, Y)
  
  # CD4 count at week 20 (Z1):
  
  # Estimated probabilities of being observed at week 20 for SIMULATED data
  cd4wk20Simu_probobs <- predict.glm(cd4wk20_probobs_model,
                                     newdata = cbind(DataSimu,
                                                     arms = TxSimu),
                                     type = "response")
  
  # Generate synthetic R_20
  R_20Simu <- rbinom(n = n_obs, size = 1, prob = cd4wk20Simu_probobs)
  
  # Generate cd420 (Z1) with missingness
  cd420Simu_withmiss <- cbind(R_20Simu, cd420Simu) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_20Simu == 1, cd420Simu, NA)) %>%
    pull(withmiss)
  
  # Outcome (cens, Y):
  
  # Estimated probabilities of being observed at week 20 for SIMULATED data
  OutcomeSimu_probobs <- predict.glm(Y_probobs_model,
                                     newdata = cbind(DataSimu,
                                                     arms = TxSimu,
                                                     cd420 = cd420Simu,
                                                     cd496 = cd496Simu,
                                                     R_20 = ifelse(!is.na(cd420Simu), 1, 0), # should be all 1
                                                     R_20xZ1 = ifelse(R_20 == 1, 
                                                                      cd420Simu,
                                                                      0)  # should be all cd420 values
                                     ),
                                     type = "response")
  
  # Generate synthetic R_Y
  R_YSimu = rbinom(n = n_obs, size = 1, prob = OutcomeSimu_probobs)
  
  # Generate cens (Y) with missingness
  OutcomeSimu_withmiss <- cbind(R_YSimu, OutcomeSimu) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_YSimu == 1, OutcomeSimu, NA)) %>%
    pull(withmiss)
  
  # Final table of synthetic data
  data_synthetic <- cbind(pidnum = c(1:nrow(DataSimu)),
                          DataSimu, 
                          arms = as.factor(TxSimu),
                          cd420_complete = cd420Simu, 
                          cd420 = cd420Simu_withmiss,
                          cd496 = cd496Simu,  # fully obs. in real data
                          cens_complete = as.factor(OutcomeSimu),
                          cens = as.factor(OutcomeSimu_withmiss))
  
  return(data_synthetic)
}


# Force monotonicity method
generate1dataset_aipw_nonmono_forcemono <- function(real_data, random_seed, n_obs) {
  # Input: real_data is the real data dataframe, 
  #        random_seed is a number for the random seed,
  #        n_obs is the number of observations (i.e., rows) to generate
  # Output: dataframe of synthetic data
  
  # Definition of the outcome vector 
  Outcome <- real_data %>% dplyr::select(cens) %>% unlist() %>% as.factor() %>% unname()
  
  # Definition of the matrix of discrete covariates (at baseline)
  Cov_Discrete <- real_data %>% 
    dplyr::select(c(hemo, homo, drugs, oprior, z30, race, gender, strat, symptom, karnof)) %>%
    # mutate(strat = strat - 1) %>%
    lapply(., as.factor) %>%
    as.data.frame()
  
  # Definition of the matrix of continuous covariates (at baseline)
  Cov_Cont <- real_data %>%
    dplyr::select(c(age, wtkg, preanti, cd40))
  
  # Definition of the matrix of covariates (at baseline)
  Cov <- c(Cov_Discrete, Cov_Cont) %>% as.data.frame()
  
  # Definition of treatment assignment vector 
  Tx <- real_data %>% dplyr::select(arms) %>% unlist() %>% as.factor()
  
  # Definition of the matrix of post-randomization variables
  Post_Random <- real_data %>%
    dplyr::select(c(cd420, cd496))
  
  # Definition of the considered data
  data_allvar <- cbind(Cov, Tx, Post_Random, Outcome)
  
  # Definition of baseline data and outcome
  db <- cbind(Cov, Outcome)
  
  # Marginal distribution of the covariates are estimated using empirical estimator 
  set.seed(random_seed)
  
  # Estimation of the R-vine model based on original data
  Rvine_dist <- Estimation_Copula(Cov)
  
  # Simulation of virtual patients based on the R-vine model and empirical distribution (of the original data)
  DataSimu <- Simulation_Copula(n_obs, Rvine_dist, Cov)  # n_obs = number of rows in original data
  
  # Simulation of synthetic treatment allocation
  TxSimu <- Simulation_Treatment(N = n_obs, Treatment_Arms = c(0, 1, 2, 3), 
                                 Probabilities = c(0.25, 0.25, 0.25, 0.25))
  
  # Simulation of (complete) post-randomization variable at week 20 (cd420)
  
  # Data subset - include real patient ID (cd420 has missingness)
  cd4wk20_data_learn <- cbind(pidnum = real_data$pidnum, db, arms = Tx, 
                              cd420 = Post_Random$cd420, R_20 = real_data$R_20)
  
  # Model to estimate probability of being observed at week 20
  # Note: this model is also used to generate synthetic missingness (R_20)
  cd4wk20_probobs_model <- glm(as.factor(R_20) ~ age + wtkg + as.factor(hemo) + 
                                 as.factor(homo) + as.factor(drugs) + as.factor(karnof) + 
                                 as.factor(oprior) + as.factor(z30) + preanti + 
                                 as.factor(race) + as.factor(gender) + as.factor(strat) +
                                 as.factor(symptom) + cd40 + as.factor(arms),
                               data = cd4wk20_data_learn,
                               family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at week 20 for REAL data
  cd4wk20_data_learn$cd420_probobs <-  predict.glm(cd4wk20_probobs_model,
                                                   type = "response")
  
  # Weighted model to predict cd420
  # Note: weights = 1/p_i, where p_i = prob of being observed (estimated by cd4wk20_probobs)
  cd420_model <- lm(cd420 ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                      as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + 
                      as.factor(race) + as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                      cd40 + as.factor(arms),
                    data = cd4wk20_data_learn,
                    weights = (1/cd420_probobs))  # prob of being observed for REAL data
  
  # Generate synthetic cd420 (fully observed)
  cd420Simu <- Simulation_PostRandom_Wk20(Model = cd420_model, Covariates_synth = DataSimu, 
                                          Tx_synth = TxSimu)
  
  # Simulation of post-randomization variable at week 96 (cd496) - this variable is fully obs. in real data
  # Model to predict cd496
  # The prediction model is learned based on original data using a linear regression model
  cd4wk96_data_learn <- cbind(cd4wk20_data_learn, cd496 = Post_Random$cd496)
  
  # Fit a weighted execution model to account for missingness in Z1 (cd420)
  cd496_model <- lm(cd496 ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                      as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + as.factor(race) +
                      as.factor(gender) + as.factor(strat) + as.factor(symptom) + cd40 + cd420 +
                      as.factor(arms),
                    data = cd4wk96_data_learn,
                    weights = (1/cd420_probobs))  # prob of Z1 being observed for REAL data
  
  cd496Simu <- Simulation_PostRandom_Wk96(Model = cd496_model, Covariates_synth = DataSimu,
                                          Tx_synth = TxSimu, PostRandom_Wk20 = cd420Simu)
  
  # Simulation of the outcome
  
  # Data subset (not really a subset, here we use all variables)
  # cd420, cens (the outcome) have missingness
  outcome_data_learn <- cbind(cd4wk96_data_learn,
                              cens = as.factor(Outcome))
  
  # Force monotonicity
  outcome_data_learn_forcemono <- outcome_data_learn %>%
    mutate(cens = case_when(is.na(cd420) ~ NA,
                            TRUE ~ cens),
           R_Y = case_when(!is.na(cens) ~ 1,
                           TRUE ~ 0))
  
  # Estimated probabilities of being observed at final visit for REAL data
  # based on decomp: Pr(Y = obs | X, A, Z1, Z2) = Pr(Y = obs | X, A, Z1 = obs, Z2)*Pr(Z1 = obs | X, A, Z2)
  #                                                + Pr(Y = obs | X, A, Z1 = miss, Z2)*Pr(Z1 = miss | X, A, Z2)
  #                                             = Pr(Y = obs | X, A, Z1 = obs, Z2)*Pr(Z1 = obs | X, A, Z2)
  
  # First term: Pr(Y = obs | X, A, Z1 = obs, Z2)
  # Model to estimate probability of being observed at final visit (cens), given Z1 observed (cd420)
  Y_probobs_model <- glm(as.factor(R_Y) ~ age + wtkg + as.factor(hemo) + as.factor(homo) + 
                           as.factor(drugs) + as.factor(karnof) + as.factor(oprior) + 
                           as.factor(z30) + preanti + as.factor(race) + as.factor(gender) + 
                           as.factor(strat) + as.factor(symptom) + cd40 + as.factor(arms) + 
                           cd420 + cd496,
                         data = outcome_data_learn_forcemono,
                         family = binomial(link = "logit"))
  
  # Pr(Y = obs | X, A, Z1 = obs, Z2)
  Y_probobs_z1obs <- predict.glm(Y_probobs_model, type = "response")
  
  # Add Pr(Y = obs | X, A, Z1 = obs, Z2) to outcome_data_learn_forcemono
  outcome_data_learn_forcemono_z1obs <- outcome_data_learn_forcemono[rownames(outcome_data_learn_forcemono) %in% names(Y_probobs_z1obs), ]
  outcome_data_learn_forcemono_z1obs$Y_probobs_z1obs <- Y_probobs_z1obs
  outcome_data_learn_forcemono <- outcome_data_learn_forcemono %>%
    left_join(outcome_data_learn_forcemono_z1obs, by = colnames(outcome_data_learn_forcemono))
  
  # Second term: Pr(Z1 = obs | X, A, Z2)
  # Model to estimate probability of being observed at week 20 (cd420), including Z2 as a predictor!
  Z1_probobs_model_Z2pred <- glm(as.factor(R_20) ~ age + wtkg + as.factor(hemo) + as.factor(homo) + 
                                   as.factor(drugs) + as.factor(karnof) + as.factor(oprior) + 
                                   as.factor(z30) + preanti + as.factor(race) + as.factor(gender) + 
                                   as.factor(strat) + as.factor(symptom) + cd40 + as.factor(arms) + 
                                   cd496,
                                 data = outcome_data_learn_forcemono,
                                 family = binomial(link = "logit"))
  
  # Pr(Z1 = obs | X, A, Z2)
  outcome_data_learn_forcemono$Z1_probobs_Z2pred <- predict.glm(Z1_probobs_model_Z2pred, type = "response")
  
  # Calculate probability of being observed at final visit for REAL data
  outcome_data_learn_forcemono <- outcome_data_learn_forcemono %>%
    mutate(cens_probobs = case_when(!is.na(cd420) ~ Y_probobs_z1obs*Z1_probobs_Z2pred,  # Z1 = obs
                                    is.na(cd420) ~ 0))  # Z1 = miss --> Y must be missing (force monotonicity)
  
  # Weighted model to predict Y
  # Note: weights = 1/p_i, where p_i = prob of being observed (estimated by Y_probobs)
  outcome_model <- glm(cens ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                         as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + as.factor(race) +
                         as.factor(gender) + as.factor(strat) + as.factor(symptom) + cd40 + as.factor(arms) +
                         cd420 + cd496,
                       data = outcome_data_learn_forcemono,
                       family = quasibinomial(link = "logit"),
                       weights = (1/(cens_probobs)))  # prob of being observed for REAL data
  
  # Generate synthetic outcome (all observed)
  OutcomeSimu <- Simulation_DataOutcome(Model = outcome_model, Covariates_synth = DataSimu,
                                        Tx_synth = TxSimu, PostRandom_Wk20 = cd420Simu,
                                        PostRandom_Wk96 = cd496Simu)
  
  # Generate missingness (cd420, Y)
  
  # CD4 count at week 20 (Z1):
  
  # Estimated probabilities of being observed at week 20 for SIMULATED data
  cd4wk20Simu_probobs <- predict.glm(cd4wk20_probobs_model,
                                     newdata = cbind(DataSimu,
                                                     arms = TxSimu),
                                     type = "response")
  
  # Generate synthetic R_20
  R_20Simu <- rbinom(n = n_obs, size = 1, prob = cd4wk20Simu_probobs)
  
  # Generate cd420 (Z1) with missingness
  cd420Simu_withmiss <- cbind(R_20Simu, cd420Simu) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_20Simu == 1, cd420Simu, NA)) %>%
    pull(withmiss)
  
  # Outcome (cens, Y):
  
  # Estimated probabilities of being observed at final visit (cens) for SIMULATED data
  # If Z1 = obs, then prob is predicted using fitted model for R_Y
  # If Z1 = miss, then prob = 0 (i.e., prob of Y being observed = 0 when Z1 is missing) - force monotonicity
  datasynth_outcome <- cbind(DataSimu,
                             arms = TxSimu,
                             cd420 = cd420Simu,
                             cd420_withmiss = cd420Simu_withmiss,
                             cd496 = cd496Simu)
  
  # Pr(Y_synth = obs | X_synth, A_synth, Z1_synth = obs, Z2_synth)
  # Restrict to rows with OBSERVED synthetic Z1
  Ysynth_probobs_z1synthobs <- predict.glm(Y_probobs_model,
                                           newdata = datasynth_outcome[!is.na(datasynth_outcome$cd420_withmiss), ],
                                           type = "response")
  
  # Add Pr(Y_synth = obs | X_synth, A_synth, Z1_synth = obs, Z2_synth) to datasynth_outcome
  datasynth_outcome_z1obs <- datasynth_outcome[rownames(datasynth_outcome) %in% names(Ysynth_probobs_z1synthobs), ]
  datasynth_outcome_z1obs$Y_probobs_z1obs <- Ysynth_probobs_z1synthobs
  datasynth_outcome <- datasynth_outcome %>%
    left_join(datasynth_outcome_z1obs, by = colnames(datasynth_outcome))
  
  # Pr(Z1_synth = obs | X, A, Z2)
  datasynth_outcome$Z1_probobs_Z2pred <- predict.glm(Z1_probobs_model_Z2pred, 
                                                     newdata = datasynth_outcome,
                                                     type = "response")
  
  # Calculate probability of being observed at final visit for SYNTHETIC data
  datasynth_outcome <- datasynth_outcome %>%
    mutate(cens_probobs = case_when(!is.na(cd420_withmiss) ~ Y_probobs_z1obs*Z1_probobs_Z2pred,  # Z1 = obs
                                    is.na(cd420_withmiss) ~ 0))  # Z1 = miss --> Y must be missing (force monotonicity)
  
  # Generate synthetic R_Y
  R_YSimu = rbinom(n = n_obs, size = 1, prob = datasynth_outcome$cens_probobs)
  
  # Generate cens (Y) with missingness
  OutcomeSimu_withmiss <- cbind(R_YSimu, OutcomeSimu) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_YSimu == 1, OutcomeSimu, NA)) %>%
    pull(withmiss)
  
  
  # Final table of synthetic data 
  data_synthetic <- cbind(pidnum = c(1:nrow(DataSimu)),
                          DataSimu, 
                          arms = as.factor(TxSimu),
                          cd420_complete = cd420Simu, 
                          cd420 = cd420Simu_withmiss,
                          cd496 = cd496Simu,  # fully obs. in real data
                          cens_complete = as.factor(OutcomeSimu),
                          cens = as.factor(OutcomeSimu_withmiss))
  
  return(data_synthetic)
}

# Handle when missingness causes all observations with karnof = 70 to drop out from model fitting
generate1dataset_aipw_nonmono_forcemono_missingstrata <- function(real_data, random_seed, n_obs) {
  # Input: real_data is the real data dataframe, 
  #        random_seed is a number for the random seed,
  #        n_obs is the number of observations (i.e., rows) to generate
  # Output: dataframe of synthetic data
  
  # Definition of the outcome vector 
  Outcome <- real_data %>% dplyr::select(cens) %>% unlist() %>% as.factor() %>% unname()
  
  # Definition of the matrix of discrete covariates (at baseline)
  Cov_Discrete <- real_data %>% 
    dplyr::select(c(hemo, homo, drugs, oprior, z30, race, gender, strat, symptom, karnof)) %>%
    # mutate(strat = strat - 1) %>%
    lapply(., as.factor) %>%
    as.data.frame()
  
  # Definition of the matrix of continuous covariates (at baseline)
  Cov_Cont <- real_data %>%
    dplyr::select(c(age, wtkg, preanti, cd40))
  
  # Definition of the matrix of covariates (at baseline)
  Cov <- c(Cov_Discrete, Cov_Cont) %>% as.data.frame()
  
  # Definition of treatment assignment vector 
  Tx <- real_data %>% dplyr::select(arms) %>% unlist() %>% as.factor()
  
  # Definition of the matrix of post-randomization variables
  Post_Random <- real_data %>%
    dplyr::select(c(cd420, cd496))
  
  # Definition of the considered data
  data_allvar <- cbind(Cov, Tx, Post_Random, Outcome)
  
  # Definition of baseline data and outcome
  db <- cbind(Cov, Outcome)
  
  # Marginal distribution of the covariates are estimated using empirical estimator 
  set.seed(random_seed)
  
  # Estimation of the R-vine model based on original data
  Rvine_dist <- Estimation_Copula(Cov)
  
  # Simulation of virtual patients based on the R-vine model and empirical distribution (of the original data)
  DataSimu <- Simulation_Copula(n_obs, Rvine_dist, Cov)  # n_obs = number of rows in original data
  
  # Simulation of synthetic treatment allocation
  TxSimu <- Simulation_Treatment(N = n_obs, Treatment_Arms = c(0, 1, 2, 3), 
                                 Probabilities = c(0.25, 0.25, 0.25, 0.25))
  
  # Simulation of (complete) post-randomization variable at week 20 (cd420)
  
  # Data subset - include real patient ID (cd420 has missingness)
  cd4wk20_data_learn <- cbind(pidnum = real_data$pidnum, db, arms = Tx, 
                              cd420 = Post_Random$cd420, R_20 = real_data$R_20)
  
  # Model to estimate probability of being observed at week 20
  # Note: this model is also used to generate synthetic missingness (R_20)
  cd4wk20_probobs_model <- glm(as.factor(R_20) ~ age + wtkg + as.factor(hemo) + 
                                 as.factor(homo) + as.factor(drugs) + as.factor(karnof) + 
                                 as.factor(oprior) + as.factor(z30) + preanti + 
                                 as.factor(race) + as.factor(gender) + as.factor(strat) +
                                 as.factor(symptom) + cd40 + as.factor(arms),
                               data = cd4wk20_data_learn,
                               family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at week 20 for REAL data
  cd4wk20_data_learn$cd420_probobs <-  predict.glm(cd4wk20_probobs_model,
                                                   type = "response")
  
  # Weighted model to predict cd420
  # Note: weights = 1/p_i, where p_i = prob of being observed (estimated by cd4wk20_probobs)
  cd420_model <- lm(cd420 ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                      as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + 
                      as.factor(race) + as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                      cd40 + as.factor(arms),
                    data = cd4wk20_data_learn,
                    weights = (1/cd420_probobs))  # prob of being observed for REAL data
  
  # Check if observed data at week 20 stage still includes the stratum 70 for karnof
  # If yes, then proceed with prediction as usual using fitted model
  # If not, then set synthetic cd420 to NA for synthetic patients with karnof = 70
  if(any(cd4wk20_data_learn[!is.na(cd4wk20_data_learn$cd420), ]$karnof == "70")) {
    cd420Simu <- Simulation_PostRandom_Wk20(Model = cd420_model, Covariates_synth = DataSimu, 
                                            Tx_synth = TxSimu)
  } else {
    # If synthetic baseline patient has a value 70 for karnof, set synthetic cd420 to NA
    indices_70 <- which(DataSimu$karnof == 70)
    
    cd420Simu_non70 <- Simulation_PostRandom_Wk20(Model = cd420_model, 
                                                  Covariates_synth = DataSimu[-c(indices_70), ], 
                                                  Tx_synth = TxSimu[-c(indices_70)])
    
    # Add NA for synthetic cd420 at the correct indices
    # Build full index
    full_index <- seq_along(cd420Simu_non70) %>% append(indices_70) %>% sort()
    
    # Expand vector with NA where needed (i.e., at indices_70)
    cd420Simu <- rep(NA, length(cd420Simu_non70) + length(indices_70))
    cd420Simu[-indices_70] <- cd420Simu_non70
  }
  
  # Simulation of post-randomization variable at week 96 (cd496) - this variable is fully obs. in real data
  # Model to predict cd496
  # The prediction model is learned based on original data using a linear regression model
  cd4wk96_data_learn <- cbind(cd4wk20_data_learn, cd496 = Post_Random$cd496)
  
  # Fit a weighted execution model to account for missingness in Z1 (cd420)
  cd496_model <- lm(cd496 ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                      as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + as.factor(race) +
                      as.factor(gender) + as.factor(strat) + as.factor(symptom) + cd40 + cd420 +
                      as.factor(arms),
                    data = cd4wk96_data_learn,
                    weights = (1/cd420_probobs))  # prob of Z1 being observed for REAL data
  
  # Check if observed data at week 96 stage still includes the stratum 70 for karnof
  # If yes, then proceed with prediction as usual using fitted model
  # If not, then set synthetic cd496 to NA for synthetic patients with karnof = 70
  if(any(cd4wk96_data_learn[!is.na(cd4wk96_data_learn$cd420), ]$karnof == "70")) {  
    cd496Simu <- Simulation_PostRandom_Wk96(Model = cd496_model, Covariates_synth = DataSimu,
                                            Tx_synth = TxSimu, PostRandom_Wk20 = cd420Simu)
  } else {
    # If synthetic baseline patient has a value 70 for karnof, set synthetic cd496 to NA
    indices_70 <- which(DataSimu$karnof == 70)
    
    cd496Simu_non70 <- Simulation_PostRandom_Wk96(Model = cd496_model, 
                                                  Covariates_synth = DataSimu[-c(indices_70), ],
                                                  Tx_synth = TxSimu[-c(indices_70)], 
                                                  PostRandom_Wk20 = cd420Simu[-c(indices_70)])
    
    # Add NA for synthetic cd496 at the correct indices
    # Build full index
    full_index <- seq_along(cd496Simu_non70) %>% append(indices_70) %>% sort()
    
    # Expand vector with NA where needed (i.e., at indices_70)
    cd496Simu <- rep(NA, length(cd496Simu_non70) + length(indices_70))
    cd496Simu[-indices_70] <- cd496Simu_non70
  }
  
  # Simulation of the outcome
  
  # Data subset (not really a subset, here we use all variables)
  # cd420, cens (the outcome) have missingness
  outcome_data_learn <- cbind(cd4wk96_data_learn,
                              cens = as.factor(Outcome))
  
  # Force monotonicity
  outcome_data_learn_forcemono <- outcome_data_learn %>%
    mutate(cens = case_when(is.na(cd420) ~ NA,
                            TRUE ~ cens),
           R_Y = case_when(!is.na(cens) ~ 1,
                           TRUE ~ 0))
  
  # Estimated probabilities of being observed at final visit for REAL data
  # based on decomp: Pr(Y = obs | X, A, Z1, Z2) = Pr(Y = obs | X, A, Z1 = obs, Z2)*Pr(Z1 = obs | X, A, Z2)
  #                                                + Pr(Y = obs | X, A, Z1 = miss, Z2)*Pr(Z1 = miss | X, A, Z2)
  #                                             = Pr(Y = obs | X, A, Z1 = obs, Z2)*Pr(Z1 = obs | X, A, Z2)
  
  # First term: Pr(Y = obs | X, A, Z1 = obs, Z2)
  # Model to estimate probability of being observed at final visit (cens), given Z1 observed (cd420)
  Y_probobs_model <- glm(as.factor(R_Y) ~ age + wtkg + as.factor(hemo) + as.factor(homo) + 
                           as.factor(drugs) + as.factor(karnof) + as.factor(oprior) + 
                           as.factor(z30) + preanti + as.factor(race) + as.factor(gender) + 
                           as.factor(strat) + as.factor(symptom) + cd40 + as.factor(arms) + 
                           cd420 + cd496,
                         data = outcome_data_learn_forcemono,
                         family = binomial(link = "logit"))
  
  # Pr(Y = obs | X, A, Z1 = obs, Z2)
  Y_probobs_z1obs <- predict.glm(Y_probobs_model, type = "response")
  
  # Add Pr(Y = obs | X, A, Z1 = obs, Z2) to outcome_data_learn_forcemono
  outcome_data_learn_forcemono_z1obs <- outcome_data_learn_forcemono[rownames(outcome_data_learn_forcemono) %in% names(Y_probobs_z1obs), ]
  outcome_data_learn_forcemono_z1obs$Y_probobs_z1obs <- Y_probobs_z1obs
  outcome_data_learn_forcemono <- outcome_data_learn_forcemono %>%
    left_join(outcome_data_learn_forcemono_z1obs, by = colnames(outcome_data_learn_forcemono))
  
  # Second term: Pr(Z1 = obs | X, A, Z2)
  # Model to estimate probability of being observed at week 20 (cd420), including Z2 as a predictor!
  Z1_probobs_model_Z2pred <- glm(as.factor(R_20) ~ age + wtkg + as.factor(hemo) + as.factor(homo) + 
                                   as.factor(drugs) + as.factor(karnof) + as.factor(oprior) + 
                                   as.factor(z30) + preanti + as.factor(race) + as.factor(gender) + 
                                   as.factor(strat) + as.factor(symptom) + cd40 + as.factor(arms) + 
                                   cd496,
                                 data = outcome_data_learn_forcemono,
                                 family = binomial(link = "logit"))
  
  # Pr(Z1 = obs | X, A, Z2)
  outcome_data_learn_forcemono$Z1_probobs_Z2pred <- predict.glm(Z1_probobs_model_Z2pred, type = "response")
  
  # Calculate probability of being observed at final visit for REAL data
  outcome_data_learn_forcemono <- outcome_data_learn_forcemono %>%
    mutate(cens_probobs = case_when(!is.na(cd420) ~ Y_probobs_z1obs*Z1_probobs_Z2pred,  # Z1 = obs
                                    is.na(cd420) ~ 0))  # Z1 = miss --> Y must be missing (force monotonicity)
  
  # Weighted model to predict Y
  # Note: weights = 1/p_i, where p_i = prob of being observed (estimated by Y_probobs)
  outcome_model <- glm(cens ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                         as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + as.factor(race) +
                         as.factor(gender) + as.factor(strat) + as.factor(symptom) + cd40 + as.factor(arms) +
                         cd420 + cd496,
                       data = outcome_data_learn_forcemono,
                       family = quasibinomial(link = "logit"),
                       weights = (1/(cens_probobs)))  # prob of being observed for REAL data
  
  # Check if observed data at outcome stage still includes the stratum 70 for karnof
  # If yes, then proceed with prediction as usual using fitted model
  # If not, then set synthetic cens to NA for synthetic patients with karnof = 70
  if(any(outcome_data_learn[!is.na(outcome_data_learn$cd420) & !is.na(outcome_data_learn$cens), ]$karnof == "70")) {  # no missingness at wk 96 for non-monotone missing
    OutcomeSimu <- Simulation_DataOutcome(Model = outcome_model, Covariates_synth = DataSimu,
                                          Tx_synth = TxSimu, PostRandom_Wk20 = cd420Simu,
                                          PostRandom_Wk96 = cd496Simu)
  } else {
    # If synthetic baseline patient has a value 70 for karnof, set synthetic cens to NA
    indices_70 <- which(DataSimu$karnof == 70)
    
    OutcomeSimu_non70 <- Simulation_DataOutcome(Model = outcome_model, 
                                                Covariates_synth = DataSimu[-c(indices_70), ],
                                                Tx_synth = TxSimu[-c(indices_70)], 
                                                PostRandom_Wk20 = cd420Simu[-c(indices_70)],
                                                PostRandom_Wk96 = cd496Simu[-c(indices_70)])
    
    # Add NA for synthetic cens at the correct indices
    # Build full index
    full_index <- seq_along(OutcomeSimu_non70) %>% append(indices_70) %>% sort()
    
    # Expand vector with NA where needed (i.e., at indices_70)
    OutcomeSimu <- rep(NA, length(OutcomeSimu_non70) + length(indices_70))
    OutcomeSimu[-indices_70] <- OutcomeSimu_non70
  }
  
  # Generate missingness (cd420, Y)
  
  # CD4 count at week 20 (Z1):
  
  # Estimated probabilities of being observed at week 20 for SIMULATED data
  cd4wk20Simu_probobs <- predict.glm(cd4wk20_probobs_model,
                                     newdata = cbind(DataSimu,
                                                     arms = TxSimu),
                                     type = "response")
  
  # Generate synthetic R_20
  R_20Simu <- rbinom(n = n_obs, size = 1, prob = cd4wk20Simu_probobs)
  
  # Generate cd420 (Z1) with missingness
  cd420Simu_withmiss <- cbind(R_20Simu, cd420Simu) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_20Simu == 1, cd420Simu, NA)) %>%
    pull(withmiss)
  
  # Outcome (cens, Y):
  
  # Estimated probabilities of being observed at final visit (cens) for SIMULATED data
  # If Z1 = obs, then prob is predicted using fitted model for R_Y
  # If Z1 = miss, then prob = 0 (i.e., prob of Y being observed = 0 when Z1 is missing) - force monotonicity
  datasynth_outcome <- cbind(DataSimu,
                             arms = TxSimu,
                             cd420 = cd420Simu,
                             cd420_withmiss = cd420Simu_withmiss,
                             cd496 = cd496Simu)
  
  # Pr(Y_synth = obs | X_synth, A_synth, Z1_synth = obs, Z2_synth)
  # Restrict to rows with OBSERVED synthetic Z1
  Ysynth_probobs_z1synthobs <- predict.glm(Y_probobs_model,
                                           newdata = datasynth_outcome[!is.na(datasynth_outcome$cd420_withmiss), ],
                                           type = "response")
  
  # Add Pr(Y_synth = obs | X_synth, A_synth, Z1_synth = obs, Z2_synth) to datasynth_outcome
  datasynth_outcome_z1obs <- datasynth_outcome[rownames(datasynth_outcome) %in% names(Ysynth_probobs_z1synthobs), ]
  datasynth_outcome_z1obs$Y_probobs_z1obs <- Ysynth_probobs_z1synthobs
  datasynth_outcome <- datasynth_outcome %>%
    left_join(datasynth_outcome_z1obs, by = colnames(datasynth_outcome))
  
  # Pr(Z1_synth = obs | X, A, Z2)
  datasynth_outcome$Z1_probobs_Z2pred <- predict.glm(Z1_probobs_model_Z2pred, 
                                                     newdata = datasynth_outcome,
                                                     type = "response")
  
  # Calculate probability of being observed at final visit for SYNTHETIC data
  datasynth_outcome <- datasynth_outcome %>%
    mutate(cens_probobs = case_when(!is.na(cd420_withmiss) ~ Y_probobs_z1obs*Z1_probobs_Z2pred,  # Z1 = obs
                                    is.na(cd420_withmiss) ~ 0))  # Z1 = miss --> Y must be missing (force monotonicity)
  
  # Generate synthetic R_Y
  R_YSimu = rbinom(n = n_obs, size = 1, prob = datasynth_outcome$cens_probobs)
  
  # Generate cens (Y) with missingness
  OutcomeSimu_withmiss <- cbind(R_YSimu, OutcomeSimu) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_YSimu == 1, OutcomeSimu, NA)) %>%
    pull(withmiss)
  
  
  # Final table of synthetic data 
  data_synthetic <- cbind(pidnum = c(1:nrow(DataSimu)),
                          DataSimu, 
                          arms = as.factor(TxSimu),
                          cd420_complete = cd420Simu, 
                          cd420 = cd420Simu_withmiss,
                          cd496 = cd496Simu,  # fully obs. in real data
                          cens_complete = as.factor(OutcomeSimu),
                          cens = as.factor(OutcomeSimu_withmiss))
  
  return(data_synthetic)
}


# MI
# (Note: to generate synthetic missingness, we implement missingness indicator method)
generate1dataset_mi_nonmono <- function(real_data, random_seed, n_obs) {
  # Input: real_data is the real data dataframe, 
  #        random_seed is a number for the random seed,
  #        n_obs is the number of observations (i.e., rows) to generate
  # Output: dataframe of synthetic data
  
  # Definition of the outcome vector 
  Outcome <- real_data %>% dplyr::select(cens) %>% unlist() %>% as.factor() %>% unname()
  
  # Definition of the matrix of discrete covariates (at baseline)
  Cov_Discrete <- real_data %>% 
    dplyr::select(c(hemo, homo, drugs, oprior, z30, race, gender, strat, symptom, karnof)) %>%
    # mutate(strat = strat - 1) %>%
    lapply(., as.factor) %>%
    as.data.frame()
  
  # Definition of the matrix of continuous covariates (at baseline)
  Cov_Cont <- real_data %>%
    dplyr::select(c(age, wtkg, preanti, cd40))
  
  # Definition of the matrix of covariates (at baseline)
  Cov <- c(Cov_Discrete, Cov_Cont) %>% as.data.frame()
  
  # Definition of treatment assignment vector 
  Tx <- real_data %>% dplyr::select(arms) %>% unlist() %>% as.factor()
  
  # Definition of the matrix of post-randomization variables
  Post_Random <- real_data %>%
    dplyr::select(c(cd420, cd496))
  
  # Definition of the considered data
  data_allvar <- cbind(Cov, Tx, Post_Random, Outcome)
  
  # Definition of baseline data and outcome
  db <- cbind(Cov, Outcome)
  
  # Marginal distribution of the covariates are estimated using empirical estimator 
  set.seed(random_seed)
  
  # Estimation of the R-vine model based on original data
  Rvine_dist <- Estimation_Copula(Cov)
  
  # Simulation of virtual patients based on the R-vine model and empirical distribution (of the original data)
  DataSimu <- Simulation_Copula(n_obs, Rvine_dist, Cov)  # n_obs = number of rows in original data
  
  # Simulation of synthetic treatment allocation
  TxSimu <- Simulation_Treatment(N = n_obs, Treatment_Arms = c(0, 1, 2, 3), 
                                 Probabilities = c(0.25, 0.25, 0.25, 0.25))
  
  # Post-randomization variables have missingness, perform MI to get m complete data sets
  Imp_data <- real_data %>% dplyr::select(c(age, wtkg, hemo, homo,  drugs, karnof, oprior, 
                                            z30, preanti, race, gender, strat, symptom, cd40, 
                                            arms, cd420, cd496, cens))
  
  # Calculate m, where m ~ max(prop. of missingness)*100
  m <- round(colMeans(is.na(Imp_data)) %>% max()*100)  # m ~ prop. of missingness*100
  
  # Perform multiple imputation by chained equations (mice)
  imp <- mice(data = Imp_data, m = m, maxit = 10, seed = random_seed, print = FALSE)
  
  
  # Simulation of post-randomization variable at week 20 (cd420)
  
  # First, fit execution model to each of the m imputed data sets
  cd420model_imp <- with(imp,
                         lm(cd420 ~ as.factor(hemo) + as.factor(homo) + as.factor(drugs) + 
                              as.factor(oprior) + as.factor(z30) + as.factor(race) + 
                              as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                              as.factor(karnof) + age + wtkg + preanti + cd40 + as.factor(arms))
  )
  
  # Predict cd420 using each of the m model fits
  # Object to store predictions 
  # (rows represent synthetic patients/obs, columns represent predictions for the jth imputed data set)
  cd420_preds <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m fitted models
    
    # Model parameters
    param <- cd420model_imp$analyses[[j]]$coefficients %>% as.matrix()
    
    # synthetic X,A with column of 1's for intercept
    data <- model.matrix(~ ., data = cbind(DataSimu, as.factor(TxSimu)))
    
    # Predicted synthetic Z1, cd420
    pred <- t(param) %*% t(data) %>% t()
    
    cd420_preds[, j] <- pred
    
  }
  
  # Generate synthetic cd420 for each of the m model fits
  # Object to store m sets of generated cd420
  cd420_mgens <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m model fits
    
    # Predicted values using j'th model
    cd420_predict <- cd420_preds[, j]
    
    # Residuals from j'th model
    cd420_resid <- cd420model_imp$analyses[[j]]$residuals
    
    for (i in 1:nrow(cd420_mgens)) {
      # Get all possible values of pred + resid for the i'th observation
      pred_resid_sums <- cd420_predict[i] + cd420_resid
      
      # All pred + resid >= 0
      pred_resid_sums_pos <- pred_resid_sums[pred_resid_sums >= 0]
      
      # Randomly sample from non-negative sum values
      sample_val = sample(pred_resid_sums_pos, size = 1)
      
      # Save sample
      cd420_mgens[i, j] <- sample_val
    }
    
  }
  
  # Generate final synthetic cd420, Z^s_1 (all observed)
  cd420Simu <- apply(cd420_mgens, 1, sample, size = 1)
  
  
  # Simulation of post-randomization variable at week 96 (cd496)
  
  # First, fit execution model to each of the m imputed data sets
  # Note: even though cd496 is fully observed in the real data, cd420 has missingness
  #       so we still proceed with using the imputed data sets
  cd496model_imp <- with(imp,
                         lm(cd496 ~ as.factor(hemo) + as.factor(homo) + as.factor(drugs) + 
                              as.factor(oprior) + as.factor(z30) + as.factor(race) + 
                              as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                              as.factor(karnof) + age + wtkg + preanti + cd40 + as.factor(arms) +
                              cd420)
  )
  
  # Predict cd496 using each of the m model fits
  # Object to store predictions 
  # (rows represent synthetic patients/obs, columns represent predictions for the jth imputed data set)
  cd496_preds <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m fitted models
    
    # Model parameters
    param <- cd496model_imp$analyses[[j]]$coefficients %>% as.matrix()
    
    # synthetic X,A with column of 1's for intercept
    data <- model.matrix(~ ., data = cbind(DataSimu, as.factor(TxSimu), cd420Simu))
    
    # Predicted synthetic Z2, cd496
    pred <- t(param) %*% t(data) %>% t()
    
    cd496_preds[, j] <- pred
    
  }
  
  # Generate synthetic cd496 for each of the m model fits
  # Object to store m sets of generated cd496
  cd496_mgens <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m model fits
    
    # Predicted values using j'th model
    cd496_predict <- cd496_preds[, j]
    
    # Residuals from j'th model
    cd496_resid <- cd496model_imp$analyses[[j]]$residuals
    
    for (i in 1:nrow(cd496_mgens)) {
      # Get all possible values of pred + resid for the i'th observation
      pred_resid_sums <- cd496_predict[i] + cd496_resid
      
      # All pred + resid >= 0
      pred_resid_sums_pos <- pred_resid_sums[pred_resid_sums >= 0]
      
      # Randomly sample from non-negative sum values
      sample_val = sample(pred_resid_sums_pos, size = 1)
      
      # Save sample
      cd496_mgens[i, j] <- sample_val
    }
    
  }
  
  # Generate final synthetic cd496, Z^s_2 (all observed)
  cd496Simu <- apply(cd496_mgens, 1, sample, size = 1)
  
  
  # Simulation of the outcome for each virtual patients
  
  # First, fit execution model to each of the m imputed data sets
  censmodel_imp <- with(imp,
                        glm(as.factor(cens) ~ as.factor(hemo) + as.factor(homo) + as.factor(drugs) + 
                              as.factor(oprior) + as.factor(z30) + as.factor(race) + 
                              as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                              as.factor(karnof) + age + wtkg + preanti + cd40 + as.factor(arms) +
                              cd420 + cd496, family = "binomial")
  )
  
  # Predict cens using each of the m model fits
  # Object to store predictions 
  # (rows represent synthetic patients/obs, columns represent predictions for the jth imputed data set)
  cens_preds <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m fitted models
    
    # Model parameters
    param <- censmodel_imp$analyses[[j]]$coefficients %>% as.matrix()  # on logit scale
    
    # synthetic X,A with column of 1's for intercept
    data <- model.matrix(~ ., data = cbind(DataSimu, as.factor(TxSimu), cd420Simu, cd496Simu))
    
    # Predicted synthetic Z2, cd496 (on normal scale)
    pred <- expit(t(param) %*% t(data)) %>% t()
    
    cens_preds[, j] <- pred
    
  }
  
  # Generate synthetic cens for each of the m model fits
  # Object to store m sets of generated cens
  cens_mgens <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m model fits
    
    # Random sample of Unif(0,1)
    unif_samples <- runif(n = n_obs, min = 0, max = 1)
    
    for (i in 1:nrow(cens_mgens)) {
      if (unif_samples[i] < cens_preds[i, j]) {
        cens_mgens[i, j] <- 1
      }
      else {
        cens_mgens[i, j] <- 0
      }
    }
    
  }
  
  # Generate final synthetic cens, Z^s_2 (all observed)
  OutcomeSimu <- apply(cens_mgens, 1, sample, size = 1)
  
  
  # Finally, generate synthetic missingness (cd420, cens)
  
  # cd420 (Z1)
  
  # Data subset - include real patient ID
  cd4wk20_data_learn <- cbind(pidnum = real_data$pidnum, db, arms = Tx, 
                              cd420 = Post_Random$cd420, R_20 = real_data$R_20)
  
  # Model to estimate probability of being observed at week 20
  # Note: this model is also used to generate synthetic missingness (R_20)
  cd4wk20_probobs_model <- glm(as.factor(R_20) ~ age + wtkg + as.factor(hemo) + 
                                 as.factor(homo) + as.factor(drugs) + as.factor(karnof) + 
                                 as.factor(oprior) + as.factor(z30) + preanti + 
                                 as.factor(race) + as.factor(gender) + as.factor(strat) +
                                 as.factor(symptom) + cd40 + as.factor(arms),
                               data = cd4wk20_data_learn,
                               family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at week 20 for SIMULATED data
  cd4wk20Simu_probobs <- predict.glm(cd4wk20_probobs_model,
                                     newdata = cbind(DataSimu,
                                                     arms = TxSimu),
                                     type = "response")
  
  # Generate synthetic R_20
  R_20Simu <- rbinom(n = n_obs, size = 1, prob = cd4wk20Simu_probobs)
  
  # Generate cd420 (Z1) with missingness
  cd420Simu_withmiss <- cbind(R_20Simu, cd420Simu) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_20Simu == 1, cd420Simu, NA)) %>%
    pull(withmiss)
  
  # cens (Y)
  
  # Data subset (not really a subset, here we use all variables)
  # cd420, cens (the outcome) have missingness
  outcome_data_learn <- cbind(cd4wk20_data_learn, 
                              cd496 = Post_Random$cd496,
                              cens = as.factor(Outcome),
                              R_Y = real_data$R_Y,
                              R_20xZ1 = ifelse(cd4wk20_data_learn$R_20 == 1, 
                                               cd4wk20_data_learn$cd420,
                                               0))
  
  # Estimated probabilities of being observed at final visit for REAL data
  # based on the following model: 
  # Pr(Y = obs | X, A, R_Z1, Z2, R_Z1*Z1)
  
  # Model to estimate probability of being observed at final visit
  Y_probobs_model <- glm(as.factor(R_Y) ~ age + wtkg + as.factor(hemo) + as.factor(homo) +
                           as.factor(drugs) + as.factor(karnof) + as.factor(oprior) + 
                           as.factor(z30) + preanti + as.factor(race) + as.factor(gender) + 
                           as.factor(strat) + as.factor(symptom) + cd40 + as.factor(arms) + 
                           R_20 + cd496 + R_20xZ1,
                         data = outcome_data_learn,
                         family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at outcome for SIMULATED data
  OutcomeSimu_probobs <- predict.glm(Y_probobs_model,
                                     newdata = cbind(DataSimu,
                                                     arms = TxSimu,
                                                     cd420 = cd420Simu,
                                                     cd496 = cd496Simu,
                                                     R_20 = ifelse(!is.na(cd420Simu), 1, 0), # should be all 1
                                                     R_20xZ1 = ifelse(R_20 == 1, 
                                                                      cd420Simu,
                                                                      0)  # should be all cd420 values
                                     ),
                                     type = "response")
  
  # Generate synthetic R_Y
  R_YSimu = rbinom(n = n_obs, size = 1, prob = OutcomeSimu_probobs)
  
  # Generate cens (Y) with missingness
  OutcomeSimu_withmiss <- cbind(R_YSimu, OutcomeSimu) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_YSimu == 1, OutcomeSimu, NA)) %>%
    pull(withmiss)
  
  
  # Final table of synthetic data
  data_synthetic <- cbind(pidnum = c(1:nrow(DataSimu)),
                          DataSimu, 
                          arms = as.factor(TxSimu),
                          cd420_complete = cd420Simu, 
                          cd420 = cd420Simu_withmiss,
                          cd496 = cd496Simu,  # fully obs. in real data
                          cens_complete = as.factor(OutcomeSimu),
                          cens = as.factor(OutcomeSimu_withmiss))
  
  return(data_synthetic)
}


# Monotone missingness

# IPW
generate1dataset_aipw_mono <- function(real_data, random_seed, n_obs) {
  # Input: real_data is the real data dataframe, 
  #        random_seed is a number for the random seed,
  #        n_obs is the number of observations (i.e., rows) to generate
  # Output: dataframe of synthetic data
  
  # Definition of the outcome vector 
  Outcome <- real_data %>% dplyr::select(cens) %>% unlist() %>% as.factor() %>% unname()
  
  # Definition of the matrix of discrete covariates (at baseline)
  # Note: treat Karnofsky score as discrete
  Cov_Discrete <- real_data %>% 
    dplyr::select(c(hemo, homo, drugs, oprior, z30, race, gender, strat, symptom, karnof)) %>%
    # mutate(strat = strat - 1) %>%
    lapply(., as.factor) %>%
    as.data.frame()
  
  # Definition of the matrix of continuous covariates (at baseline)
  Cov_Cont <- real_data %>%
    dplyr::select(c(age, wtkg, preanti, cd40))
  
  # Definition of the matrix of covariates (at baseline)
  Cov <- c(Cov_Discrete, Cov_Cont) %>% as.data.frame()
  
  # Definition of treatment assignment vector 
  Tx <- real_data %>% dplyr::select(arms) %>% unlist() %>% as.factor()
  
  # Definition of the matrix of post-randomization variables
  Post_Random <- real_data %>%
    dplyr::select(c(cd420, cd496))
  
  # Definition of the considered data
  data_allvar <- cbind(Cov, Tx, Post_Random, Outcome)
  
  # Definition of baseline data and outcome
  db <- cbind(Cov, Outcome)
  
  # Marginal distribution of the covariates are estimated using empirical estimator 
  set.seed(random_seed)
  
  # Estimation of the R-vine model based on original data
  Rvine_dist <- Estimation_Copula(Cov)
  
  # Simulation of virtual patients based on the R-vine model and empirical distribution (of the original data)
  DataSimu <- Simulation_Copula(n_obs, Rvine_dist, Cov)  # n_obs = number of rows in original data
  
  # Simulation of synthetic treatment allocation
  TxSimu <- Simulation_Treatment(N = n_obs, Treatment_Arms = c(0, 1, 2, 3), 
                                 Probabilities = c(0.25, 0.25, 0.25, 0.25))
  
  # Simulation of (complete) post-randomization variable at week 20 (cd420)
  
  # Data subset - include real patient ID (cd420 has missingness)
  cd4wk20_data_learn <- cbind(pidnum = real_data$pidnum, db, arms = Tx, 
                              cd420 = Post_Random$cd420, R_20 = real_data$R_20)
  
  # Model to estimate probability of being observed at week 20
  # Note: this model is also used to generate synthetic missingness (R_20)
  cd4wk20_probobs_model <- glm(as.factor(R_20) ~ age + wtkg + as.factor(hemo) + 
                                 as.factor(homo) + as.factor(drugs) + as.factor(karnof) + 
                                 as.factor(oprior) + as.factor(z30) + preanti + 
                                 as.factor(race) + as.factor(gender) + as.factor(strat) +
                                 as.factor(symptom) + cd40 + as.factor(arms),
                               data = cd4wk20_data_learn,
                               family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at week 20 for REAL data
  cd4wk20_data_learn$cd420_probobs <-  predict.glm(cd4wk20_probobs_model,
                                                   type = "response")
  
  # Weighted model to predict cd420
  # Note: weights = 1/p_i, where p_i = prob of being observed (estimated by cd4wk20_probobs)
  cd420_model <- lm(cd420 ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                      as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + 
                      as.factor(race) + as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                      cd40 + as.factor(arms),
                    data = cd4wk20_data_learn,
                    weights = (1/cd420_probobs))  # prob of being observed for REAL data
  
  # Generate synthetic cd420 (fully observed)
  cd420Simu <- Simulation_PostRandom_Wk20(Model = cd420_model, Covariates_synth = DataSimu, 
                                          Tx_synth = TxSimu)
  
  # Simulation of post-randomization variable at week 96 (cd496)
  
  # Data subset (cd420, cd496 have missingness)
  cd4wk96_data_learn <- cbind(cd4wk20_data_learn,
                              cd496 = Post_Random$cd496, R_96 = real_data$R_96)
  
  # Estimated probabilities of being observed at week 96 for REAL data
  # based on decomp: Pr(Z2 = obs | X, A, Z1) = Pr(Z2 = obs | X, A, Z1 = obs)*Pr(Z1 = obs | X, A)
  #                                                + Pr(Z2 = obs | X, A, Z1 = miss)*Pr(Z1 = miss | X, A)
  #                                          = Pr(Z2 = obs | X, A, Z1 = obs)*Pr(Z1 = obs | X, A)
  
  # First term: Pr(Z2 = obs | X, A, Z1 = obs)
  # Model to estimate probability of being observed at week 96, given Z1 observed (cd420)
  cd4wk96_probobs_model <- glm(as.factor(R_96) ~ age + wtkg + as.factor(hemo) + 
                                 as.factor(homo) + as.factor(drugs) + as.factor(karnof) + 
                                 as.factor(oprior) + as.factor(z30) + preanti + 
                                 as.factor(race) + as.factor(gender) + as.factor(strat) +
                                 as.factor(symptom) + cd40 + as.factor(arms) + cd420,
                               data = cd4wk96_data_learn,
                               family = binomial(link = "logit"))
  
  # Pr(Z2 = obs | X, A, Z1 = obs)
  cd496_probobs_z1obs <- predict.glm(cd4wk96_probobs_model, type = "response")
  
  # Add Pr(Z2 = obs | X, A, Z1 = obs) to cd4wk96_data_learn
  cd4wk96_data_learn_z1obs <- cd4wk96_data_learn[rownames(cd4wk96_data_learn) %in% names(cd496_probobs_z1obs), ]
  cd4wk96_data_learn_z1obs$cd496_probobs_z1obs <- cd496_probobs_z1obs
  cd4wk96_data_learn <- cd4wk96_data_learn %>%
    left_join(cd4wk96_data_learn_z1obs, by = colnames(cd4wk96_data_learn))
  
  # Calculate probability of being observed at week 96 for REAL data
  cd4wk96_data_learn <- cd4wk96_data_learn %>%
    mutate(cd496_probobs = case_when(!is.na(cd420) ~ cd496_probobs_z1obs*cd420_probobs,  # Z1 = obs
                                     is.na(cd420) ~ 0))  # Z1 = miss --> Z2 must be missing
  
  # Weighted model to predict cd496
  # Note: weights = 1/p_i, where p_i = prob of being observed
  cd496_model <- lm(cd496 ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                      as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + 
                      as.factor(race) + as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                      cd40 + as.factor(arms) + cd420,
                    data = cd4wk96_data_learn,
                    weights = (1/cd496_probobs))  # prob of being observed for REAL data
  
  # Generate synthetic cd496
  cd496Simu <- Simulation_PostRandom_Wk96(Model = cd496_model, Covariates_synth = DataSimu,
                                          Tx_synth = TxSimu, PostRandom_Wk20 = cd420Simu)
  
  # Simulation of the outcome
  
  # Data subset (not really a subset, here we use all variables)
  # cd420, cd496, cens (the outcome) have missingness
  outcome_data_learn <- cbind(cd4wk96_data_learn,
                              cens = as.factor(Outcome),
                              R_Y = real_data$R_Y)
  
  # Estimated probabilities of being observed at final visit for REAL data
  # based on decomp: 
  # Pr(Y = obs | X, A, Z1, Z2) = Pr(Y = obs | X, A, Z1 = obs, Z2 = obs)*Pr(Z2 = obs | X, A, Z1)
  
  # Model to estimate probability of being observed at final visit, given Z1 and Z2 observed (cd420, cd496)
  Y_probobs_model <- glm(as.factor(R_Y) ~ age + wtkg + as.factor(hemo) + as.factor(homo) +
                           as.factor(drugs) + as.factor(karnof) + as.factor(oprior) + as.factor(z30) +
                           preanti + as.factor(race) + as.factor(gender) + as.factor(strat) +
                           as.factor(symptom) + cd40 + as.factor(arms) + cd420 + cd496,
                         data = outcome_data_learn,
                         family = binomial(link = "logit"))
  
  # Pr(Y = obs | X, A, Z1 = obs, Z2 = obs)
  Y_probobs_z1z2obs <- predict.glm(Y_probobs_model, type = "response")
  
  # Add Pr(Y = obs | X, A, Z1 = obs, Z2 = obs) to outcome_data_learn
  outcome_data_learn_z1z2obs <- outcome_data_learn[rownames(outcome_data_learn) %in% names(Y_probobs_z1z2obs), ]
  outcome_data_learn_z1z2obs$cens_probobs_z1z2obs <- Y_probobs_z1z2obs
  outcome_data_learn <- outcome_data_learn %>%
    left_join(outcome_data_learn_z1z2obs, by = colnames(outcome_data_learn))
  
  # Calculate probability of being observed at final visit for REAL data
  outcome_data_learn <- outcome_data_learn %>%
    mutate(cens_probobs = case_when(!is.na(cd496) ~ cens_probobs_z1z2obs*cd496_probobs,  # Z1, Z2 = obs
                                    is.na(cd496) ~ 0))  # Z1 = miss, Z2 = miss --> Y must be missing  
  
  # Weighted model to predict cens (outcome)
  # Note: weights = 1/p_i, where p_i = prob of being observed (estimated by Y_probobs)
  outcome_model <- glm(cens ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                         as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + as.factor(race) +
                         as.factor(gender) + as.factor(strat) + as.factor(symptom) + cd40 + as.factor(arms) +
                         cd420 + cd496,
                       data = outcome_data_learn,
                       family = quasibinomial(link = "logit"),
                       weights = (1/(cens_probobs)))  # prob of being observed for REAL data
  
  # Generate synthetic outcome (all observed)
  OutcomeSimu <- Simulation_DataOutcome(Model = outcome_model, Covariates_synth = DataSimu,
                                        Tx_synth = TxSimu, PostRandom_Wk20 = cd420Simu,
                                        PostRandom_Wk96 = cd496Simu)
  
  # Generate missingness (cd420, cd496, Y)
  
  # CD4 count at week 20 (Z1):
  
  # Estimated probabilities of being observed at week 20 for SIMULATED data
  cd4wk20Simu_probobs <- predict.glm(cd4wk20_probobs_model,
                                     newdata = cbind(DataSimu,
                                                     arms = TxSimu),
                                     type = "response")
  
  # Generate synthetic R_20
  R_20Simu <- rbinom(n = n_obs, size = 1, prob = cd4wk20Simu_probobs)
  
  # Generate cd420 (Z1) with missingness
  cd420Simu_withmiss <- cbind(R_20Simu, cd420Simu) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_20Simu == 1, cd420Simu, NA)) %>%
    pull(withmiss)
  
  # CD4 count at week 96 (Z2):
  
  # Estimated probabilities of being observed at week 96 for SIMULATED data
  # If Z1 = obs, then prob is predicted using fitted model for R_Z2
  # If Z1 = miss, then prob = 0 (i.e., prob of Z2 being observed = 0 when Z1 is missing)
  datasynth_wk96 <- cbind(pidnum = 1:nrow(DataSimu), DataSimu, arms = TxSimu, 
                          cd420 = cd420Simu, cd496 = cd496Simu,
                          R_20 = R_20Simu, cd420_withmiss = cd420Simu_withmiss)
  
  # Pr(Z2_synth = obs | X_synth, A_synth, Z1_synth = obs)
  # Restrict to rows with OBSERVED synthetic Z1
  cd496synth_probobs_z1synthobs <- predict.glm(cd4wk96_probobs_model, 
                                               newdata = datasynth_wk96[!is.na(datasynth_wk96$cd420_withmiss), ],  
                                               type = "response")
  
  # Add Pr(Z2_synth = obs | X_synth, A_synth, Z1_synth = obs) to datasynth_wk96
  datasynth_wk96_z1obs <- datasynth_wk96[rownames(datasynth_wk96) %in% names(cd496synth_probobs_z1synthobs), ]
  datasynth_wk96_z1obs$cd496_probobs_z1obs <- cd496synth_probobs_z1synthobs
  datasynth_wk96 <- datasynth_wk96 %>%
    left_join(datasynth_wk96_z1obs, by = colnames(datasynth_wk96))
  
  # Calculate prob. observed for Z2
  datasynth_wk96 <- datasynth_wk96 %>%
    mutate(cd496_probobs = case_when(!is.na(cd420_withmiss) ~ cd496_probobs_z1obs,
                                     is.na(cd420_withmiss) ~ 0))  # Z1 = miss --> Z2 must be missing
  
  # Generate synthetic R_96
  R_96Simu = rbinom(n = n_obs, size = 1, prob = datasynth_wk96$cd496_probobs)
  
  # Generate cd496 (Z2) with missingness
  cd496Simu_withmiss <- cbind(R_96Simu, cd496Simu = datasynth_wk96$cd496) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_96Simu == 1, cd496Simu, NA)) %>%
    pull(withmiss)
  
  # Outcome (cens, Y):
  
  # Estimated probabilities of being observed at final visit for SIMULATED data
  # If Z2 = obs (meaning Z1 = obs), then prob is predicted using fitted model for R_Y
  # If Z2 = miss, then prob = 0 (i.e., prob of Y being observed = 0 when Z2 is missing)
  datasynth_outcome <- cbind(datasynth_wk96, 
                             R_96 = R_96Simu, cd496_withmiss = cd496Simu_withmiss, cens = OutcomeSimu)
  
  # Pr(Y_synth = obs | X_synth, A_synth, Z1_synth = obs, Z2_synth = obs)
  # Restrict to rows with OBSERVED synthetic Z1 and OBSERVED synthetic Z2 (but if Z2 obs, then so is Z1)
  Ysynth_probobs_z1z2synthobs <- predict.glm(Y_probobs_model,
                                             newdata = datasynth_outcome[(!is.na(datasynth_outcome$cd496_withmiss)), ],  
                                             type = "response")
  
  # Pr(Y_synth = obs | X_synth, A_synth, Z1_synth = obs, Z2_synth = obs) to datasynth_outcome
  datasynth_outcome_z1z2obs <- datasynth_outcome[rownames(datasynth_outcome) %in% names(Ysynth_probobs_z1z2synthobs), ]
  datasynth_outcome_z1z2obs$cens_probobs_z1z2obs <- Ysynth_probobs_z1z2synthobs
  datasynth_outcome <- datasynth_outcome %>%
    left_join(datasynth_outcome_z1z2obs, by = colnames(datasynth_outcome))
  
  # Calculate prob. observed for Y
  datasynth_outcome <- datasynth_outcome %>%
    mutate(cens_probobs = case_when(!is.na(cd496_withmiss) ~ cens_probobs_z1z2obs,
                                    is.na(cd496_withmiss) ~ 0))  # Z2 = miss --> Y must be missing
  
  # Generate synthetic R_Y
  R_YSimu = rbinom(n = n_obs, size = 1, prob = datasynth_outcome$cens_probobs)
  
  # Generate cens (Y) with missingness
  OutcomeSimu_withmiss <- cbind(R_YSimu, OutcomeSimu = datasynth_outcome$cens) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_YSimu == 1, OutcomeSimu, NA)) %>%
    pull(withmiss)
  
  # Final table of synthetic data generated via R-vine copula + execution models
  data_synthetic <- cbind(pidnum = c(1:nrow(DataSimu)),
                          DataSimu, 
                          arms = as.factor(TxSimu),
                          cd420_complete = cd420Simu, 
                          cd420 = cd420Simu_withmiss,
                          cd496_complete = cd496Simu,
                          cd496 = cd496Simu_withmiss,
                          cens_complete = as.factor(OutcomeSimu),
                          cens = as.factor(OutcomeSimu_withmiss))
  
  return(data_synthetic)
}

# Handle when missingness causes all observations with karnof = 70 to drop out from model fitting
generate1dataset_aipw_mono_missingstrata <- function(real_data, random_seed, n_obs) {
  # Input: real_data is the real data dataframe, 
  #        random_seed is a number for the random seed,
  #        n_obs is the number of observations (i.e., rows) to generate
  # Output: dataframe of synthetic data
  
  # Definition of the outcome vector 
  Outcome <- real_data %>% dplyr::select(cens) %>% unlist() %>% as.factor() %>% unname()
  
  # Definition of the matrix of discrete covariates (at baseline)
  # Note: treat Karnofsky score as discrete
  Cov_Discrete <- real_data %>% 
    dplyr::select(c(hemo, homo, drugs, oprior, z30, race, gender, strat, symptom, karnof)) %>%
    # mutate(strat = strat - 1) %>%
    lapply(., as.factor) %>%
    as.data.frame()
  
  # Definition of the matrix of continuous covariates (at baseline)
  Cov_Cont <- real_data %>%
    dplyr::select(c(age, wtkg, preanti, cd40))
  
  # Definition of the matrix of covariates (at baseline)
  Cov <- c(Cov_Discrete, Cov_Cont) %>% as.data.frame()
  
  # Definition of treatment assignment vector 
  Tx <- real_data %>% dplyr::select(arms) %>% unlist() %>% as.factor()
  
  # Definition of the matrix of post-randomization variables
  Post_Random <- real_data %>%
    dplyr::select(c(cd420, cd496))
  
  # Definition of the considered data
  data_allvar <- cbind(Cov, Tx, Post_Random, Outcome)
  
  # Definition of baseline data and outcome
  db <- cbind(Cov, Outcome)
  
  # Marginal distribution of the covariates are estimated using empirical estimator 
  set.seed(random_seed)
  
  # Estimation of the R-vine model based on original data
  Rvine_dist <- Estimation_Copula(Cov)
  
  # Simulation of virtual patients based on the R-vine model and empirical distribution (of the original data)
  DataSimu <- Simulation_Copula(n_obs, Rvine_dist, Cov)  # n_obs = number of rows in original data
  
  # Simulation of synthetic treatment allocation
  TxSimu <- Simulation_Treatment(N = n_obs, Treatment_Arms = c(0, 1, 2, 3), 
                                 Probabilities = c(0.25, 0.25, 0.25, 0.25))
  
  # Simulation of (complete) post-randomization variable at week 20 (cd420)
  
  # Data subset - include real patient ID (cd420 has missingness)
  cd4wk20_data_learn <- cbind(pidnum = real_data$pidnum, db, arms = Tx, 
                              cd420 = Post_Random$cd420, R_20 = real_data$R_20)
  
  # Model to estimate probability of being observed at week 20
  # Note: this model is also used to generate synthetic missingness (R_20)
  cd4wk20_probobs_model <- glm(as.factor(R_20) ~ age + wtkg + as.factor(hemo) + 
                                 as.factor(homo) + as.factor(drugs) + as.factor(karnof) + 
                                 as.factor(oprior) + as.factor(z30) + preanti + 
                                 as.factor(race) + as.factor(gender) + as.factor(strat) +
                                 as.factor(symptom) + cd40 + as.factor(arms),
                               data = cd4wk20_data_learn,
                               family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at week 20 for REAL data
  cd4wk20_data_learn$cd420_probobs <-  predict.glm(cd4wk20_probobs_model,
                                                   type = "response")
  
  # Weighted model to predict cd420
  # Note: weights = 1/p_i, where p_i = prob of being observed (estimated by cd4wk20_probobs)
  cd420_model <- lm(cd420 ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                      as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + 
                      as.factor(race) + as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                      cd40 + as.factor(arms),
                    data = cd4wk20_data_learn,
                    weights = (1/cd420_probobs))  # prob of being observed for REAL data
  
  # Check if observed data at week 20 stage still includes the stratum 70 for karnof
  # If yes, then proceed with prediction as usual using fitted model
  # If not, then set synthetic cd420 to NA for synthetic patients with karnof = 70
  if(any(cd4wk20_data_learn[!is.na(cd4wk20_data_learn$cd420), ]$karnof == "70")) {
    cd420Simu <- Simulation_PostRandom_Wk20(Model = cd420_model, Covariates_synth = DataSimu, 
                                            Tx_synth = TxSimu)
  } else {
    # If synthetic baseline patient has a value 70 for karnof, set synthetic cd420 to NA
    indices_70 <- which(DataSimu$karnof == 70)
    
    cd420Simu_non70 <- Simulation_PostRandom_Wk20(Model = cd420_model, 
                                                  Covariates_synth = DataSimu[-c(indices_70), ], 
                                                  Tx_synth = TxSimu[-c(indices_70)])
    
    # Add NA for synthetic cd420 at the correct indices
    # Build full index
    full_index <- seq_along(cd420Simu_non70) %>% append(indices_70) %>% sort()
    
    # Expand vector with NA where needed (i.e., at indices_70)
    cd420Simu <- rep(NA, length(cd420Simu_non70) + length(indices_70))
    cd420Simu[-indices_70] <- cd420Simu_non70
  }
  
  # Simulation of post-randomization variable at week 96 (cd496)
  
  # Data subset (cd420, cd496 have missingness)
  cd4wk96_data_learn <- cbind(cd4wk20_data_learn,
                              cd496 = Post_Random$cd496, R_96 = real_data$R_96)
  
  # Estimated probabilities of being observed at week 96 for REAL data
  # based on decomp: Pr(Z2 = obs | X, A, Z1) = Pr(Z2 = obs | X, A, Z1 = obs)*Pr(Z1 = obs | X, A)
  #                                                + Pr(Z2 = obs | X, A, Z1 = miss)*Pr(Z1 = miss | X, A)
  #                                          = Pr(Z2 = obs | X, A, Z1 = obs)*Pr(Z1 = obs | X, A)
  
  # First term: Pr(Z2 = obs | X, A, Z1 = obs)
  # Model to estimate probability of being observed at week 96, given Z1 observed (cd420)
  cd4wk96_probobs_model <- glm(as.factor(R_96) ~ age + wtkg + as.factor(hemo) + 
                                 as.factor(homo) + as.factor(drugs) + as.factor(karnof) + 
                                 as.factor(oprior) + as.factor(z30) + preanti + 
                                 as.factor(race) + as.factor(gender) + as.factor(strat) +
                                 as.factor(symptom) + cd40 + as.factor(arms) + cd420,
                               data = cd4wk96_data_learn,
                               family = binomial(link = "logit"))
  
  # Pr(Z2 = obs | X, A, Z1 = obs)
  cd496_probobs_z1obs <- predict.glm(cd4wk96_probobs_model, type = "response")
  
  # Add Pr(Z2 = obs | X, A, Z1 = obs) to cd4wk96_data_learn
  cd4wk96_data_learn_z1obs <- cd4wk96_data_learn[rownames(cd4wk96_data_learn) %in% names(cd496_probobs_z1obs), ]
  cd4wk96_data_learn_z1obs$cd496_probobs_z1obs <- cd496_probobs_z1obs
  cd4wk96_data_learn <- cd4wk96_data_learn %>%
    left_join(cd4wk96_data_learn_z1obs, by = colnames(cd4wk96_data_learn))
  
  # Calculate probability of being observed at week 96 for REAL data
  cd4wk96_data_learn <- cd4wk96_data_learn %>%
    mutate(cd496_probobs = case_when(!is.na(cd420) ~ cd496_probobs_z1obs*cd420_probobs,  # Z1 = obs
                                     is.na(cd420) ~ 0))  # Z1 = miss --> Z2 must be missing
  
  # Weighted model to predict cd496
  # Note: weights = 1/p_i, where p_i = prob of being observed
  cd496_model <- lm(cd496 ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                      as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + 
                      as.factor(race) + as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                      cd40 + as.factor(arms) + cd420,
                    data = cd4wk96_data_learn,
                    weights = (1/cd496_probobs))  # prob of being observed for REAL data
  
  # Check if observed data at week 96 stage still includes the stratum 70 for karnof
  # If yes, then proceed with prediction as usual using fitted model
  # If not, then set synthetic cd496 to NA for synthetic patients with karnof = 70
  if(any(cd4wk96_data_learn[!is.na(cd4wk96_data_learn$cd420), ]$karnof == "70")) {  
    cd496Simu <- Simulation_PostRandom_Wk96(Model = cd496_model, Covariates_synth = DataSimu,
                                            Tx_synth = TxSimu, PostRandom_Wk20 = cd420Simu)
  } else {
    # If synthetic baseline patient has a value 70 for karnof, set synthetic cd496 to NA
    indices_70 <- which(DataSimu$karnof == 70)
    
    cd496Simu_non70 <- Simulation_PostRandom_Wk96(Model = cd496_model, 
                                                  Covariates_synth = DataSimu[-c(indices_70), ],
                                                  Tx_synth = TxSimu[-c(indices_70)], 
                                                  PostRandom_Wk20 = cd420Simu[-c(indices_70)])
    
    # Add NA for synthetic cd496 at the correct indices
    # Build full index
    full_index <- seq_along(cd496Simu_non70) %>% append(indices_70) %>% sort()
    
    # Expand vector with NA where needed (i.e., at indices_70)
    cd496Simu <- rep(NA, length(cd496Simu_non70) + length(indices_70))
    cd496Simu[-indices_70] <- cd496Simu_non70
  }
  
  # Simulation of the outcome
  
  # Data subset (not really a subset, here we use all variables)
  # cd420, cd496, cens (the outcome) have missingness
  outcome_data_learn <- cbind(cd4wk96_data_learn,
                              cens = as.factor(Outcome),
                              R_Y = real_data$R_Y)
  
  # Estimated probabilities of being observed at final visit for REAL data
  # based on decomp: 
  # Pr(Y = obs | X, A, Z1, Z2) = Pr(Y = obs | X, A, Z1 = obs, Z2 = obs)*Pr(Z2 = obs | X, A, Z1)
  
  # Model to estimate probability of being observed at final visit, given Z1 and Z2 observed (cd420, cd496)
  Y_probobs_model <- glm(as.factor(R_Y) ~ age + wtkg + as.factor(hemo) + as.factor(homo) +
                           as.factor(drugs) + as.factor(karnof) + as.factor(oprior) + as.factor(z30) +
                           preanti + as.factor(race) + as.factor(gender) + as.factor(strat) +
                           as.factor(symptom) + cd40 + as.factor(arms) + cd420 + cd496,
                         data = outcome_data_learn,
                         family = binomial(link = "logit"))
  
  # Pr(Y = obs | X, A, Z1 = obs, Z2 = obs)
  Y_probobs_z1z2obs <- predict.glm(Y_probobs_model, type = "response")
  
  # Add Pr(Y = obs | X, A, Z1 = obs, Z2 = obs) to outcome_data_learn
  outcome_data_learn_z1z2obs <- outcome_data_learn[rownames(outcome_data_learn) %in% names(Y_probobs_z1z2obs), ]
  outcome_data_learn_z1z2obs$cens_probobs_z1z2obs <- Y_probobs_z1z2obs
  outcome_data_learn <- outcome_data_learn %>%
    left_join(outcome_data_learn_z1z2obs, by = colnames(outcome_data_learn))
  
  # Calculate probability of being observed at final visit for REAL data
  outcome_data_learn <- outcome_data_learn %>%
    mutate(cens_probobs = case_when(!is.na(cd496) ~ cens_probobs_z1z2obs*cd496_probobs,  # Z1, Z2 = obs
                                    is.na(cd496) ~ 0))  # Z1 = miss, Z2 = miss --> Y must be missing  
  
  # Weighted model to predict cens (outcome)
  # Note: weights = 1/p_i, where p_i = prob of being observed (estimated by Y_probobs)
  outcome_model <- glm(cens ~ age + wtkg + as.factor(hemo) + as.factor(homo) + as.factor(drugs) +
                         as.factor(karnof) + as.factor(oprior) + as.factor(z30) + preanti + as.factor(race) +
                         as.factor(gender) + as.factor(strat) + as.factor(symptom) + cd40 + as.factor(arms) +
                         cd420 + cd496,
                       data = outcome_data_learn,
                       family = quasibinomial(link = "logit"),
                       weights = (1/(cens_probobs)))  # prob of being observed for REAL data
  
  # Check if observed data at outcome stage still includes the stratum 70 for karnof
  # If yes, then proceed with prediction as usual using fitted model
  # If not, then set synthetic cens to NA for synthetic patients with karnof = 70
  if(any(outcome_data_learn[!is.na(outcome_data_learn$cd420) & !is.na(outcome_data_learn$cens), ]$karnof == "70")) {  # no missingness at wk 96 for non-monotone missing
    OutcomeSimu <- Simulation_DataOutcome(Model = outcome_model, Covariates_synth = DataSimu,
                                          Tx_synth = TxSimu, PostRandom_Wk20 = cd420Simu,
                                          PostRandom_Wk96 = cd496Simu)
  } else {
    # If synthetic baseline patient has a value 70 for karnof, set synthetic cens to NA
    indices_70 <- which(DataSimu$karnof == 70)
    
    OutcomeSimu_non70 <- Simulation_DataOutcome(Model = outcome_model, 
                                                Covariates_synth = DataSimu[-c(indices_70), ],
                                                Tx_synth = TxSimu[-c(indices_70)], 
                                                PostRandom_Wk20 = cd420Simu[-c(indices_70)],
                                                PostRandom_Wk96 = cd496Simu[-c(indices_70)])
    
    # Add NA for synthetic cens at the correct indices
    # Build full index
    full_index <- seq_along(OutcomeSimu_non70) %>% append(indices_70) %>% sort()
    
    # Expand vector with NA where needed (i.e., at indices_70)
    OutcomeSimu <- rep(NA, length(OutcomeSimu_non70) + length(indices_70))
    OutcomeSimu[-indices_70] <- OutcomeSimu_non70
  }
  
  # Generate missingness (cd420, cd496, Y)
  
  # CD4 count at week 20 (Z1):
  
  # Estimated probabilities of being observed at week 20 for SIMULATED data
  cd4wk20Simu_probobs <- predict.glm(cd4wk20_probobs_model,
                                     newdata = cbind(DataSimu,
                                                     arms = TxSimu),
                                     type = "response")
  
  # Generate synthetic R_20
  R_20Simu <- rbinom(n = n_obs, size = 1, prob = cd4wk20Simu_probobs)
  
  # Generate cd420 (Z1) with missingness
  cd420Simu_withmiss <- cbind(R_20Simu, cd420Simu) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_20Simu == 1, cd420Simu, NA)) %>%
    pull(withmiss)
  
  # CD4 count at week 96 (Z2):
  
  # Estimated probabilities of being observed at week 96 for SIMULATED data
  # If Z1 = obs, then prob is predicted using fitted model for R_Z2
  # If Z1 = miss, then prob = 0 (i.e., prob of Z2 being observed = 0 when Z1 is missing)
  datasynth_wk96 <- cbind(pidnum = 1:nrow(DataSimu), DataSimu, arms = TxSimu, 
                          cd420 = cd420Simu, cd496 = cd496Simu,
                          R_20 = R_20Simu, cd420_withmiss = cd420Simu_withmiss)
  
  # Pr(Z2_synth = obs | X_synth, A_synth, Z1_synth = obs)
  # Restrict to rows with OBSERVED synthetic Z1
  cd496synth_probobs_z1synthobs <- predict.glm(cd4wk96_probobs_model, 
                                               newdata = datasynth_wk96[!is.na(datasynth_wk96$cd420_withmiss), ],  
                                               type = "response")
  
  # Add Pr(Z2_synth = obs | X_synth, A_synth, Z1_synth = obs) to datasynth_wk96
  datasynth_wk96_z1obs <- datasynth_wk96[rownames(datasynth_wk96) %in% names(cd496synth_probobs_z1synthobs), ]
  datasynth_wk96_z1obs$cd496_probobs_z1obs <- cd496synth_probobs_z1synthobs
  datasynth_wk96 <- datasynth_wk96 %>%
    left_join(datasynth_wk96_z1obs, by = colnames(datasynth_wk96))
  
  # Calculate prob. observed for Z2
  datasynth_wk96 <- datasynth_wk96 %>%
    mutate(cd496_probobs = case_when(!is.na(cd420_withmiss) ~ cd496_probobs_z1obs,
                                     is.na(cd420_withmiss) ~ 0))  # Z1 = miss --> Z2 must be missing
  
  # Generate synthetic R_96
  R_96Simu = rbinom(n = n_obs, size = 1, prob = datasynth_wk96$cd496_probobs)
  
  # Generate cd496 (Z2) with missingness
  cd496Simu_withmiss <- cbind(R_96Simu, cd496Simu = datasynth_wk96$cd496) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_96Simu == 1, cd496Simu, NA)) %>%
    pull(withmiss)
  
  # Outcome (cens, Y):
  
  # Estimated probabilities of being observed at final visit for SIMULATED data
  # If Z2 = obs (meaning Z1 = obs), then prob is predicted using fitted model for R_Y
  # If Z2 = miss, then prob = 0 (i.e., prob of Y being observed = 0 when Z2 is missing)
  datasynth_outcome <- cbind(datasynth_wk96, 
                             R_96 = R_96Simu, cd496_withmiss = cd496Simu_withmiss, cens = OutcomeSimu)
  
  # Pr(Y_synth = obs | X_synth, A_synth, Z1_synth = obs, Z2_synth = obs)
  # Restrict to rows with OBSERVED synthetic Z1 and OBSERVED synthetic Z2 (but if Z2 obs, then so is Z1)
  Ysynth_probobs_z1z2synthobs <- predict.glm(Y_probobs_model,
                                             newdata = datasynth_outcome[(!is.na(datasynth_outcome$cd496_withmiss)), ],  
                                             type = "response")
  
  # Pr(Y_synth = obs | X_synth, A_synth, Z1_synth = obs, Z2_synth = obs) to datasynth_outcome
  datasynth_outcome_z1z2obs <- datasynth_outcome[rownames(datasynth_outcome) %in% names(Ysynth_probobs_z1z2synthobs), ]
  datasynth_outcome_z1z2obs$cens_probobs_z1z2obs <- Ysynth_probobs_z1z2synthobs
  datasynth_outcome <- datasynth_outcome %>%
    left_join(datasynth_outcome_z1z2obs, by = colnames(datasynth_outcome))
  
  # Calculate prob. observed for Y
  datasynth_outcome <- datasynth_outcome %>%
    mutate(cens_probobs = case_when(!is.na(cd496_withmiss) ~ cens_probobs_z1z2obs,
                                    is.na(cd496_withmiss) ~ 0))  # Z2 = miss --> Y must be missing
  
  # Generate synthetic R_Y
  R_YSimu = rbinom(n = n_obs, size = 1, prob = datasynth_outcome$cens_probobs)
  
  # Generate cens (Y) with missingness
  OutcomeSimu_withmiss <- cbind(R_YSimu, OutcomeSimu = datasynth_outcome$cens) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_YSimu == 1, OutcomeSimu, NA)) %>%
    pull(withmiss)
  
  # Final table of synthetic data generated via R-vine copula + execution models
  data_synthetic <- cbind(pidnum = c(1:nrow(DataSimu)),
                          DataSimu, 
                          arms = as.factor(TxSimu),
                          cd420_complete = cd420Simu, 
                          cd420 = cd420Simu_withmiss,
                          cd496_complete = cd496Simu,
                          cd496 = cd496Simu_withmiss,
                          cens_complete = as.factor(OutcomeSimu),
                          cens = as.factor(OutcomeSimu_withmiss))
  
  return(data_synthetic)
}


# MI
generate1dataset_mi_mono <- function(real_data, random_seed, n_obs){
  # Input: real_data is the real data dataframe, 
  #        random_seed is a number for the random seed,
  #        n_obs is the number of observations (i.e., rows) to generate
  # Output: dataframe of synthetic data
  
  # Definition of the outcome vector 
  Outcome <- real_data %>% dplyr::select(cens) %>% unlist() %>% as.factor() %>% unname()
  
  # Definition of the matrix of discrete covariates (at baseline)
  Cov_Discrete <- real_data %>% 
    dplyr::select(c(hemo, homo, drugs, oprior, z30, race, gender, strat, symptom, karnof)) %>%
    # mutate(strat = strat - 1) %>%
    lapply(., as.factor) %>%
    as.data.frame()
  
  # Definition of the matrix of continuous covariates (at baseline)
  Cov_Cont <- real_data %>%
    dplyr::select(c(age, wtkg, preanti, cd40))
  
  # Definition of the matrix of covariates (at baseline)
  Cov <- c(Cov_Discrete, Cov_Cont) %>% as.data.frame()
  
  # Definition of treatment assignment vector 
  Tx <- real_data %>% dplyr::select(arms) %>% unlist() %>% as.factor()
  
  # Definition of the matrix of post-randomization variables
  Post_Random <- real_data %>%
    dplyr::select(c(cd420, cd496))
  
  # Definition of the considered data
  data_allvar <- cbind(Cov, Tx, Post_Random, Outcome)
  
  # Definition of baseline data and outcome
  db <- cbind(Cov, Outcome)
  
  # Marginal distribution of the covariates are estimated using empirical estimator 
  set.seed(random_seed)
  
  # Estimation of the R-vine model based on original data
  Rvine_dist <- Estimation_Copula(Cov)
  
  # Simulation of virtual patients based on the R-vine model and empirical distribution (of the original data)
  DataSimu <- Simulation_Copula(n_obs, Rvine_dist, Cov)  # n_obs = number of rows in original data
  
  # Simulation of synthetic treatment allocation
  TxSimu <- Simulation_Treatment(N = n_obs, Treatment_Arms = c(0, 1, 2, 3), 
                                 Probabilities = c(0.25, 0.25, 0.25, 0.25))
  
  # Post-randomization variables have missingness, perform MI to get m complete data sets
  Imp_data <- real_data %>% dplyr::select(c(age, wtkg, hemo, homo,  drugs, karnof, oprior, 
                                            z30, preanti, race, gender, strat, symptom, cd40, 
                                            arms, cd420, cd496, cens))
  
  # Calculate m, where m ~ max(prop. of missingness)*100
  m <- round(colMeans(is.na(Imp_data)) %>% max()*100)  # m ~ prop. of missingness*100
  
  # Perform multiple imputation by chained equations (mice)
  imp <- mice(data = Imp_data, m = m, maxit = 10, seed = random_seed, print = FALSE)
  
  
  # Simulation of post-randomization variable at week 20 (cd420)
  
  # First, fit execution model to each of the m imputed data sets
  cd420model_imp <- with(imp,
                         lm(cd420 ~ as.factor(hemo) + as.factor(homo) + as.factor(drugs) + 
                              as.factor(oprior) + as.factor(z30) + as.factor(race) + 
                              as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                              as.factor(karnof) + age + wtkg + preanti + cd40 + as.factor(arms))
  )
  
  # Predict cd420 using each of the m model fits
  # Object to store predictions 
  # (rows represent synthetic patients/obs, columns represent predictions for the jth imputed data set)
  cd420_preds <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m fitted models
    
    # Model parameters
    param <- cd420model_imp$analyses[[j]]$coefficients %>% as.matrix()
    
    # synthetic X,A with column of 1's for intercept
    data <- model.matrix(~ ., data = cbind(DataSimu, as.factor(TxSimu)))
    
    # Predicted synthetic Z1, cd420
    pred <- t(param) %*% t(data) %>% t()
    
    cd420_preds[, j] <- pred
    
  }
  
  # Generate synthetic cd420 for each of the m model fits
  # Object to store m sets of generated cd420
  cd420_mgens <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m model fits
    
    # Predicted values using j'th model
    cd420_predict <- cd420_preds[, j]
    
    # Residuals from j'th model
    cd420_resid <- cd420model_imp$analyses[[j]]$residuals
    
    for (i in 1:nrow(cd420_mgens)) {
      # Get all possible values of pred + resid for the i'th observation
      pred_resid_sums <- cd420_predict[i] + cd420_resid
      
      # All pred + resid >= 0
      pred_resid_sums_pos <- pred_resid_sums[pred_resid_sums >= 0]
      
      # Randomly sample from non-negative sum values
      sample_val = sample(pred_resid_sums_pos, size = 1)
      
      # Save sample
      cd420_mgens[i, j] <- sample_val
    }
    
  }
  
  # Generate final synthetic cd420, Z^s_1 (all observed)
  cd420Simu <- apply(cd420_mgens, 1, sample, size = 1)
  
  
  # Simulation of post-randomization variable at week 96 (cd496)
  
  # First, fit execution model to each of the m imputed data sets
  cd496model_imp <- with(imp,
                         lm(cd496 ~ as.factor(hemo) + as.factor(homo) + as.factor(drugs) + 
                              as.factor(oprior) + as.factor(z30) + as.factor(race) + 
                              as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                              as.factor(karnof) + age + wtkg + preanti + cd40 + as.factor(arms) +
                              cd420)
  )
  
  # Predict cd496 using each of the m model fits
  # Object to store predictions 
  # (rows represent synthetic patients/obs, columns represent predictions for the jth imputed data set)
  cd496_preds <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m fitted models
    
    # Model parameters
    param <- cd496model_imp$analyses[[j]]$coefficients %>% as.matrix()
    
    # synthetic X,A with column of 1's for intercept
    data <- model.matrix(~ ., data = cbind(DataSimu, as.factor(TxSimu), cd420Simu))
    
    # Predicted synthetic Z2, cd496
    pred <- t(param) %*% t(data) %>% t()
    
    cd496_preds[, j] <- pred
    
  }
  
  # Generate synthetic cd496 for each of the m model fits
  # Object to store m sets of generated cd496
  cd496_mgens <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m model fits
    
    # Predicted values using j'th model
    cd496_predict <- cd496_preds[, j]
    
    # Residuals from j'th model
    cd496_resid <- cd496model_imp$analyses[[j]]$residuals
    
    for (i in 1:nrow(cd496_mgens)) {
      # Get all possible values of pred + resid for the i'th observation
      pred_resid_sums <- cd496_predict[i] + cd496_resid
      
      # All pred + resid >= 0
      pred_resid_sums_pos <- pred_resid_sums[pred_resid_sums >= 0]
      
      # Randomly sample from non-negative sum values
      sample_val = sample(pred_resid_sums_pos, size = 1)
      
      # Save sample
      cd496_mgens[i, j] <- sample_val
    }
    
  }
  
  # Generate final synthetic cd496, Z^s_2 (all observed)
  cd496Simu <- apply(cd496_mgens, 1, sample, size = 1)
  
  
  # Simulation of the outcome for each virtual patients
  
  # First, fit execution model to each of the m imputed data sets
  censmodel_imp <- with(imp,
                        glm(as.factor(cens) ~ as.factor(hemo) + as.factor(homo) + as.factor(drugs) + 
                              as.factor(oprior) + as.factor(z30) + as.factor(race) + 
                              as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                              as.factor(karnof) + age + wtkg + preanti + cd40 + as.factor(arms) +
                              cd420 + cd496, family = "binomial")
  )
  
  # Predict cens using each of the m model fits
  # Object to store predictions 
  # (rows represent synthetic patients/obs, columns represent predictions for the jth imputed data set)
  cens_preds <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m fitted models
    
    # Model parameters
    param <- censmodel_imp$analyses[[j]]$coefficients %>% as.matrix()  # on logit scale
    
    # synthetic X,A with column of 1's for intercept
    data <- model.matrix(~ ., data = cbind(DataSimu, as.factor(TxSimu), cd420Simu, cd496Simu))
    
    # Predicted synthetic Z2, cd496 (on normal scale)
    pred <- expit(t(param) %*% t(data)) %>% t()
    
    cens_preds[, j] <- pred
    
  }
  
  # Generate synthetic cens for each of the m model fits
  # Object to store m sets of generated cens
  cens_mgens <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m model fits
    
    # Random sample of Unif(0,1)
    unif_samples <- runif(n = n_obs, min = 0, max = 1)
    
    for (i in 1:nrow(cens_mgens)) {
      if (unif_samples[i] < cens_preds[i, j]) {
        cens_mgens[i, j] <- 1
      }
      else {
        cens_mgens[i, j] <- 0
      }
    }
    
  }
  
  # Generate final synthetic cens, Y (all observed)
  OutcomeSimu <- apply(cens_mgens, 1, sample, size = 1)
  
  # Finally, generate synthetic missingness (cd420, cd496, cens)
  
  # cd420 (Z1)
  
  # Data subset - include real patient ID
  cd4wk20_data_learn <- cbind(pidnum = real_data$pidnum, db, arms = Tx, 
                              cd420 = Post_Random$cd420, R_20 = real_data$R_20)
  
  # Model to estimate probability of being observed at week 20
  # Note: this model is also used to generate synthetic missingness (R_20)
  cd4wk20_probobs_model <- glm(as.factor(R_20) ~ age + wtkg + as.factor(hemo) + 
                                 as.factor(homo) + as.factor(drugs) + as.factor(karnof) + 
                                 as.factor(oprior) + as.factor(z30) + preanti + 
                                 as.factor(race) + as.factor(gender) + as.factor(strat) +
                                 as.factor(symptom) + cd40 + as.factor(arms),
                               data = cd4wk20_data_learn,
                               family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at week 20 for SIMULATED data
  cd4wk20Simu_probobs <- predict.glm(cd4wk20_probobs_model,
                                     newdata = cbind(DataSimu,
                                                     arms = TxSimu),
                                     type = "response")
  
  # Generate synthetic R_20
  R_20Simu <- rbinom(n = n_obs, size = 1, prob = cd4wk20Simu_probobs)
  
  # Generate cd420 (Z1) with missingness
  cd420Simu_withmiss <- cbind(R_20Simu, cd420Simu) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_20Simu == 1, cd420Simu, NA)) %>%
    pull(withmiss)
  
  # cd496 (Z2)
  
  # Data subset (cd420, cd496 have missingness)
  cd4wk96_data_learn <- cbind(cd4wk20_data_learn,
                              cd496 = Post_Random$cd496, R_96 = real_data$R_96)
  
  # Estimated probabilities of being observed at week 96 for REAL data
  # based on decomp: Pr(Z2 = obs | X, A, Z1) = Pr(Z2 = obs | X, A, Z1 = obs)*Pr(Z1 = obs | X, A)
  #                                                + Pr(Z2 = obs | X, A, Z1 = miss)*Pr(Z1 = miss | X, A)
  #                                          = Pr(Z2 = obs | X, A, Z1 = obs)*Pr(Z1 = obs | X, A)
  
  # First term: Pr(Z2 = obs | X, A, Z1 = obs)
  # Model to estimate probability of being observed at week 96, given Z1 observed (cd420)
  cd4wk96_probobs_model <- glm(as.factor(R_96) ~ age + wtkg + as.factor(hemo) + 
                                 as.factor(homo) + as.factor(drugs) + as.factor(karnof) + 
                                 as.factor(oprior) + as.factor(z30) + preanti + 
                                 as.factor(race) + as.factor(gender) + as.factor(strat) +
                                 as.factor(symptom) + cd40 + as.factor(arms) + cd420,
                               data = cd4wk96_data_learn,
                               family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at week 96 for SIMULATED data
  # If Z1 = obs, then prob is predicted using fitted model for R_Z2
  # If Z1 = miss, then prob = 0 (i.e., prob of Z2 being observed = 0 when Z1 is missing)
  datasynth_wk96 <- cbind(pidnum = 1:nrow(DataSimu), DataSimu, arms = TxSimu, 
                          cd420 = cd420Simu, cd496 = cd496Simu,
                          R_20 = R_20Simu, cd420_withmiss = cd420Simu_withmiss)
  
  # Pr(Z2_synth = obs | X_synth, A_synth, Z1_synth = obs)
  # Restrict to rows with OBSERVED synthetic Z1
  cd496synth_probobs_z1synthobs <- predict.glm(cd4wk96_probobs_model, 
                                               newdata = datasynth_wk96[!is.na(datasynth_wk96$cd420_withmiss), ],  
                                               type = "response")
  
  # Add Pr(Z2_synth = obs | X_synth, A_synth, Z1_synth = obs) to datasynth_wk96
  datasynth_wk96_z1obs <- datasynth_wk96[rownames(datasynth_wk96) %in% names(cd496synth_probobs_z1synthobs), ]
  datasynth_wk96_z1obs$cd496_probobs_z1obs <- cd496synth_probobs_z1synthobs
  datasynth_wk96 <- datasynth_wk96 %>%
    left_join(datasynth_wk96_z1obs, by = colnames(datasynth_wk96))
  
  # Calculate prob. observed for Z2
  datasynth_wk96 <- datasynth_wk96 %>%
    mutate(cd496_probobs = case_when(!is.na(cd420_withmiss) ~ cd496_probobs_z1obs,
                                     is.na(cd420_withmiss) ~ 0))  # Z1 = miss --> Z2 must be missing
  
  # Generate synthetic R_96
  R_96Simu = rbinom(n = n_obs, size = 1, prob = datasynth_wk96$cd496_probobs)
  
  # Generate cd496 (Z2) with missingness
  cd496Simu_withmiss <- cbind(R_96Simu, cd496Simu = datasynth_wk96$cd496) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_96Simu == 1, cd496Simu, NA)) %>%
    pull(withmiss)
  
  # cens (Y)
  
  # Data subset (not really a subset, here we use all variables)
  # cd420, cd496, cens (the outcome) have missingness
  outcome_data_learn <- cbind(cd4wk96_data_learn,
                              cens = as.factor(Outcome),
                              R_Y = real_data$R_Y)
  
  # Estimated probabilities of being observed at final visit for REAL data
  # based on decomp: 
  # Pr(Y = obs | X, A, Z1, Z2) = Pr(Y = obs | X, A, Z1 = obs, Z2 = obs)*Pr(Z2 = obs | X, A, Z1)
  
  # Model to estimate probability of being observed at final visit, given Z1 and Z2 observed (cd420, cd496)
  Y_probobs_model <- glm(as.factor(R_Y) ~ age + wtkg + as.factor(hemo) + as.factor(homo) +
                           as.factor(drugs) + as.factor(karnof) + as.factor(oprior) + as.factor(z30) +
                           preanti + as.factor(race) + as.factor(gender) + as.factor(strat) +
                           as.factor(symptom) + cd40 + as.factor(arms) + cd420 + cd496,
                         data = outcome_data_learn,
                         family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at final visit for SIMULATED data
  # If Z2 = obs (meaning Z1 = obs), then prob is predicted using fitted model for R_Y
  # If Z2 = miss, then prob = 0 (i.e., prob of Y being observed = 0 when Z2 is missing)
  datasynth_outcome <- cbind(datasynth_wk96, 
                             R_96 = R_96Simu, cd496_withmiss = cd496Simu_withmiss, cens = OutcomeSimu)
  
  # Pr(Y_synth = obs | X_synth, A_synth, Z1_synth = obs, Z2_synth = obs)
  # Restrict to rows with OBSERVED synthetic Z1 and OBSERVED synthetic Z2 (but if Z2 obs, then so is Z1)
  Ysynth_probobs_z1z2synthobs <- predict.glm(Y_probobs_model,
                                             newdata = datasynth_outcome[(!is.na(datasynth_outcome$cd496_withmiss)), ],  
                                             type = "response")
  
  # Pr(Y_synth = obs | X_synth, A_synth, Z1_synth = obs, Z2_synth = obs) to datasynth_outcome
  datasynth_outcome_z1z2obs <- datasynth_outcome[rownames(datasynth_outcome) %in% names(Ysynth_probobs_z1z2synthobs), ]
  datasynth_outcome_z1z2obs$cens_probobs_z1z2obs <- Ysynth_probobs_z1z2synthobs
  datasynth_outcome <- datasynth_outcome %>%
    left_join(datasynth_outcome_z1z2obs, by = colnames(datasynth_outcome))
  
  # Calculate prob. observed for Y
  datasynth_outcome <- datasynth_outcome %>%
    mutate(cens_probobs = case_when(!is.na(cd496_withmiss) ~ cens_probobs_z1z2obs,
                                    is.na(cd496_withmiss) ~ 0))  # Z2 = miss --> Y must be missing
  
  # Generate synthetic R_Y
  R_YSimu = rbinom(n = n_obs, size = 1, prob = datasynth_outcome$cens_probobs)
  
  # Generate cens (Y) with missingness
  OutcomeSimu_withmiss <- cbind(R_YSimu, OutcomeSimu = datasynth_outcome$cens) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_YSimu == 1, OutcomeSimu, NA)) %>%
    pull(withmiss)
  
  # Final table of synthetic data generated via R-vine copula + execution models
  data_synthetic <- cbind(pidnum = c(1:nrow(DataSimu)),
                          DataSimu,
                          arms = as.factor(TxSimu),
                          cd420_complete = cd420Simu,
                          cd420 = cd420Simu_withmiss,
                          cd496_complete = cd496Simu,
                          cd496 = cd496Simu_withmiss,
                          cens_complete = as.factor(OutcomeSimu),
                          cens = as.factor(OutcomeSimu_withmiss))
  
  return(data_synthetic)
}

# Handle when missingness causes all observations with karnof = 70 to drop out from model fitting
generate1dataset_mi_mono_missingstrata <- function(real_data, random_seed, n_obs){
  # Input: real_data is the real data dataframe, 
  #        random_seed is a number for the random seed,
  #        n_obs is the number of observations (i.e., rows) to generate
  # Output: dataframe of synthetic data
  
  # Definition of the outcome vector 
  Outcome <- real_data %>% dplyr::select(cens) %>% unlist() %>% as.factor() %>% unname()
  
  # Definition of the matrix of discrete covariates (at baseline)
  Cov_Discrete <- real_data %>% 
    dplyr::select(c(hemo, homo, drugs, oprior, z30, race, gender, strat, symptom, karnof)) %>%
    # mutate(strat = strat - 1) %>%
    lapply(., as.factor) %>%
    as.data.frame()
  
  # Definition of the matrix of continuous covariates (at baseline)
  Cov_Cont <- real_data %>%
    dplyr::select(c(age, wtkg, preanti, cd40))
  
  # Definition of the matrix of covariates (at baseline)
  Cov <- c(Cov_Discrete, Cov_Cont) %>% as.data.frame()
  
  # Definition of treatment assignment vector 
  Tx <- real_data %>% dplyr::select(arms) %>% unlist() %>% as.factor()
  
  # Definition of the matrix of post-randomization variables
  Post_Random <- real_data %>%
    dplyr::select(c(cd420, cd496))
  
  # Definition of the considered data
  data_allvar <- cbind(Cov, Tx, Post_Random, Outcome)
  
  # Definition of baseline data and outcome
  db <- cbind(Cov, Outcome)
  
  # Marginal distribution of the covariates are estimated using empirical estimator 
  set.seed(random_seed)
  
  # Estimation of the R-vine model based on original data
  Rvine_dist <- Estimation_Copula(Cov)
  
  # Simulation of virtual patients based on the R-vine model and empirical distribution (of the original data)
  DataSimu <- Simulation_Copula(n_obs, Rvine_dist, Cov)  # n_obs = number of rows in original data
  
  # Simulation of synthetic treatment allocation
  TxSimu <- Simulation_Treatment(N = n_obs, Treatment_Arms = c(0, 1, 2, 3), 
                                 Probabilities = c(0.25, 0.25, 0.25, 0.25))
  
  # Post-randomization variables have missingness, perform MI to get m complete data sets
  Imp_data <- real_data %>% dplyr::select(c(age, wtkg, hemo, homo,  drugs, karnof, oprior, 
                                            z30, preanti, race, gender, strat, symptom, cd40, 
                                            arms, cd420, cd496, cens))
  
  # Calculate m, where m ~ max(prop. of missingness)*100
  m <- round(colMeans(is.na(Imp_data)) %>% max()*100)  # m ~ prop. of missingness*100
  
  # Perform multiple imputation by chained equations (mice)
  imp <- mice(data = Imp_data, m = m, maxit = 10, seed = random_seed, print = FALSE)
  
  
  # Simulation of post-randomization variable at week 20 (cd420)
  
  # First, fit execution model to each of the m imputed data sets
  cd420model_imp <- with(imp,
                         lm(cd420 ~ as.factor(hemo) + as.factor(homo) + as.factor(drugs) + 
                              as.factor(oprior) + as.factor(z30) + as.factor(race) + 
                              as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                              as.factor(karnof) + age + wtkg + preanti + cd40 + as.factor(arms))
  )
  
  # Predict cd420 using each of the m model fits
  # Object to store predictions 
  # (rows represent synthetic patients/obs, columns represent predictions for the jth imputed data set)
  cd420_preds <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m fitted models
    
    # Model parameters
    param <- cd420model_imp$analyses[[j]]$coefficients %>% as.matrix()
    
    # synthetic X,A with column of 1's for intercept
    data <- model.matrix(~ ., data = cbind(DataSimu, as.factor(TxSimu)))
    
    # Predicted synthetic Z1, cd420
    pred <- t(param) %*% t(data) %>% t()
    
    cd420_preds[, j] <- pred
    
  }
  
  # Generate synthetic cd420 for each of the m model fits
  # Object to store m sets of generated cd420
  cd420_mgens <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m model fits
    
    # Predicted values using j'th model
    cd420_predict <- cd420_preds[, j]
    
    # Residuals from j'th model
    cd420_resid <- cd420model_imp$analyses[[j]]$residuals
    
    for (i in 1:nrow(cd420_mgens)) {
      # Get all possible values of pred + resid for the i'th observation
      pred_resid_sums <- cd420_predict[i] + cd420_resid
      
      # All pred + resid >= 0
      pred_resid_sums_pos <- pred_resid_sums[pred_resid_sums >= 0]
      
      # Randomly sample from non-negative sum values
      sample_val = sample(pred_resid_sums_pos, size = 1)
      
      # Save sample
      cd420_mgens[i, j] <- sample_val
    }
    
  }
  
  # Generate final synthetic cd420, Z^s_1 (all observed)
  cd420Simu <- apply(cd420_mgens, 1, sample, size = 1)
  
  
  # Simulation of post-randomization variable at week 96 (cd496)
  
  # First, fit execution model to each of the m imputed data sets
  cd496model_imp <- with(imp,
                         lm(cd496 ~ as.factor(hemo) + as.factor(homo) + as.factor(drugs) + 
                              as.factor(oprior) + as.factor(z30) + as.factor(race) + 
                              as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                              as.factor(karnof) + age + wtkg + preanti + cd40 + as.factor(arms) +
                              cd420)
  )
  
  # Predict cd496 using each of the m model fits
  # Object to store predictions 
  # (rows represent synthetic patients/obs, columns represent predictions for the jth imputed data set)
  cd496_preds <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m fitted models
    
    # Model parameters
    param <- cd496model_imp$analyses[[j]]$coefficients %>% as.matrix()
    
    # synthetic X,A with column of 1's for intercept
    data <- model.matrix(~ ., data = cbind(DataSimu, as.factor(TxSimu), cd420Simu))
    
    # Predicted synthetic Z2, cd496
    pred <- t(param) %*% t(data) %>% t()
    
    cd496_preds[, j] <- pred
    
  }
  
  # Generate synthetic cd496 for each of the m model fits
  # Object to store m sets of generated cd496
  cd496_mgens <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m model fits
    
    # Predicted values using j'th model
    cd496_predict <- cd496_preds[, j]
    
    # Residuals from j'th model
    cd496_resid <- cd496model_imp$analyses[[j]]$residuals
    
    for (i in 1:nrow(cd496_mgens)) {
      # Get all possible values of pred + resid for the i'th observation
      pred_resid_sums <- cd496_predict[i] + cd496_resid
      
      # All pred + resid >= 0
      pred_resid_sums_pos <- pred_resid_sums[pred_resid_sums >= 0]
      
      # Randomly sample from non-negative sum values
      sample_val = sample(pred_resid_sums_pos, size = 1)
      
      # Save sample
      cd496_mgens[i, j] <- sample_val
    }
    
  }
  
  # Generate final synthetic cd496, Z^s_2 (all observed)
  cd496Simu <- apply(cd496_mgens, 1, sample, size = 1)
  
  
  # Simulation of the outcome for each virtual patients
  
  # First, fit execution model to each of the m imputed data sets
  censmodel_imp <- with(imp,
                        glm(as.factor(cens) ~ as.factor(hemo) + as.factor(homo) + as.factor(drugs) + 
                              as.factor(oprior) + as.factor(z30) + as.factor(race) + 
                              as.factor(gender) + as.factor(strat) + as.factor(symptom) + 
                              as.factor(karnof) + age + wtkg + preanti + cd40 + as.factor(arms) +
                              cd420 + cd496, family = "binomial")
  )
  
  # Predict cens using each of the m model fits
  # Object to store predictions 
  # (rows represent synthetic patients/obs, columns represent predictions for the jth imputed data set)
  cens_preds <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m fitted models
    
    # Model parameters
    param <- censmodel_imp$analyses[[j]]$coefficients %>% as.matrix()  # on logit scale
    
    # synthetic X,A with column of 1's for intercept
    data <- model.matrix(~ ., data = cbind(DataSimu, as.factor(TxSimu), cd420Simu, cd496Simu))
    
    # Predicted synthetic Z2, cd496 (on normal scale)
    pred <- expit(t(param) %*% t(data)) %>% t()
    
    cens_preds[, j] <- pred
    
  }
  
  # Generate synthetic cens for each of the m model fits
  # Object to store m sets of generated cens
  cens_mgens <- matrix(data = NA, nrow = n_obs, ncol = m) %>% as.data.frame()
  
  for(j in 1:m) {  # iterate through all columns i.e., all m model fits
    
    # Random sample of Unif(0,1)
    unif_samples <- runif(n = n_obs, min = 0, max = 1)
    
    for (i in 1:nrow(cens_mgens)) {
      if (unif_samples[i] < cens_preds[i, j]) {
        cens_mgens[i, j] <- 1
      }
      else {
        cens_mgens[i, j] <- 0
      }
    }
    
  }
  
  # Generate final synthetic cens, Y (all observed)
  OutcomeSimu <- apply(cens_mgens, 1, sample, size = 1)
  
  # Finally, generate synthetic missingness (cd420, cd496, cens)
  
  # cd420 (Z1)
  
  # Data subset - include real patient ID
  cd4wk20_data_learn <- cbind(pidnum = real_data$pidnum, db, arms = Tx, 
                              cd420 = Post_Random$cd420, R_20 = real_data$R_20)
  
  # Model to estimate probability of being observed at week 20
  # Note: this model is also used to generate synthetic missingness (R_20)
  cd4wk20_probobs_model <- glm(as.factor(R_20) ~ age + wtkg + as.factor(hemo) + 
                                 as.factor(homo) + as.factor(drugs) + as.factor(karnof) + 
                                 as.factor(oprior) + as.factor(z30) + preanti + 
                                 as.factor(race) + as.factor(gender) + as.factor(strat) +
                                 as.factor(symptom) + cd40 + as.factor(arms),
                               data = cd4wk20_data_learn,
                               family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at week 20 for SIMULATED data
  cd4wk20Simu_probobs <- predict.glm(cd4wk20_probobs_model,
                                     newdata = cbind(DataSimu,
                                                     arms = TxSimu),
                                     type = "response")
  
  # Generate synthetic R_20
  R_20Simu <- rbinom(n = n_obs, size = 1, prob = cd4wk20Simu_probobs)
  
  # Generate cd420 (Z1) with missingness
  cd420Simu_withmiss <- cbind(R_20Simu, cd420Simu) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_20Simu == 1, cd420Simu, NA)) %>%
    pull(withmiss)
  
  # cd496 (Z2)
  
  # Data subset (cd420, cd496 have missingness)
  cd4wk96_data_learn <- cbind(cd4wk20_data_learn,
                              cd496 = Post_Random$cd496, R_96 = real_data$R_96)
  
  # Estimated probabilities of being observed at week 96 for REAL data
  # based on decomp: Pr(Z2 = obs | X, A, Z1) = Pr(Z2 = obs | X, A, Z1 = obs)*Pr(Z1 = obs | X, A)
  #                                                + Pr(Z2 = obs | X, A, Z1 = miss)*Pr(Z1 = miss | X, A)
  #                                          = Pr(Z2 = obs | X, A, Z1 = obs)*Pr(Z1 = obs | X, A)
  
  # First term: Pr(Z2 = obs | X, A, Z1 = obs)
  # Model to estimate probability of being observed at week 96, given Z1 observed (cd420)
  cd4wk96_probobs_model <- glm(as.factor(R_96) ~ age + wtkg + as.factor(hemo) + 
                                 as.factor(homo) + as.factor(drugs) + as.factor(karnof) + 
                                 as.factor(oprior) + as.factor(z30) + preanti + 
                                 as.factor(race) + as.factor(gender) + as.factor(strat) +
                                 as.factor(symptom) + cd40 + as.factor(arms) + cd420,
                               data = cd4wk96_data_learn,
                               family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at week 96 for SIMULATED data
  # If Z1 = obs, then prob is predicted using fitted model for R_Z2
  # If Z1 = miss, then prob = 0 (i.e., prob of Z2 being observed = 0 when Z1 is missing)
  datasynth_wk96 <- cbind(pidnum = 1:nrow(DataSimu), DataSimu, arms = TxSimu, 
                          cd420 = cd420Simu, cd496 = cd496Simu,
                          R_20 = R_20Simu, cd420_withmiss = cd420Simu_withmiss)
  
  # If observed data subset with cd420 observed (i.e., data used to fit cd4wk96_probobs_model) has missing stratum karnof = 70,
  # and if synthetic data subset with cd420 observed also includes karnof = 70, 
  # then set observed cd420 value to missing when karnof = 70 in the synthetic data
  if((!(any(cd4wk96_data_learn[!is.na(cd4wk96_data_learn$cd420), ]$karnof == "70"))) & 
     any(datasynth_wk96[!is.na(datasynth_wk96$cd420_withmiss), ]$karnof == "70")){
    datasynth_wk96 <- datasynth_wk96 %>%
      mutate(cd420_withmiss = case_when(karnof == 70 ~ NA,
                                        TRUE ~ cd420_withmiss))
  }
  
  # Pr(Z2_synth = obs | X_synth, A_synth, Z1_synth = obs)
  # Restrict to rows with OBSERVED synthetic Z1
  cd496synth_probobs_z1synthobs <- predict.glm(cd4wk96_probobs_model, 
                                               newdata = datasynth_wk96[!is.na(datasynth_wk96$cd420_withmiss), ],  
                                               type = "response")
  
  # Add Pr(Z2_synth = obs | X_synth, A_synth, Z1_synth = obs) to datasynth_wk96
  datasynth_wk96_z1obs <- datasynth_wk96[rownames(datasynth_wk96) %in% names(cd496synth_probobs_z1synthobs), ]
  datasynth_wk96_z1obs$cd496_probobs_z1obs <- cd496synth_probobs_z1synthobs
  datasynth_wk96 <- datasynth_wk96 %>%
    left_join(datasynth_wk96_z1obs, by = colnames(datasynth_wk96))
  
  # Calculate prob. observed for Z2
  datasynth_wk96 <- datasynth_wk96 %>%
    mutate(cd496_probobs = case_when(!is.na(cd420_withmiss) ~ cd496_probobs_z1obs,
                                     is.na(cd420_withmiss) ~ 0))  # Z1 = miss --> Z2 must be missing
  
  # Generate synthetic R_96
  R_96Simu = rbinom(n = n_obs, size = 1, prob = datasynth_wk96$cd496_probobs)
  
  # Generate cd496 (Z2) with missingness
  cd496Simu_withmiss <- cbind(R_96Simu, cd496Simu = datasynth_wk96$cd496) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_96Simu == 1, cd496Simu, NA)) %>%
    pull(withmiss)
  
  # cens (Y)
  
  # Data subset (not really a subset, here we use all variables)
  # cd420, cd496, cens (the outcome) have missingness
  outcome_data_learn <- cbind(cd4wk96_data_learn,
                              cens = as.factor(Outcome),
                              R_Y = real_data$R_Y)
  
  # Estimated probabilities of being observed at final visit for REAL data
  # based on decomp: 
  # Pr(Y = obs | X, A, Z1, Z2) = Pr(Y = obs | X, A, Z1 = obs, Z2 = obs)*Pr(Z2 = obs | X, A, Z1)
  
  # Model to estimate probability of being observed at final visit, given Z1 and Z2 observed (cd420, cd496)
  Y_probobs_model <- glm(as.factor(R_Y) ~ age + wtkg + as.factor(hemo) + as.factor(homo) +
                           as.factor(drugs) + as.factor(karnof) + as.factor(oprior) + as.factor(z30) +
                           preanti + as.factor(race) + as.factor(gender) + as.factor(strat) +
                           as.factor(symptom) + cd40 + as.factor(arms) + cd420 + cd496,
                         data = outcome_data_learn,
                         family = binomial(link = "logit"))
  
  # Estimated probabilities of being observed at final visit for SIMULATED data
  # If Z2 = obs (meaning Z1 = obs), then prob is predicted using fitted model for R_Y
  # If Z2 = miss, then prob = 0 (i.e., prob of Y being observed = 0 when Z2 is missing)
  datasynth_outcome <- cbind(datasynth_wk96, 
                             R_96 = R_96Simu, cd496_withmiss = cd496Simu_withmiss, cens = OutcomeSimu)
  
  # If observed data subset with cd496 observed (i.e., data used to fit Y_probobs_model) has missing stratum karnof = 70,
  # and if synthetic data subset with cd496 observed also includes karnof = 70, 
  # then set observed cd496 value to missing when karnof = 70 in the synthetic data
  # AND set observed cd420 value to missing (since missing cd496 implies missing cd420 under monotone missing)
  if((!(any(outcome_data_learn[!is.na(outcome_data_learn$cd496), ]$karnof == "70"))) & 
     any(datasynth_outcome[(!is.na(datasynth_outcome$cd496_withmiss)), ]$karnof == "70")){
    datasynth_outcome <- datasynth_outcome %>%
      mutate(cd496_withmiss = case_when(karnof == 70 ~ NA,
                                        TRUE ~ cd496_withmiss),
             cd420_withmiss = case_when(is.na(cd496_withmiss) ~ NA,
                                        TRUE ~ cd420_withmiss))
  }
  
  # Pr(Y_synth = obs | X_synth, A_synth, Z1_synth = obs, Z2_synth = obs)
  # Restrict to rows with OBSERVED synthetic Z1 and OBSERVED synthetic Z2 (but if Z2 obs, then so is Z1)
  Ysynth_probobs_z1z2synthobs <- predict.glm(Y_probobs_model,
                                             newdata = datasynth_outcome[(!is.na(datasynth_outcome$cd496_withmiss)), ],  
                                             type = "response")
  
  # Pr(Y_synth = obs | X_synth, A_synth, Z1_synth = obs, Z2_synth = obs) to datasynth_outcome
  datasynth_outcome_z1z2obs <- datasynth_outcome[rownames(datasynth_outcome) %in% names(Ysynth_probobs_z1z2synthobs), ]
  datasynth_outcome_z1z2obs$cens_probobs_z1z2obs <- Ysynth_probobs_z1z2synthobs
  datasynth_outcome <- datasynth_outcome %>%
    left_join(datasynth_outcome_z1z2obs, by = colnames(datasynth_outcome))
  
  # Calculate prob. observed for Y
  datasynth_outcome <- datasynth_outcome %>%
    mutate(cens_probobs = case_when(!is.na(cd496_withmiss) ~ cens_probobs_z1z2obs,
                                    is.na(cd496_withmiss) ~ 0))  # Z2 = miss --> Y must be missing
  
  # Generate synthetic R_Y
  R_YSimu = rbinom(n = n_obs, size = 1, prob = datasynth_outcome$cens_probobs)
  
  # Generate cens (Y) with missingness
  OutcomeSimu_withmiss <- cbind(R_YSimu, OutcomeSimu = datasynth_outcome$cens) %>% 
    as.data.frame() %>%
    mutate(withmiss = if_else(R_YSimu == 1, OutcomeSimu, NA)) %>%
    pull(withmiss)
  
  # Final table of synthetic data generated via R-vine copula + execution models
  data_synthetic <- cbind(pidnum = c(1:nrow(DataSimu)),
                          DataSimu,
                          arms = as.factor(TxSimu),
                          cd420_complete = cd420Simu,
                          cd420 = cd420Simu_withmiss,
                          cd496_complete = cd496Simu,
                          cd496 = cd496Simu_withmiss,
                          cens_complete = as.factor(OutcomeSimu),
                          cens = as.factor(OutcomeSimu_withmiss))
  
  return(data_synthetic)
}


# Metrics ----
# Function for calculating 1-KS for all variables, for a given dataset (i.e., method)
ks.stat <- function(Synthetic_Data, Real_Data) {
  # This function takes as input a synthetic data set and the real data set
  # and returns a dataframe with the 1-KS value and the variable name.
  # This function uses the ks.test() function from the dgof package
  
  # Throw error if column names of Synthetic_Data and Real_Data are not the same
  if(length(intersect(colnames(Synthetic_Data), colnames(Real_Data))) != ncol(Synthetic_Data)) {
    stop("Column names should be the same in synthetic and real data frames.")
  }
  
  # Initialize dataframe to store 1-KS values
  vals <- matrix(data = NA, nrow = ncol(Synthetic_Data), ncol = 2) %>% as.data.frame()
  colnames(vals) <- c("Variable", "KS Statistic")
  
  # Perform KS test, then store 1 - KS statistic for each variable
  for(i in 1:ncol(Synthetic_Data)) {
    # i'th variable
    col_name <- names(Synthetic_Data)[i]
    
    # Save variable name
    vals[i, 1] <- col_name
    
    # Perform KS test for i'th variable
    ks_test <- ks.test(Synthetic_Data[, col_name], Real_Data[, col_name], alternative = "two.sided")
    
    # KS statistic
    ks_stat <- ks_test$statistic %>% unname()
    
    # Save 1-KS statistic
    vals[i, 2] <- 1 - ks_stat
  }
  
  # Return df of 1 - KS statistics
  return(vals)
  
}

# Calculate this by hand:
# calculate difference between synthetic and real proportions of each category of a given variable,
# sum the absolute value of all differences,
# then divide the sum by 2.
# Note: this function works for both binary variables and categorical variables with more than 2 levels.
tvd.calc <- function(Synthetic_Data, Real_Data, Var) {
  # Synthetic_Data is a dataframe containing synthetic data
  # Real_Data is a dataframe containing real data
  # Var is a character string of the variable name
  
  # Need to handle the case that level 70 of karnof was dropped/missing
  if(Var == "karnof" & nlevels(Synthetic_Data[, Var]) == 3) {
    synthetic_prop <- table(Synthetic_Data[!is.na(Synthetic_Data[, Var]), Var])/nrow(Synthetic_Data[!is.na(Synthetic_Data[, Var]), ])
    # Add prop = 0 for karnof = 70
    synthetic_prop <- c(0, synthetic_prop)
    real_prop <- table(Real_Data[!is.na(Real_Data[, Var]), Var])/nrow(Real_Data[!is.na(Real_Data[, Var]), ])
    tvd <- 0.5 * sum(abs(synthetic_prop - real_prop))
  }
  
  else {
    synthetic_prop <- table(Synthetic_Data[!is.na(Synthetic_Data[, Var]), Var])/nrow(Synthetic_Data[!is.na(Synthetic_Data[, Var]), ])
    real_prop <- table(Real_Data[!is.na(Real_Data[, Var]), Var])/nrow(Real_Data[!is.na(Real_Data[, Var]), ])
    tvd <- 0.5 * sum(abs(synthetic_prop - real_prop))
  }
  
  return(tvd)
}

# Function to return all tvd stats for all discrete variables in a given data set
tvd.stat <- function(Synthetic_Data, Real_Data) {
  # This function takes as input a synthetic data set and the real data set
  # and returns a dataframe with the 1 - TVD value and the variable name.
  # This function uses the previously-declared function, tvd.calc
  
  # Throw error if column names of Synthetic_Data and Real_Data are not the same
  if(length(intersect(colnames(Synthetic_Data), colnames(Real_Data))) != ncol(Synthetic_Data)) {
    stop("Column names should be the same in synthetic and real data frames.")
  }
  
  # Initialize dataframe to store 1 - TVD values
  vals <- matrix(data = NA, nrow = ncol(Synthetic_Data), ncol = 2) %>% as.data.frame()
  colnames(vals) <- c("Variable", "TVD Statistic")
  
  # Calculate TVD, then store 1 - TVD statistic for each variable
  for(i in 1:ncol(Synthetic_Data)) {
    # i'th variable
    col_name <- names(Synthetic_Data)[i]
    
    # Save variable name
    vals[i, 1] <- col_name
    
    # Save 1 - TVD statistic
    vals[i, 2] <- 1 - tvd.calc(Synthetic_Data, Real_Data, col_name)
  }
  
  # Return df of 1 - KS statistics
  return(vals)
  
}

# Normalized difference between correlation of two given continuous variables in 
# the real v. synthetic data
# Score = 1 - (0.5 * |Corr_synth - Corr_real|) --> "similarity score" due to  1 - (value)
# We will use Spearman correlation, not Pearson
Corr.Sim.Score.Spearman <- function(Synthetic_Data, Real_Data) {
  # Calculate correlation for all combinations of pairs of continuous variables
  # Returns dataframe of pairs of variables, correlation in synthetic and real data, and similarity score
  
  # Throw error if Synthetic_Data and Real_Data have different number of columns
  if(ncol(Synthetic_Data) != ncol(Real_Data)) {
    stop("Number of columns in synthetic and real data frames should be equal.")
  }
  
  # Throw error if column names of Synthetic_Data and Real_Data are not the same
  if(length(intersect(colnames(Synthetic_Data), colnames(Real_Data))) != ncol(Synthetic_Data)) {
    stop("Column names should be the same in synthetic and real data frames.")
  }
  
  # Calculate correlations in synthetic data
  Corr_synth <- Synthetic_Data %>%
    as.matrix() %>%
    cor(use = "everything", method = "spearman") %>%
    as.data.frame %>%
    rownames_to_column(var = 'var1') %>%
    gather(var2, value, -var1) %>%
    rename(corr_synth = value)
  
  # Deal with missing values by using only complete data
  for(i in 1:nrow(Corr_synth)) {
    if(is.na(Corr_synth[i, "corr_synth"])) {
      Corr_synth[i, "corr_synth"] <- cor(Synthetic_Data[, Corr_synth[i, "var1"]],
                                         Synthetic_Data[, Corr_synth[i, "var2"]],
                                         use = "complete.obs",
                                         method = "spearman")
    }
  }
  
  # Calculate correlations in real data
  Corr_real <- Real_Data %>%
    as.matrix() %>%
    cor(use = "everything", method = "spearman") %>%
    as.data.frame %>%
    rownames_to_column(var = 'var1') %>%
    gather(var2, value, -var1) %>%
    rename(corr_real = value)
  
  # Deal with missing values by using only complete data
  for(i in 1:nrow(Corr_real)) {
    if(is.na(Corr_real[i, "corr_real"])) {
      Corr_real[i, "corr_real"] <- cor(Real_Data[, Corr_real[i, "var1"]],
                                       Real_Data[, Corr_real[i, "var2"]],
                                       use = "complete.obs",
                                       method = "spearman")
    }
  }
  
  # Join tables so all correlation values are in same table
  Corr_all <- left_join(Corr_synth, Corr_real, by = c("var1", "var2")) %>%
    # Remove variances (i.e., corr between a variable and itself)
    filter(corr_real != 1 & corr_synth != 1) %>%
    # Remove duplicate pairs
    mutate(var_order = paste(var1, var2) %>%
             strsplit(split = ' ') %>%
             map_chr( ~ sort(.x) %>% 
                        paste(collapse = ' '))) %>%
    mutate(cnt = 1) %>%
    group_by(var_order) %>%
    mutate(cumsum = cumsum(cnt)) %>%
    filter(cumsum != 2) %>%
    ungroup %>%
    select(-var_order, -cnt, -cumsum) %>%
    # Calculate normalized similarity score
    mutate(score = 1 - 0.5*(abs(corr_synth - corr_real)))
  
  # Return final table of results
  return(Corr_all)
}

# Function to return all bivariate tvd stats (i.e. 2-way contingency table diffs) THIS DOESNT WORK YET!!!!!
# for all discrete variables in a given data set
Contingency.Sim.stat <- function(Synthetic_Data, Real_Data) {
  # This function takes as input a synthetic data set and the real data set
  # and returns a dataframe with the contingency similarity score (1 - bivariate TVD) and the variable name.
  # This function uses the previously-declared function, bivariatetvd.calc
  
  # Throw error if column names of Synthetic_Data and Real_Data are not the same
  if(length(intersect(colnames(Synthetic_Data), colnames(Real_Data))) != ncol(Synthetic_Data)) {
    stop("Column names should be the same in synthetic and real data frames.")
  }
  
  # Initialize dataframe to store contingency similarity score values
  # Note: number of rows (i.e., values) = n(n-1)/2
  vals <- matrix(data = NA, 
                 nrow = ncol(Synthetic_Data)*(ncol(Synthetic_Data) - 1)/2, 
                 ncol = 3) %>% as.data.frame()
  colnames(vals) <- c("Var1", "Var2", "Stat")
  
  # Fill in values for Var1 and Var2 columns
  varlist <- names(Synthetic_Data)
  df <- expand.grid(varlist, varlist) %>% 
    mutate(combo = paste(Var1, Var2)) %>% 
    group_by(combo) %>% 
    unique()
  # Unique combos of var 1 and var 2
  unique_combos <- df %>% 
    group_by(combo) %>%
    dplyr::select(combo) %>% 
    apply(1, function(x) paste(sort(unlist(strsplit(x, " "))), collapse = " ")) %>% 
    unique() %>%
    as.data.frame()
  colnames(unique_combos) <- c("combo")
  
  # Var 1 and Var 2 as separate columns, and as combo in 1 column
  df <- df %>% 
    right_join(unique_combos, by = "combo") %>% 
    filter(Var1 != Var2)
  
  vals[, 1] <- df[, 1]
  vals[, 2] <- df[, 2]
  
  # Calculate bivariate TVD, then store 1 - bivariate TVD statistic for each variable
  for(i in 1:nrow(vals)) {
    var1 <- vals[i, 1]
    var2 <- vals[i, 2]
    
    vals[i, 3] <- 1 - bivariatetvd.calc(Synthetic_Data = Synthetic_Data,
                                        Real_Data = Real_Data,
                                        Var1 = var1, Var2 = var2)
  }
  
  # Return df of 1 - bivariate TVD statistics
  return(vals)
  
}

# Function to capture all bivariate comparisons
# Takes as input Synthetic_Data, Real_Data
# If var 1 is continuous and var 2 is continuous, calculate correlations (Spearman and Pearson)
# If var 1 is continuous and var 2 is discrete, or vice versa, 
# bin the continous variable, then calculate contingency score
# If var 1 is discrete and var 2 is discrete, calculate contingency score
# This function calls the previously-defined function: bivariatetvd.calc

# Calculate this by hand:
# calculate difference between synthetic and real proportions of each combination of categories
# of two given variables,
# sum the absolute value of all differences,
# then divide the sum by 2.
bivariatetvd.calc <- function(Synthetic_Data, Real_Data, Var1, Var2) {
  # Synthetic_Data is a dataframe containing synthetic data
  # Real_Data is a dataframe containing real data
  # Var1 and Var2 are character strings of variable names
  
  # Need to handle the case that level 70 of karnof was dropped/missing
  if(Var1 == "karnof" & nlevels(Synthetic_Data[, Var1]) == 3) {
    synthetic_prop <- table(Synthetic_Data[, Var1] %>% unlist(), 
                            Synthetic_Data[, Var2] %>% unlist())/nrow(Synthetic_Data)
    # Add prop = 0 for karnof = 70
    synthetic_prop <- rbind(c(0, 0), synthetic_prop)
    real_prop <- table(Real_Data[, Var1] %>% unlist(), 
                       Real_Data[, Var2] %>% unlist())/nrow(Real_Data)
    bivariatetvd <- 0.5 * sum(abs(synthetic_prop - real_prop))
  }
  
  else if(Var2 == "karnof" & nlevels(Synthetic_Data[, Var2]) == 3) {
    synthetic_prop <- table(Synthetic_Data[, Var1] %>% unlist(), 
                            Synthetic_Data[, Var2] %>% unlist())/nrow(Synthetic_Data)
    # Add prop = 0 for karnof = 70
    synthetic_prop <- cbind(c(0, 0), synthetic_prop)
    real_prop <- table(Real_Data[, Var1] %>% unlist(), 
                       Real_Data[, Var2] %>% unlist())/nrow(Real_Data)
    bivariatetvd <- 0.5 * sum(abs(synthetic_prop - real_prop))
  }
  
  else {
    synthetic_prop <- table(Synthetic_Data[, Var1] %>% unlist(), 
                            Synthetic_Data[, Var2] %>% unlist())/nrow(Synthetic_Data)
    real_prop <- table(Real_Data[, Var1] %>% unlist(), 
                       Real_Data[, Var2] %>% unlist())/nrow(Real_Data)
    bivariatetvd <- 0.5 * sum(abs(synthetic_prop - real_prop))
  }
  
  return(bivariatetvd)
}

bivar.metrics <- function(Synthetic_Data, Real_Data) {
  
  # Throw error if Synthetic_Data and Real_Data have different number of columns
  if(ncol(Synthetic_Data) != ncol(Real_Data)) {
    stop("Number of columns in synthetic and real data frames should be equal.")
  }
  
  # Throw error if column names of Synthetic_Data and Real_Data are not the same
  if(length(intersect(colnames(Synthetic_Data), colnames(Real_Data))) != ncol(Synthetic_Data)) {
    stop("Column names should be the same in synthetic and real data frames.")
  }
  
  # Initialize dataframe to store similarity score values
  # Note: number of rows (i.e., values) = n(n-1)/2
  vals <- matrix(data = NA, 
                 nrow = ncol(Synthetic_Data)*(ncol(Synthetic_Data) - 1)/2, 
                 ncol = 5) %>% as.data.frame()
  colnames(vals) <- c("Var1", "Var2", "Corr_Score_Spearman", "Corr_Score_Pearson", "Contin_Score")
  
  # Fill in values for Var1 and Var2 columns
  varlist <- names(Synthetic_Data)
  df <- expand.grid(varlist, varlist) %>% 
    mutate(combo = paste(Var1, Var2)) %>% 
    group_by(combo) %>% 
    unique()
  # Unique combos of var 1 and var 2
  unique_combos <- df %>% 
    group_by(combo) %>%
    dplyr::select(combo) %>% 
    apply(1, function(x) paste(sort(unlist(strsplit(x, " "))), collapse = " ")) %>% 
    unique() %>%
    as.data.frame()
  colnames(unique_combos) <- c("combo")
  
  # Var 1 and Var 2 as separate columns, and as combo in 1 column
  df <- df %>% 
    right_join(unique_combos, by = "combo") %>% 
    filter(Var1 != Var2)
  
  vals[, 1] <- df[, 1]
  vals[, 2] <- df[, 2]
  
  # Calculate scores
  for(i in 1:nrow(vals)) {
    var1 <- vals[i, 1] %>% as.character()
    var2 <- vals[i, 2] %>% as.character()
    
    # If var1 and var2 are both continuous, calculate Spearman and Pearson correlation
    if((is.numeric(unlist(Synthetic_Data[, var1])) & is.numeric(unlist(Synthetic_Data[, var2])) & 
        is.numeric(unlist(Real_Data[, var1]))& is.numeric(unlist(Real_Data[, var2])))) {
      
      # Spearman
      corr_spearman_synth <- cor(x = Synthetic_Data[, var1], 
                                 y = Synthetic_Data[, var2],
                                 use = "complete.obs",
                                 method = "spearman")
      corr_spearman_real <- cor(x = Real_Data[, var1], 
                                y = Real_Data[, var2],
                                use = "complete.obs",
                                method = "spearman")
      vals[i, 3] = 1 - 0.5*(abs(corr_spearman_synth - corr_spearman_real))
      
      # Pearson
      corr_pearson_synth <- cor(x = Synthetic_Data[, var1], 
                                y = Synthetic_Data[, var2],
                                use = "complete.obs",
                                method = "pearson")
      corr_pearson_real <- cor(x = Real_Data[, var1], 
                               y = Real_Data[, var2],
                               use = "complete.obs",
                               method = "pearson")
      vals[i, 4] = 1 - 0.5*(abs(corr_pearson_synth - corr_pearson_real))
    }
    
    # If var1 and var2 are both discrete, calculate contingency score
    else if((is.factor(unlist(Synthetic_Data[, var1])) & is.factor(unlist(Synthetic_Data[, var2])) & 
             is.factor(unlist(Real_Data[, var1])) & is.factor(unlist(Real_Data[, var2])))) {
      
      # Calculate and store contingency score
      vals[i, 5] <- 1 - bivariatetvd.calc(Synthetic_Data = Synthetic_Data,
                                          Real_Data = Real_Data,
                                          Var1 = var1, 
                                          Var2 = var2)
    }
    
    # If one of var1 and var2 is continuous and the other is discrete,
    # bin the continuous variable and treat as categorical,
    # then calculate contingency score.
    else if((is.numeric(unlist(Synthetic_Data[, var1])) & is.factor(unlist(Synthetic_Data[, var2])) & 
             is.numeric(unlist(Real_Data[, var1])) & is.factor(unlist(Real_Data[, var2]))) |
            (is.factor(unlist(Synthetic_Data[, var1])) & is.numeric(unlist(Synthetic_Data[, var2])) & 
             is.factor(unlist(Real_Data[, var1])) & is.numeric(unlist(Real_Data[, var2])))) {
      
      # Identify the continuous variable
      # var1 is continuous
      if(is.numeric(unlist(Synthetic_Data[, var1])) & is.numeric(unlist(Real_Data[, var1]))) {
        
        # Bin this variable (using quantiles)
        Synthetic_Data_bin <- Synthetic_Data %>%
          mutate(cont_binned = cut(Synthetic_Data[, var1] %>% unlist(), 4))
        
        Real_Data_bin <- Real_Data %>%
          mutate(cont_binned = cut(Real_Data[, var1] %>% unlist(), 4))
        
        vals[i, 5] <- 1 - bivariatetvd.calc(Synthetic_Data = Synthetic_Data_bin,
                                            Real_Data = Real_Data_bin,
                                            Var1 = "cont_binned", 
                                            Var2 = var2)
      }
      # var2 is continuous
      else {
        # Bin this variable (using quantiles)
        Synthetic_Data_bin <- Synthetic_Data %>%
          mutate(cont_binned = cut(Synthetic_Data[, var2] %>% unlist(), 4))
        
        Real_Data_bin <- Real_Data %>%
          mutate(cont_binned = cut(Real_Data[, var2] %>% unlist(), 4))
        
        vals[i, 5] <- 1 - bivariatetvd.calc(Synthetic_Data = Synthetic_Data_bin,
                                            Real_Data = Real_Data_bin,
                                            Var1 = var1, 
                                            Var2 = "cont_binned")
      }
    }
  }
  
  return(vals)
}

