                  knn_pred <- knn(train = data_train[, !(names(data_train) %in% c("pidnum", "label"))],
                                  test = data_test[, !(names(data_test) %in% c("pidnum", "label"))],
                                  cl = data_train[, names(data_train) %in% "label"],
                                  k = 5)

                  # Confusion matrix
                  cm_knn <- confusionMatrix(as.factor(data_test[, "label"]), knn_pred)

                  # Metrics (Accuracy, Precision, Recall, F1-Score)
                  MLmetrics_knn <- cm_knn$byClass[c("Balanced Accuracy", "Precision", "Recall", "F1")]
                  MLmetrics_complement_knn <- matrix(data = 1 - MLmetrics_knn, nrow = 1, ncol = 4) %>% as.data.frame()
                  colnames(MLmetrics_complement_knn) <- c("Balanced Accuracy", "Precision", "Recall", "F1")

                  # Trial inference metrics

                  # Create dichotomous tx variable for simplicity
                  data_synth <- data_synth %>%
                    mutate(tx_bin = case_when(arms == 0 ~ 0,
                                              arms == 1 ~ 1,
                                              arms == 2 ~ 1,
                                              arms == 3 ~ 1))

                  # Fit logistic regression model (no confounders)
                  mod <- glm(formula = as.factor(cens) ~ as.factor(tx_bin), family = "binomial", data = data_synth)

                  # OR, CI for treatment
                  OR_est <- exp(mod$coefficients)[2] %>% as.numeric()
                  CI_est <- exp(confint(mod))[2,] %>% as.numeric()
                  trialinf_ORCI <- matrix(data = c(OR_est, CI_est), nrow = 1, ncol = 3)
                  colnames(trialinf_ORCI) <- c("OR", "Lower CI", "Upper CI")

                  # Variables with missingness only - MONOTONE SETTING Z1, Z2, Y

                  # Z1 (cd420)

                  # Compare ALL synthetic to OBSERVED real (should be close)
                  cd420_allsynth_obsreal <- 1 - ks.test(data_synth[, "cd420"],
                                                        real_data[, "cd420"],
                                                        alternative = "two.sided")$statistic

                  # Compare ALL synthetic to ALL real (should NOT be close)
                  cd420_allsynth_allreal <- 1 - ks.test(data_synth[, "cd420"],
                                                        real_data[, "cd420_complete"],
                                                        alternative = "two.sided")$statistic

                  cd420_missmetrics <- matrix(data = c("cd420", cd420_allsynth_obsreal, cd420_allsynth_allreal),
                                              nrow = 1, ncol = 3) %>% as.data.frame()
                  colnames(cd420_missmetrics) <- c("Var", "AllSynthObsReal", "AllSynthAllReal")

                  # Z2 (cd496)

                  # Compare ALL synthetic to OBSERVED real (should be close)
                  cd496_allsynth_obsreal <- 1 - ks.test(data_synth[, "cd496"],
                                                        real_data[, "cd496"],
                                                        alternative = "two.sided")$statistic

                  # Compare ALL synthetic to ALL real (should NOT be close)
                  cd496_allsynth_allreal <- 1 - ks.test(data_synth[, "cd496"],
                                                        real_data[, "cd496_complete"],
                                                        alternative = "two.sided")$statistic

                  cd496_missmetrics <- matrix(data = c("cd496", cd496_allsynth_obsreal, cd496_allsynth_allreal),
                                              nrow = 1, ncol = 3) %>% as.data.frame()
                  colnames(cd496_missmetrics) <- c("Var", "AllSynthObsReal", "AllSynthAllReal")

                  # Y (cens)

                  # Compare ALL synthetic to OBSERVED real
                  cens_allsynth_obsreal <- 1 - tvd.calc(data_synth, real_data, "cens")

                  # Compare ALL synthetic to ALL real
                  cens_allsynth_allreal <- 1 - tvd.calc(data_synth,
                                                        real_data %>% dplyr::select(-c(cens)) %>% rename(cens = cens_complete),
                                                        "cens")

                  cens_missmetrics <- matrix(data = c("cens", cens_allsynth_obsreal, cens_allsynth_allreal),
                                             nrow = 1, ncol = 3) %>% as.data.frame()
                  colnames(cens_missmetrics) <- c("Var", "AllSynthObsReal", "AllSynthAllReal")

                  # Combine all missingness metrics into one object
                  missmetrics <- rbind(cd420_missmetrics, cd496_missmetrics, cens_missmetrics)

                  # Tibble of metric results
                  tibble(
                    # First 5 columns are scenario settings
                    par1 = "Monotone", par2 = "MAR", par3 = "25", par4 = "Strong", method = "CC_Stagewise") %>%
                    # Tibble contains metric results
                    bind_cols(tibble(univar_cont_metrics = list(univar_cont %>% as_tibble()),
                                     univar_disc_metrics = list(univar_disc %>% as_tibble()),
                                     bivar_metrics = list(bivar %>% as_tibble()),
                                     MLeff_xgb = list(MLmetrics_complement_xgb %>% as_tibble()),
                                     MLeff_knn = list(MLmetrics_complement_knn %>% as_tibble()),
                                     trialinf = list(trialinf_ORCI %>% as_tibble()),
                                     missmetrics = list(missmetrics %>% as_tibble())
                    ))
                }
doParallel::stopImplicitCluster()
end_time <- Sys.time()
(time_takenccstagewise <- end_time - start_time)

final_res <- sim.eval.cc.parallel.stagewise %>%
  list_rbind()

# Name the columns you want to combine
list_cols <- names(final_res)[6:ncol(final_res)]

# Create a named list of combined tibbles, one for each list-column
Scen1B_CC_stagewise_results <- purrr::map(set_names(list_cols), ~ bind_rows(final_res[[.x]]))

# IPW
random_seed = 20250529

start_time <- Sys.time()
doParallel::registerDoParallel(cores = 10)
sim.eval.aipw.parallel <- foreach(
  i = 1:1000,
  .packages = c("tidyverse", "rvinecopulib", "e1071", "caret", "EnvStats", "truncnorm",
                "dgof", "caTools", "xgboost", "VIM", "class", "patchwork", "mice")) %dopar% {
                  
                  set.seed(20250529)
                  
                  # First, make sure columns are in the correct order
                  data_real <- real_data[, col_order]
                  
                  # Add R variables (indicators of missingness)
                  data_real <- data_real %>%
                    mutate(R_20 = case_when(!is.na(cd420) ~ 1,  # R = 1 means observed
                                            TRUE ~ 0),
                           R_96 = case_when(!is.na(cd496) ~ 1,
                                            TRUE ~ 0),
                           R_Y = case_when(!is.na(cens) ~ 1,
                                           TRUE ~ 0))
                  
                  # Generate data set 
                  data_synth_raw <- generate1dataset_aipw_mono(real_data = data_real,
                                                               random_seed = random_seed + i,
                                                               n_obs = n_obs)
                  
                  # Make sure columns are in the same order as real data set
                  # This is not actually necessary for R, but to make things consistent with python
                  data_synth <- data_synth_raw[, col_order]
                  
                  # Compute univariate metrics
                  
                  # Calculate univariate continuous metrics for current data set
                  univar_cont_cols <- ks.stat(Synthetic_Data = data_synth[, var_cont],
                                              Real_Data = data_real[, var_cont])
                  univar_cont <- matrix(data = univar_cont_cols[, 2], nrow = 1,
                                        ncol = nrow(univar_cont_cols)) %>% as.data.frame()
                  colnames(univar_cont) <- univar_cont_cols[, 1]

                  # Calculate univariate discrete metrics for current data set
                  univar_disc_cols <- tvd.stat(Synthetic_Data = data_synth[, var_disc],
                                               Real_Data = data_real[, var_disc])
                  univar_disc <- matrix(data = univar_disc_cols[, 2], nrow = 1,
                                        ncol = nrow(univar_disc_cols)) %>% as.data.frame()
                  colnames(univar_disc) <- univar_disc_cols[, 1]

                  # Calculate all bivariate metrics for current data set

                  # First, remove id column
                  data_synth_noid <- data_synth[, !(names(data_synth) %in% c("pidnum"))]
                  data_real_noid <- data_real[, !(names(data_real) %in% c("pidnum", "R_20", "R_96", "R_Y"))]

                  bivar <- bivar.metrics(Synthetic_Data = data_synth_noid, Real_Data = data_real_noid)

                  # Calculate ML efficacy metrics - detecting real data from synthetic data

                  # XGBoost

                  # Combine real and synthetic data into 1 data set, and add label for real/synthetic
                  # 0 = real, 1 = synthetic
                  data_realsynth <- rbind(data_real[, !(names(data_real) %in% c("R_20", "R_96", "R_Y"))],
                                          data_synth) %>%
                    mutate(label = c(rep(0, nrow(data_real)), rep(1, nrow(data_synth))))

                  # Split real data into training set and test set, and separate labels from covariates
                  # 70:30 split
                  train_split <- 0.7

                  # Set random seed
                  set.seed(random_seed + i)

                  # Sample rows for training set (70%)
                  sample_indices <- sample.split(data_realsynth[, 1], SplitRatio = 0.70)

                  # Make sure data is all type numeric and stored in a matrix
                  data_matrix <- apply(data_realsynth, 2, as.numeric) %>% as.matrix()

                  data_train <- data_matrix[sample_indices, ]
                  data_test <- data_matrix[!sample_indices, ]

                  # Train the prediction model on training set (real data)
                  xgb_mod <- xgboost(data = data_train[, !(names(data_realsynth) %in% c("label", "pidnum"))],
                                     label = data_train[, (names(data_realsynth) %in% c("label"))],
                                     max.depth = 6, eta = 1, nthread = 2, nrounds = 2, objective = "binary:logistic")

                  # Predict the outcome on the real data test set based on trained model
                  y_prob <- predict(xgb_mod, data_test[, !(names(data_realsynth) %in% c("pidnum", "label"))])
                  y_pred <- as.numeric(y_prob > 0.5)

                  # Confusion matrix
                  cm <- confusionMatrix(as.factor(data_test[, "label"]), as.factor(y_pred))

                  # Metrics (Accuracy, Precision, Recall, F1-Score)
                  MLmetrics_xgb <- cm$byClass[c("Balanced Accuracy", "Precision", "Recall", "F1")]
                  MLmetrics_complement_xgb <- matrix(data = 1 - MLmetrics_xgb, nrow = 1, ncol = 4) %>% as.data.frame()
                  colnames(MLmetrics_complement_xgb) <- c("Balanced Accuracy", "Precision", "Recall", "F1")

                  # KNN

                  set.seed(random_seed + i)

                  # Need to impute missing values first (for real data AND SYNTHETIC DATA)
                  # Real data
                  knn_imp_real <- kNN(data_real, k = 5)[, 1:ncol(data_real)]

                  # Synthetic data
                  knn_imp_synthetic <- kNN(data_synth, k = 5)[, 1:ncol(data_synth)]

                  # Combine (imputed) real and synthetic data into 1 data set, and add label for real/synthetic
                  # 0 = real, 1 = synthetic
                  data_realsynth <- rbind(knn_imp_real[, !(names(data_real) %in% c("R_20", "R_96", "R_Y"))],
                                          knn_imp_synthetic) %>%
                    mutate(label = c(rep(0, nrow(knn_imp_real[, !(names(data_real) %in% c("R_20", "R_96", "R_Y"))])),
                                     rep(1, nrow(knn_imp_synthetic))))

                  # Split real data into training set and test set, and separate labels (outcome) from covariates
                  # 70:30 split
                  train_split <- 0.7
                  sample_indices <- sample.split(data_realsynth[, 1], SplitRatio = 0.70)

                  data_train <- data_realsynth[sample_indices, ]
                  data_test <- data_realsynth[!sample_indices, ]

                  # Train the prediction model on training set and predict label (real/synthetic)
                  # KNN algorithm for prediction of the outcome based on real data
                  knn_pred <- knn(train = data_train[, !(names(data_train) %in% c("pidnum", "label"))],
                                  test = data_test[, !(names(data_test) %in% c("pidnum", "label"))],
                                  cl = data_train[, names(data_train) %in% "label"],
                                  k = 5)

                  # Confusion matrix
                  cm_knn <- confusionMatrix(as.factor(data_test[, "label"]), knn_pred)

                  # Metrics (Accuracy, Precision, Recall, F1-Score)
                  MLmetrics_knn <- cm_knn$byClass[c("Balanced Accuracy", "Precision", "Recall", "F1")]
                  MLmetrics_complement_knn <- matrix(data = 1 - MLmetrics_knn, nrow = 1, ncol = 4) %>% as.data.frame()
                  colnames(MLmetrics_complement_knn) <- c("Balanced Accuracy", "Precision", "Recall", "F1")
                  
                  # Trial inference metrics
                  
                  # Create dichotomous tx variable for simplicity
                  data_synth <- data_synth %>%
                    mutate(tx_bin = case_when(arms == 0 ~ 0,
                                              arms == 1 ~ 1,
                                              arms == 2 ~ 1,
                                              arms == 3 ~ 1))
                  data_synth_raw <- data_synth_raw %>% 
                    mutate(tx_bin = case_when(arms == 0 ~ 0,
                                              arms == 1 ~ 1,
                                              arms == 2 ~ 1,
                                              arms == 3 ~ 1))
                  
                  # Fit logistic regression model (no confounders)
                  mod <- glm(formula = as.factor(cens) ~ as.factor(tx_bin), family = "binomial", data = data_synth)
                  mod_comp <- glm(formula = as.factor(cens_complete) ~ as.factor(tx_bin), family = "binomial", data = data_synth_raw)
                  
                  # OR, CI for treatment
                  OR_est <- exp(mod$coefficients)[2] %>% as.numeric()
                  CI_est <- exp(confint(mod))[2,] %>% as.numeric()
                  trialinf_ORCI <- matrix(data = c(OR_est, CI_est), nrow = 1, ncol = 3)
                  colnames(trialinf_ORCI) <- c("OR", "Lower CI", "Upper CI")
                  OR_est_comp <- exp(mod_comp$coefficients)[2] %>% as.numeric()
                  CI_est_comp <- exp(confint(mod_comp))[2,] %>% as.numeric()
                  trialinf_ORCI_comp <- matrix(data = c(OR_est_comp, CI_est_comp), nrow = 1, ncol = 3)
                  colnames(trialinf_ORCI_comp) <- c("OR", "Lower CI", "Upper CI")
                  
                  # Missingness prop
                  missprop <- matrix(
                    data = c(sum(is.na(data_synth$cd420))/nrow(data_synth),
                             sum(is.na(data_synth$cd496))/nrow(data_synth),
                             sum(is.na(data_synth$cens))/nrow(data_synth)),
                    nrow = 1, ncol = 3)
                  colnames(missprop) <- c("cd420", "cd496", "cens")

                  # Variables with missingness only - MONOTONE SETTING Z1, Z2, Y

                  # Z1 (cd420)

                  # Compare OBSERVED synthetic to OBSERVED real (should be close)
                  cd420_obssynth_obsreal <- 1 - ks.test(data_synth[, "cd420"],
                                                        real_data[, "cd420"],
                                                        alternative = "two.sided")$statistic

                  # Compare ALL synthetic to ALL real (should be close)
                  cd420_allsynth_allreal <- 1 - ks.test(data_synth_raw[, "cd420_complete"],
                                                        real_data[, "cd420_complete"],
                                                        alternative = "two.sided")$statistic

                  # Compare OBSERVED synthetic to ALL real (should NOT be close)
                  cd420_obssynth_allreal <- 1 - ks.test(data_synth[, "cd420"],
                                                        real_data[, "cd420_complete"],
                                                        alternative = "two.sided")$statistic

                  # Compare ALL synthetic to OBSERVED real (should NOT be close)
                  cd420_allsynth_obsreal <- 1 - ks.test(data_synth_raw[, "cd420_complete"],
                                                        real_data[, "cd420"],
                                                        alternative = "two.sided")$statistic

                  cd420_missmetrics <- matrix(data = c("cd420", cd420_obssynth_obsreal, cd420_allsynth_allreal,
                                                       cd420_obssynth_allreal, cd420_allsynth_obsreal),
                                              nrow = 1, ncol = 5) %>% as.data.frame()
                  colnames(cd420_missmetrics) <- c("Var", "ObsSynthObsReal", "AllSynthAllReal",
                                                   "ObsSynthAllReal", "AllSynthObsReal")

                  # Z2 (cd496)

                  # Compare OBSERVED synthetic to OBSERVED real (should be close)
                  cd496_obssynth_obsreal <- 1 - ks.test(data_synth[, "cd496"],
                                                        real_data[, "cd496"],
                                                        alternative = "two.sided")$statistic

                  # Compare ALL synthetic to ALL real (should be close)
                  cd496_allsynth_allreal <- 1 - ks.test(data_synth_raw[, "cd496_complete"],
                                                        real_data[, "cd496_complete"],
                                                        alternative = "two.sided")$statistic

                  # Compare OBSERVED synthetic to ALL real (should NOT be close)
                  cd496_obssynth_allreal <- 1 - ks.test(data_synth[, "cd496"],
                                                        real_data[, "cd496_complete"],
                                                        alternative = "two.sided")$statistic

                  # Compare ALL synthetic to OBSERVED real (should NOT be close)
                  cd496_allsynth_obsreal <- 1 - ks.test(data_synth_raw[, "cd496_complete"],
                                                        real_data[, "cd496"],
                                                        alternative = "two.sided")$statistic

                  cd496_missmetrics <- matrix(data = c("cd496", cd496_obssynth_obsreal, cd496_allsynth_allreal,
                                                       cd496_obssynth_allreal, cd496_allsynth_obsreal),
                                              nrow = 1, ncol = 5) %>% as.data.frame()
                  colnames(cd496_missmetrics) <- c("Var", "ObsSynthObsReal", "AllSynthAllReal",
                                                   "ObsSynthAllReal", "AllSynthObsReal")

                  # Y (cens)

                  # Compare OBSERVED synthetic to OBSERVED real (should be close)
                  cens_obssynth_obsreal <- 1 - tvd.calc(data_synth, real_data, "cens")

                  # Compare ALL synthetic to ALL real (should be close)
                  cens_allsynth_allreal <- 1 - tvd.calc(data_synth_raw, real_data, "cens_complete")

                  # Compare OBSERVED synthetic to ALL real (should NOT be close)
                  cens_obssynth_allreal <- 1 - tvd.calc(data_synth,
                                                        real_data %>% dplyr::select(-c(cens)) %>% rename(cens = cens_complete),
                                                        "cens")

                  # Compare ALL synthetic to OBSERVED real (should NOT be close)
                  cens_allsynth_obsreal <- 1 - tvd.calc(data_synth_raw %>% dplyr::select(-c(cens)) %>% rename(cens = cens_complete),
                                                        real_data,
                                                        "cens")

                  cens_missmetrics <- matrix(data = c("cens", cens_obssynth_obsreal, cens_allsynth_allreal,
                                                      cens_obssynth_allreal, cens_allsynth_obsreal),
                                             nrow = 1, ncol = 5) %>% as.data.frame()
                  colnames(cens_missmetrics) <- c("Var", "ObsSynthObsReal", "AllSynthAllReal",
                                                  "ObsSynthAllReal", "AllSynthObsReal")

                  # Combine all missingness metrics into one object
                  missmetrics <- rbind(cd420_missmetrics, cd496_missmetrics, cens_missmetrics)
                  
                  
                  # Tibble of metric results
                  tibble(
                    # First 5 columns are scenario settings
                    par1 = "Monotone", par2 = "MAR", par3 = "25", par4 = "Strong", method = "IPW") %>% 
                    # Tibble contains metric results
                    bind_cols(tibble(
                      univar_cont_metrics = list(univar_cont %>% as_tibble()),
                                     univar_disc_metrics = list(univar_disc %>% as_tibble()),
                                     bivar_metrics = list(bivar %>% as_tibble()),
                                     MLeff_xgb = list(MLmetrics_complement_xgb %>% as_tibble()),
                                     MLeff_knn = list(MLmetrics_complement_knn %>% as_tibble()),
                                     trialinf = list(trialinf_ORCI %>% as_tibble()),
                      trialinf_comp = list(trialinf_ORCI_comp %>% as_tibble())
                      ,
                                     missingprop = list(missprop %>% as_tibble()),
                                     missmetrics = list(missmetrics %>% as_tibble())
                    ))
                }
doParallel::stopImplicitCluster()
end_time <- Sys.time()
(time_takenipw <- end_time - start_time)

final_res <- sim.eval.aipw.parallel %>%
  list_rbind()

# Name the columns you want to combine
list_cols <- names(final_res)[6:ncol(final_res)]

# Create a named list of combined tibbles, one for each list-column
Scen1B_IPW_results <- purrr::map(set_names(list_cols), ~ bind_rows(final_res[[.x]]))

