                  MLmetrics_complement_knn <- matrix(data = 1 - MLmetrics_knn, nrow = 1, ncol = 4) %>% as.data.frame()
                  colnames(MLmetrics_complement_knn) <- c("Balanced Accuracy", "Precision", "Recall", "F1")
                  
                  # Trial inference metrics
                  
                  # Create dichotomous tx variable for simplicity
                  data_synth <- data_synth %>% 
                    mutate(tx_bin = case_when(arms == 0 ~ 0,
                                              arms == 1 ~ 1,
                                              arms == 2 ~ 1,
                                              arms == 3 ~ 1))
                  
                  # Fit logistic regression model (no confounders)
                  mod <- glm(formula = as.factor(cens) ~ as.factor(tx_bin), family = "binomial", data = data_synth)
                  
                  # OR, CI for treatment
                  OR_est <- exp(mod$coefficients)[2] %>% as.numeric()
                  CI_est <- exp(confint(mod))[2,] %>% as.numeric()
                  trialinf_ORCI <- matrix(data = c(OR_est, CI_est), nrow = 1, ncol = 3)
                  colnames(trialinf_ORCI) <- c("OR", "Lower CI", "Upper CI")
                  
                  # Variables with missingness only - NON-MONOTONE SETTING Z1, Y
                  
                  # Z1 (cd420)
                  
                  # Compare ALL synthetic to OBSERVED real (should be close)
                  cd420_allsynth_obsreal <- 1 - ks.test(data_synth[, "cd420"],
                                                        real_data[, "cd420"],
                                                        alternative = "two.sided")$statistic
                  
                  # Compare ALL synthetic to ALL real (should NOT be close)
                  cd420_allsynth_allreal <- 1 - ks.test(data_synth[, "cd420"],
                                                        real_data[, "cd420_complete"],
                                                        alternative = "two.sided")$statistic
                  
                  cd420_missmetrics <- matrix(data = c("cd420", cd420_allsynth_obsreal, cd420_allsynth_allreal), 
                                              nrow = 1, ncol = 3) %>% as.data.frame()
                  colnames(cd420_missmetrics) <- c("Var", "AllSynthObsReal", "AllSynthAllReal")
                  
                  # Y (cens)
                  
                  # Compare ALL synthetic to OBSERVED real
                  cens_allsynth_obsreal <- 1 - tvd.calc(data_synth, real_data, "cens")
                  
                  # Compare ALL synthetic to ALL real
                  cens_allsynth_allreal <- 1 - tvd.calc(data_synth, 
                                                        real_data %>% dplyr::select(-c(cens)) %>% rename(cens = cens_complete), 
                                                        "cens")
                  
                  cens_missmetrics <- matrix(data = c("cens", cens_allsynth_obsreal, cens_allsynth_allreal),
                                             nrow = 1, ncol = 3) %>% as.data.frame()
                  colnames(cens_missmetrics) <- c("Var", "AllSynthObsReal", "AllSynthAllReal")
                  
                  # Combine all missingness metrics into one object
                  missmetrics <- rbind(cd420_missmetrics, cens_missmetrics)
                  
                  # Tibble of metric results
                  tibble(
                    # First 5 columns are scenario settings
                    par1 = "Non-Monotone", par2 = "MCAR", par3 = "25", par4 = "Strong", method = "CC_Stagewise") %>% 
                    # Tibble contains metric results
                    bind_cols(tibble(univar_cont_metrics = list(univar_cont %>% as_tibble()),
                                     univar_disc_metrics = list(univar_disc %>% as_tibble()),
                                     bivar_metrics = list(bivar %>% as_tibble()),
                                     MLeff_xgb = list(MLmetrics_complement_xgb %>% as_tibble()),
                                     MLeff_knn = list(MLmetrics_complement_knn %>% as_tibble()),
                                     trialinf = list(trialinf_ORCI %>% as_tibble()),
                                     missmetrics = list(missmetrics %>% as_tibble())
                    ))
                }
doParallel::stopImplicitCluster()
end_time <- Sys.time()
(time_takenccstagewise <- end_time - start_time)

final_res <- sim.eval.cc.stagewise.parallel %>%
  list_rbind()

