                  CI_est_comp <- exp(confint(mod_comp))[2,] %>% as.numeric()
                  trialinf_ORCI_comp <- matrix(data = c(OR_est_comp, CI_est_comp), nrow = 1, ncol = 3)
                  colnames(trialinf_ORCI_comp) <- c("OR", "Lower CI", "Upper CI")
                  
                  # Missingness prop
                  missprop <- matrix(
                    data = c(sum(is.na(data_synth$cd420))/nrow(data_synth),
                             sum(is.na(data_synth$cens))/nrow(data_synth)),
                    nrow = 1, ncol = 2)
                  colnames(missprop) <- c("cd420", "cens")

                  # Variables with missingness only - NON-MONOTONE SETTING Z1, Y

                  # Z1 (cd420)

                  # Compare OBSERVED synthetic to OBSERVED real (should be close)
                  cd420_obssynth_obsreal <- 1 - ks.test(data_synth[, "cd420"],
                                                        real_data[, "cd420"],
                                                        alternative = "two.sided")$statistic

                  # Compare ALL synthetic to ALL real (should be close)
                  cd420_allsynth_allreal <- 1 - ks.test(data_synth_raw[, "cd420_complete"],
                                                        real_data[, "cd420_complete"],
                                                        alternative = "two.sided")$statistic

                  # Compare OBSERVED synthetic to ALL real (should NOT be close)
                  cd420_obssynth_allreal <- 1 - ks.test(data_synth[, "cd420"],
                                                        real_data[, "cd420_complete"],
                                                        alternative = "two.sided")$statistic

                  # Compare ALL synthetic to OBSERVED real (should NOT be close)
                  cd420_allsynth_obsreal <- 1 - ks.test(data_synth_raw[, "cd420_complete"],
                                                        real_data[, "cd420"],
                                                        alternative = "two.sided")$statistic

                  cd420_missmetrics <- matrix(data = c("cd420", cd420_obssynth_obsreal, cd420_allsynth_allreal,
                                                       cd420_obssynth_allreal, cd420_allsynth_obsreal),
                                              nrow = 1, ncol = 5) %>% as.data.frame()
                  colnames(cd420_missmetrics) <- c("Var", "ObsSynthObsReal", "AllSynthAllReal",
                                                   "ObsSynthAllReal", "AllSynthObsReal")

                  # Y (cens)

                  # Compare OBSERVED synthetic to OBSERVED real (should be close)
                  cens_obssynth_obsreal <- 1 - tvd.calc(data_synth, real_data, "cens")

                  # Compare ALL synthetic to ALL real (should be close)
                  cens_allsynth_allreal <- 1 - tvd.calc(data_synth_raw, real_data, "cens_complete")

                  # Compare OBSERVED synthetic to ALL real (should NOT be close)
                  cens_obssynth_allreal <- 1 - tvd.calc(data_synth,
                                                        real_data %>% dplyr::select(-c(cens)) %>% rename(cens = cens_complete),
                                                        "cens")

                  # Compare ALL synthetic to OBSERVED real (should NOT be close)
                  cens_allsynth_obsreal <- 1 - tvd.calc(data_synth_raw %>% dplyr::select(-c(cens)) %>% rename(cens = cens_complete),
                                                        real_data,
                                                        "cens")

                  cens_missmetrics <- matrix(data = c("cens", cens_obssynth_obsreal, cens_allsynth_allreal,
                                                      cens_obssynth_allreal, cens_allsynth_obsreal),
                                             nrow = 1, ncol = 5) %>% as.data.frame()
                  colnames(cens_missmetrics) <- c("Var", "ObsSynthObsReal", "AllSynthAllReal",
                                                  "ObsSynthAllReal", "AllSynthObsReal")

                  # Combine all missingness metrics into one object
                  missmetrics <- rbind(cd420_missmetrics, cens_missmetrics)
                  
                  # Tibble of metric results
                  tibble(
                    # First 5 columns are scenario settings
                    par1 = "Non-Monotone", par2 = "MCAR", par3 = "25", par4 = "Strong", method = "IPW - Force Mono.") %>% 
                    # Tibble contains metric results
                    bind_cols(tibble(
                      univar_cont_metrics = list(univar_cont %>% as_tibble()),
                                     univar_disc_metrics = list(univar_disc %>% as_tibble()),
                                     bivar_metrics = list(bivar %>% as_tibble()),
                                     MLeff_xgb = list(MLmetrics_complement_xgb %>% as_tibble()),
                                     MLeff_knn = list(MLmetrics_complement_knn %>% as_tibble()),
                                     trialinf = list(trialinf_ORCI %>% as_tibble()),
                      trialinf_comp = list(trialinf_ORCI_comp %>% as_tibble())
                      ,
                                     missingprop = list(missprop %>% as_tibble()),
                                     missmetrics = list(missmetrics %>% as_tibble())
                    ))
                }
doParallel::stopImplicitCluster()
end_time <- Sys.time()
(time_takenipwforcemono <- end_time - start_time)

