sim.eval.cc.parallel.stagewise <- foreach(
  i = 1:1000, 
  .packages = c("tidyverse", "rvinecopulib", "e1071", "caret", "EnvStats", "truncnorm", 
                "dgof", "caTools", "xgboost", "VIM", "class", "patchwork", "mice")) %dopar% {
                  
                  set.seed(20250529)
                  
