                                          knn_imp_synthetic) %>%
                    mutate(label = c(rep(0, nrow(knn_imp_real[, !(names(data_real) %in% c("R_20", "R_96", "R_Y"))])), 
                                     rep(1, nrow(knn_imp_synthetic))))
                  
                  # Split real data into training set and test set, and separate labels (outcome) from covariates
